impl ProductionTaskBoard {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let board: ProductionTaskBoard =
            serde_json::from_str(input).context("failed to parse Production Task Board JSON")?;
        board.validate_schema()?;
        Ok(board)
    }

    pub fn validate_schema(&self) -> Result<()> {
        if self.schema_version != PRODUCTION_TASK_BOARD_SCHEMA_VERSION {
            return Err(anyhow!(
                "production task board schemaVersion must be {PRODUCTION_TASK_BOARD_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("production task board boardId", &self.board_id)?;
        require_text("production task board milestone", &self.milestone)?;
        if self.tasks.is_empty() {
            return Err(anyhow!("production task board tasks must not be empty"));
        }
        for (index, task) in self.tasks.iter().enumerate() {
            task.validate_schema(index)?;
        }
        self.generated_state.validate()?;
        validate_nonempty_text_list("production task board guardrails", &self.guardrails)?;
        validate_nonempty_text_list(
            "production task board forbiddenActions",
            &self.forbidden_actions,
        )?;
        require_text("production task board boundary", &self.boundary)?;
        let forbidden_text = self.forbidden_actions.join(" ").to_ascii_lowercase();
        for required_forbidden in [
            "hidden background agents",
            "auto-apply",
            "auto-merge",
            "browser command bridge",
        ] {
            if !forbidden_text.contains(required_forbidden) {
                return Err(anyhow!(
                    "production task board forbiddenActions must include {required_forbidden} boundary"
                ));
            }
        }
        if !self
            .boundary
            .to_ascii_lowercase()
            .contains("does not execute")
        {
            return Err(anyhow!(
                "production task board boundary must state that the board does not execute work"
            ));
        }
        self.validate_board_rules()?;
        Ok(())
    }

    fn validate_board_rules(&self) -> Result<()> {
        let mut task_ids = BTreeSet::new();
        for task in &self.tasks {
            if !task_ids.insert(task.id.clone()) {
                return Err(anyhow!(
                    "duplicate production task board task id: {}",
                    task.id
                ));
            }
        }

        for task in &self.tasks {
            for dependency in &task.depends_on {
                if !task_ids.contains(dependency) {
                    return Err(anyhow!(
                        "production task board task {} dependsOn {} must reference an existing task",
                        task.id,
                        dependency
                    ));
                }
                if dependency == &task.id {
                    return Err(anyhow!(
                        "production task board task {} cannot depend on itself",
                        task.id
                    ));
                }
            }
        }
        self.validate_dependency_cycles()?;
        self.validate_target_ownership()?;
        Ok(())
    }

    fn validate_dependency_cycles(&self) -> Result<()> {
        fn visit(
            task_id: &str,
            tasks: &BTreeMap<&str, &ProductionTaskBoardTask>,
            temporary: &mut BTreeSet<String>,
            permanent: &mut BTreeSet<String>,
        ) -> Result<()> {
            if permanent.contains(task_id) {
                return Ok(());
            }
            if !temporary.insert(task_id.to_string()) {
                return Err(anyhow!(
                    "production task board dependency cycle includes task {task_id}"
                ));
            }
            let task = tasks
                .get(task_id)
                .ok_or_else(|| anyhow!("production task board task not found: {task_id}"))?;
            for dependency in &task.depends_on {
                visit(dependency, tasks, temporary, permanent)?;
            }
            temporary.remove(task_id);
            permanent.insert(task_id.to_string());
            Ok(())
        }

        let tasks = self
            .tasks
            .iter()
            .map(|task| (task.id.as_str(), task))
            .collect::<BTreeMap<_, _>>();
        let mut temporary = BTreeSet::new();
        let mut permanent = BTreeSet::new();
        for task in &self.tasks {
            visit(&task.id, &tasks, &mut temporary, &mut permanent)?;
        }
        Ok(())
    }

    fn validate_target_ownership(&self) -> Result<()> {
        // Artifact ids and paths occupy separate namespaces: an artifact id must
        // only conflict with another task's artifact id, and a path only with
        // another path. Keying both into one map would falsely reject a valid
        // board where one task's artifact id equals another task's path string.
        let mut id_owners = BTreeMap::<&str, (&str, &str)>::new();
        let mut path_owners = BTreeMap::<&str, (&str, &str)>::new();
        for task in &self.tasks {
            if task.status.releases_ownership() {
                continue;
            }
            for artifact in &task.target_artifacts {
                for (namespace, key, owners) in [
                    ("id", artifact.id.as_str(), &mut id_owners),
                    ("path", artifact.path.as_str(), &mut path_owners),
                ] {
                    if let Some((existing_task, existing_owner)) = owners.get(key) {
                        if *existing_owner != task.owner_agent {
                            return Err(anyhow!(
                                "production task board target ownership conflict for {namespace} {key}: task {existing_task} owned by {existing_owner} conflicts with task {} owned by {}",
                                task.id,
                                task.owner_agent
                            ));
                        }
                    } else {
                        owners.insert(key, (task.id.as_str(), task.owner_agent.as_str()));
                    }
                }
            }
        }
        Ok(())
    }
}

impl ProductionTaskBoardTask {
    fn validate_schema(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("production task board tasks[{index}].id"),
            &self.id,
        )?;
        validate_path_component(
            &format!("production task board tasks[{index}].role"),
            &self.role,
        )?;
        if !SUPPORTED_AGENT_ROLES.contains(&self.role.as_str()) {
            return Err(anyhow!(
                "production task board tasks[{index}].role '{}' is unsupported",
                self.role
            ));
        }
        validate_path_component(
            &format!("production task board tasks[{index}].ownerAgent"),
            &self.owner_agent,
        )?;
        for dependency in &self.depends_on {
            validate_path_component(
                &format!("production task board tasks[{index}].dependsOn"),
                dependency,
            )?;
        }
        if self.target_artifacts.is_empty() {
            return Err(anyhow!(
                "production task board tasks[{index}].targetArtifacts must not be empty"
            ));
        }
        for artifact in &self.target_artifacts {
            artifact.validate(&format!(
                "production task board tasks[{index}].targetArtifacts"
            ))?;
        }
        validate_nonempty_text_list(
            &format!("production task board tasks[{index}].acceptanceCriteria"),
            &self.acceptance_criteria,
        )?;
        validate_nonempty_text_list(
            &format!("production task board tasks[{index}].requiredEvidence"),
            &self.required_evidence,
        )?;
        if matches!(self.status, ProductionTaskStatus::Blocked) && self.blocked_reasons.is_empty() {
            return Err(anyhow!(
                "production task board tasks[{index}] blocked status requires blockedReasons"
            ));
        }
        if matches!(self.status, ProductionTaskStatus::Completed)
            && self
                .timestamps
                .as_ref()
                .is_none_or(|timestamps| timestamps.completed_at.is_none())
        {
            return Err(anyhow!(
                "production task board tasks[{index}] completed status requires timestamps.completedAt"
            ));
        }
        if let Some(transition) = &self.status_transition {
            transition.validate(&self.id, self.status)?;
        }
        Ok(())
    }
}

impl ProductionTaskStatusTransition {
    fn validate(&self, task_id: &str, status: ProductionTaskStatus) -> Result<()> {
        if self.to != status {
            return Err(anyhow!(
                "production task board task {task_id} statusTransition.to must match current status"
            ));
        }
        if !self.from.can_transition_to(self.to) {
            return Err(anyhow!(
                "production task board task {task_id} cannot transition from {:?} to {:?}",
                self.from,
                self.to
            ));
        }
        Ok(())
    }
}

impl ProductionTaskStatus {
    fn can_transition_to(self, next: ProductionTaskStatus) -> bool {
        if self == next {
            return true;
        }
        match self {
            ProductionTaskStatus::Proposed => matches!(
                next,
                ProductionTaskStatus::Assigned
                    | ProductionTaskStatus::Deferred
                    | ProductionTaskStatus::Rejected
            ),
            ProductionTaskStatus::Assigned => matches!(
                next,
                ProductionTaskStatus::InProgress
                    | ProductionTaskStatus::Blocked
                    | ProductionTaskStatus::Deferred
                    | ProductionTaskStatus::Rejected
            ),
            ProductionTaskStatus::InProgress => matches!(
                next,
                ProductionTaskStatus::Blocked
                    | ProductionTaskStatus::ReadyForReview
                    | ProductionTaskStatus::Deferred
                    | ProductionTaskStatus::Rejected
            ),
            ProductionTaskStatus::Blocked => matches!(
                next,
                ProductionTaskStatus::Assigned
                    | ProductionTaskStatus::InProgress
                    | ProductionTaskStatus::Deferred
                    | ProductionTaskStatus::Rejected
            ),
            ProductionTaskStatus::ReadyForReview => matches!(
                next,
                ProductionTaskStatus::Accepted
                    | ProductionTaskStatus::Rejected
                    | ProductionTaskStatus::Deferred
            ),
            ProductionTaskStatus::Accepted => matches!(
                next,
                ProductionTaskStatus::Completed | ProductionTaskStatus::Deferred
            ),
            ProductionTaskStatus::Rejected => matches!(next, ProductionTaskStatus::Deferred),
            ProductionTaskStatus::Deferred => matches!(
                next,
                ProductionTaskStatus::Proposed
                    | ProductionTaskStatus::Assigned
                    | ProductionTaskStatus::Rejected
            ),
            ProductionTaskStatus::Completed => false,
        }
    }

    fn releases_ownership(self) -> bool {
        matches!(
            self,
            ProductionTaskStatus::Rejected
                | ProductionTaskStatus::Deferred
                | ProductionTaskStatus::Completed
        )
    }
}

pub const PRODUCTION_TASK_BOARD_READ_MODEL_SCHEMA_VERSION: &str =
    "production-task-board-read-model-v1";

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct ProductionTaskBoardReadModel {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    #[serde(rename = "boardId")]
    pub board_id: String,
    pub status: String,
    #[serde(rename = "taskCount")]
    pub task_count: usize,
    #[serde(rename = "statusCounts")]
    pub status_counts: Vec<ProductionTaskStatusCount>,
    pub blockers: Vec<String>,
    #[serde(rename = "malformedReasons")]
    pub malformed_reasons: Vec<String>,
    pub boundary: String,
}

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct ProductionTaskStatusCount {
    pub status: String,
    pub count: usize,
}

pub fn production_task_board_read_model_from_json_str(input: &str) -> ProductionTaskBoardReadModel {
    match ProductionTaskBoard::from_json_str(input) {
        Ok(board) => ProductionTaskBoardReadModel::from_board(&board),
        Err(error) => ProductionTaskBoardReadModel::malformed(format!("{error:#}")),
    }
}

impl ProductionTaskBoardReadModel {
    pub fn from_board(board: &ProductionTaskBoard) -> Self {
        let mut counts = BTreeMap::<String, usize>::new();
        let mut blockers = Vec::new();
        for task in &board.tasks {
            *counts.entry(task.status.as_str().to_string()).or_default() += 1;
            for blocker in &task.blocked_reasons {
                blockers.push(format!("{}: {blocker}", task.id));
            }
        }
        let status = if board
            .tasks
            .iter()
            .any(|task| task.status == ProductionTaskStatus::Blocked)
        {
            "blocked"
        } else if board
            .tasks
            .iter()
            .any(|task| task.status == ProductionTaskStatus::Deferred)
        {
            "deferred"
        } else if board
            .tasks
            .iter()
            .any(|task| task.status == ProductionTaskStatus::ReadyForReview)
        {
            "ready-for-review"
        } else if board
            .tasks
            .iter()
            .all(|task| task.status == ProductionTaskStatus::Completed)
        {
            "completed"
        } else {
            "active"
        };
        Self {
            schema_version: PRODUCTION_TASK_BOARD_READ_MODEL_SCHEMA_VERSION.to_string(),
            board_id: board.board_id.clone(),
            status: status.to_string(),
            task_count: board.tasks.len(),
            status_counts: counts
                .into_iter()
                .map(|(status, count)| ProductionTaskStatusCount { status, count })
                .collect(),
            blockers,
            malformed_reasons: Vec::new(),
            boundary: "Read-only production task board summary; it does not execute tasks, spawn agents, apply changes, write trusted browser state, or merge PRs.".to_string(),
        }
    }

    fn malformed(reason: String) -> Self {
        Self {
            schema_version: PRODUCTION_TASK_BOARD_READ_MODEL_SCHEMA_VERSION.to_string(),
            board_id: "malformed-production-task-board".to_string(),
            status: "malformed".to_string(),
            task_count: 0,
            status_counts: Vec::new(),
            blockers: Vec::new(),
            malformed_reasons: vec![reason],
            boundary: "Read-only malformed production task board summary; it reports validation errors without executing tasks, spawning agents, applying changes, or writing trusted state.".to_string(),
        }
    }
}

impl ProductionTaskStatus {
    pub fn as_str(self) -> &'static str {
        match self {
            ProductionTaskStatus::Proposed => "proposed",
            ProductionTaskStatus::Assigned => "assigned",
            ProductionTaskStatus::InProgress => "in-progress",
            ProductionTaskStatus::Blocked => "blocked",
            ProductionTaskStatus::ReadyForReview => "ready-for-review",
            ProductionTaskStatus::Accepted => "accepted",
            ProductionTaskStatus::Rejected => "rejected",
            ProductionTaskStatus::Deferred => "deferred",
            ProductionTaskStatus::Completed => "completed",
        }
    }
}

