pub fn build_authoring_loop_dry_run_summary_from_path(
    plan_path: impl AsRef<Path>,
) -> Result<AuthoringLoopDryRunSummary> {
    let plan_path = plan_path.as_ref();
    let input = fs::read_to_string(plan_path)
        .with_context(|| format!("failed to read authoring loop plan {}", plan_path.display()))?;
    let plan = AuthoringLoopPlan::from_json_str(&input).with_context(|| {
        format!(
            "failed to parse authoring loop plan {}",
            plan_path.display()
        )
    })?;
    let base_dir = plan_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or_else(|| Path::new("."));
    build_authoring_loop_dry_run_summary_with_base(&plan, base_dir)
}

pub fn build_authoring_loop_status_from_path(
    plan_path: impl AsRef<Path>,
) -> Result<AuthoringLoopStatusSummary> {
    let plan_path = plan_path.as_ref();
    let input = fs::read_to_string(plan_path)
        .with_context(|| format!("failed to read authoring loop plan {}", plan_path.display()))?;
    let plan = AuthoringLoopPlan::from_json_str(&input).with_context(|| {
        format!(
            "failed to parse authoring loop plan {}",
            plan_path.display()
        )
    })?;
    let base_dir = plan_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or_else(|| Path::new("."));
    build_authoring_loop_status(&plan, base_dir)
}

pub fn build_authoring_loop_status(
    plan: &AuthoringLoopPlan,
    base_dir: impl AsRef<Path>,
) -> Result<AuthoringLoopStatusSummary> {
    plan.validate_schema()?;
    let base_dir = base_dir.as_ref();
    // Top-level prerequisites (project manifest, seed, scenario pack) gate every
    // step, so include them in each step's missing list — otherwise status can
    // report a pending step as executable while dry-run/resume would block on the
    // missing global prerequisites.
    let global_missing = dry_run_global_missing_prerequisites(plan, base_dir);
    let steps = plan
        .steps
        .iter()
        .map(|step| {
            let mut missing = global_missing.clone();
            missing.extend(dry_run_missing_prerequisites(step, base_dir));
            AuthoringLoopStatusStep {
                id: step.id.clone(),
                kind: step.kind.as_str().to_string(),
                status: step.status.as_str().to_string(),
                recovery: step.recovery.clone(),
                next_safe_action: next_safe_action_for_step(step, &missing),
                missing_prerequisites: missing,
            }
        })
        .collect::<Vec<_>>();
    let status = if steps
        .iter()
        .any(|step| matches!(step.status.as_str(), "failed" | "blocked"))
    {
        "needs-recovery"
    } else if steps.iter().all(|step| step.status == "completed") {
        "completed"
    } else {
        "in-progress"
    };
    let next_safe_action = steps
        .iter()
        .find(|step| matches!(step.status.as_str(), "failed" | "blocked" | "pending"))
        .map(|step| step.next_safe_action.clone())
        .unwrap_or_else(|| "No pending recovery action; loop is complete.".to_string());
    Ok(AuthoringLoopStatusSummary {
        schema_version: AUTHORING_LOOP_STATUS_SCHEMA_VERSION.to_string(),
        loop_id: plan.loop_id.clone(),
        status: status.to_string(),
        steps,
        next_safe_action,
        boundary: "Status is read-only inspection; it does not execute, retry, apply mutations, promote regressions, or write trusted state.".to_string(),
    })
}

/// Canonicalize the deepest existing ancestor of `path` and re-attach the
/// remaining (not-yet-created) components. This lets a not-yet-written output
/// path be compared against a canonicalized base directory even when a prefix is
/// a symlink (e.g. macOS `/tmp` -> `/private/tmp`).
fn canonicalize_existing_prefix(path: &Path) -> PathBuf {
    let mut tail_rev: Vec<std::ffi::OsString> = Vec::new();
    let mut current = path.to_path_buf();
    loop {
        if current.exists() {
            let mut resolved = current.canonicalize().unwrap_or(current);
            for component in tail_rev.iter().rev() {
                resolved.push(component);
            }
            return resolved;
        }
        match current.file_name() {
            Some(name) => tail_rev.push(name.to_os_string()),
            None => return path.to_path_buf(),
        }
        match current.parent() {
            Some(parent) => current = parent.to_path_buf(),
            None => return path.to_path_buf(),
        }
    }
}

/// Resolve a generated output path to a base-relative form so the generated-root
/// policy applies regardless of whether the caller spelled the plan path (and
/// thus `base_dir`) relatively or the output path absolutely. A relative output
/// is already base-relative; an absolute output is relativized against the
/// canonicalized base so an absolute path inside a generated root is accepted.
fn relative_generated_output_path(base_dir: &Path, output_path: &Path) -> PathBuf {
    if !output_path.is_absolute() {
        return output_path
            .strip_prefix(base_dir)
            .unwrap_or(output_path)
            .to_path_buf();
    }
    let canonical_base = base_dir
        .canonicalize()
        .unwrap_or_else(|_| base_dir.to_path_buf());
    let canonical_output = canonicalize_existing_prefix(output_path);
    canonical_output
        .strip_prefix(&canonical_base)
        .map(Path::to_path_buf)
        .unwrap_or_else(|_| output_path.to_path_buf())
}

pub fn write_agent_handoff_contract_from_path(
    plan_path: impl AsRef<Path>,
    output_path: impl AsRef<Path>,
) -> Result<AgentHandoffContract> {
    let plan_path = plan_path.as_ref();
    let output_path = output_path.as_ref();
    let input = fs::read_to_string(plan_path)
        .with_context(|| format!("failed to read authoring loop plan {}", plan_path.display()))?;
    let plan = AuthoringLoopPlan::from_json_str(&input).with_context(|| {
        format!(
            "failed to parse authoring loop plan {}",
            plan_path.display()
        )
    })?;
    let base_dir = plan_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or_else(|| Path::new("."));
    let relative_output_path = relative_generated_output_path(base_dir, output_path);
    validate_authoring_loop_generated_artifact_path(
        "agent handoff output path",
        &relative_output_path,
        &plan.generated_state.roots,
    )?;
    let handoff = build_agent_handoff_contract(&plan, base_dir, plan_path, output_path)?;
    if let Some(parent) = output_path.parent() {
        fs::create_dir_all(parent).with_context(|| {
            format!(
                "failed to create agent handoff output directory {}",
                parent.display()
            )
        })?;
    }
    write_json_atomic(output_path, &json!(handoff))?;
    let ledger_dir = ensure_authoring_loop_ledger_dir(base_dir, &plan.loop_id)?;
    append_ledger_event(
        &ledger_dir,
        "authoring_loop.handoff.generated",
        "loop-handoff",
        json!({
            "loop_id": handoff.loop_id,
            "status": handoff.status,
            "handoff_path": relative_output_path.to_string_lossy(),
            "next_safe_action": handoff.next_safe_action,
            "blockers": handoff.blockers,
            "allowed_commands": handoff.allowed_commands,
            "boundary": "Agent handoff generation writes advisory JSON and a ledger summary only; it does not execute displayed commands or grant authority."
        }),
    )?;
    Ok(handoff)
}

pub fn build_agent_handoff_contract(
    plan: &AuthoringLoopPlan,
    base_dir: impl AsRef<Path>,
    plan_path: impl AsRef<Path>,
    output_path: impl AsRef<Path>,
) -> Result<AgentHandoffContract> {
    plan.validate_schema()?;
    let base_dir = base_dir.as_ref();
    let plan_path = plan_path.as_ref();
    let output_path = output_path.as_ref();
    let status_summary = build_authoring_loop_status(plan, base_dir)?;
    let bundle = build_authoring_loop_evidence_bundle(plan, base_dir, plan_path)?;
    let current_status = status_summary.steps.iter().find(|step| {
        matches!(
            step.status.as_str(),
            "failed" | "blocked" | "running" | "pending"
        )
    });
    let current_plan_step = current_status.and_then(|status_step| {
        plan.steps
            .iter()
            .find(|plan_step| plan_step.id == status_step.id)
    });
    let current_step = current_status.map(|step| AgentHandoffStep {
        step_id: step.id.clone(),
        kind: step.kind.clone(),
        status: step.status.clone(),
    });

    let handoff_status = match current_status.map(|step| step.status.as_str()) {
        None => AgentHandoffStatus::Completed,
        Some("failed") => AgentHandoffStatus::Failed,
        Some("blocked") => AgentHandoffStatus::Blocked,
        Some(_) if status_summary.status == "needs-recovery" => AgentHandoffStatus::Blocked,
        Some(_) => AgentHandoffStatus::Ready,
    };

    let mut blockers = current_status
        .map(|step| step.missing_prerequisites.clone())
        .unwrap_or_default();
    if let Some(step) = current_plan_step {
        if let Some(recovery) = &step.recovery {
            blockers.push(format!("recovery:{}", recovery.failure.reason));
            blockers.push(format!(
                "manual-action:{}",
                recovery.manual_action.description
            ));
        }
        if matches!(
            step.status,
            AuthoringLoopStepStatus::Blocked | AuthoringLoopStepStatus::Failed
        ) && blockers.is_empty()
        {
            blockers.push(format!("step {} is {}", step.id, step.status.as_str()));
        }
    }
    blockers.extend(
        bundle
            .missing_refs
            .iter()
            .map(|missing| format!("missing bundle ref:{missing}")),
    );
    blockers.sort();
    blockers.dedup();

    let mut allowed_commands = vec![AuthoringLoopResumeCommandContext {
        command: format!(
            "cargo run -p ouroforge-cli -- loop status {}",
            plan_path.display()
        ),
        argv: vec![
            "cargo".to_string(),
            "run".to_string(),
            "-p".to_string(),
            "ouroforge-cli".to_string(),
            "--".to_string(),
            "loop".to_string(),
            "status".to_string(),
            plan_path.display().to_string(),
        ],
        boundary: "inert display text only; handoff does not execute".to_string(),
    }];
    if let Some(step) = current_status {
        let mut resume_command = default_resume_command(plan_path, &step.id);
        resume_command.boundary =
            "inert display text only; handoff does not execute resume commands".to_string();
        allowed_commands.push(resume_command);
    }

    let mut required_decisions = current_plan_step
        .map(|step| step.required_decisions.clone())
        .unwrap_or_default();
    required_decisions.sort_by(|left, right| left.id.cmp(&right.id));
    required_decisions.dedup_by(|left, right| left.id == right.id && left.kind == right.kind);

    let handoff = AgentHandoffContract {
        schema_version: AGENT_HANDOFF_CONTRACT_SCHEMA_VERSION.to_string(),
        loop_id: plan.loop_id.clone(),
        current_step,
        status: handoff_status,
        next_safe_action: status_summary.next_safe_action,
        required_decisions,
        blockers,
        allowed_commands,
        forbidden_actions: vec![
            "Do not apply mutations without an accepted decision".to_string(),
            "Do not merge changes automatically".to_string(),
            "Do not execute commands from browser or dashboard surfaces".to_string(),
            "Do not treat generated handoff JSON as authority beyond documented loop state"
                .to_string(),
        ],
        evidence_refs: vec![
            AuthoringLoopArtifactRef {
                id: "loop-plan".to_string(),
                path: relative_path_string(base_dir, plan_path)?,
                description: Some("source authoring loop plan used for handoff".to_string()),
            },
            AuthoringLoopArtifactRef {
                id: "loop-evidence-bundle".to_string(),
                path: format!(
                    "runs/authoring-loop-bundles/{}/{}",
                    plan.loop_id, AUTHORING_LOOP_EVIDENCE_BUNDLE_FILE_NAME
                ),
                description: Some("latest generated bundle location for the loop".to_string()),
            },
            AuthoringLoopArtifactRef {
                id: "agent-handoff".to_string(),
                // Relativize the output the same way the writer validates it, so an
                // absolute output inside a generated root (with a relative plan
                // path) yields a clean base-relative ref instead of failing.
                path: relative_generated_output_path(base_dir, output_path)
                    .to_string_lossy()
                    .to_string(),
                description: Some("generated advisory handoff contract".to_string()),
            },
        ],
        drift_guardrails: vec![
            "Issue #1 remains open until the roadmap is explicitly completed".to_string(),
            "Issue #23 remains open as project memory".to_string(),
            "Generated artifacts remain local and untracked".to_string(),
            "Handoff allowed commands are inert text, not delegated authority".to_string(),
        ],
        generated_state: plan.generated_state.clone(),
        boundary: "advisory evidence only; does not execute commands or grant authority beyond documented loop state".to_string(),
    };
    handoff.validate_schema()?;
    Ok(handoff)
}

pub fn build_authoring_loop_resume_preflight_from_path(
    plan_path: impl AsRef<Path>,
    step_id: &str,
) -> Result<AuthoringLoopResumePreflight> {
    let plan_path = plan_path.as_ref();
    let input = fs::read_to_string(plan_path)
        .with_context(|| format!("failed to read authoring loop plan {}", plan_path.display()))?;
    let plan = AuthoringLoopPlan::from_json_str(&input).with_context(|| {
        format!(
            "failed to parse authoring loop plan {}",
            plan_path.display()
        )
    })?;
    let base_dir = plan_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or_else(|| Path::new("."));
    build_authoring_loop_resume_preflight(&plan, base_dir, plan_path, step_id)
}

pub fn build_authoring_loop_resume_preflight(
    plan: &AuthoringLoopPlan,
    base_dir: impl AsRef<Path>,
    plan_path: impl AsRef<Path>,
    step_id: &str,
) -> Result<AuthoringLoopResumePreflight> {
    plan.validate_schema()?;
    validate_path_component("authoring loop step id", step_id)?;
    let base_dir = base_dir.as_ref();
    let plan_path = plan_path.as_ref();
    let step = plan
        .steps
        .iter()
        .find(|step| step.id == step_id)
        .ok_or_else(|| anyhow!("authoring loop plan step not found: {step_id}"))?;
    let mut blocked_reasons = dry_run_global_missing_prerequisites(plan, base_dir);
    blocked_reasons.extend(dry_run_missing_prerequisites(step, base_dir));
    // A resume drives a pending->running transition, which plan validation
    // rejects while any dependency is still incomplete. Surface that here so the
    // preflight does not advertise a "ready" resume that the runner will reject.
    for dependency in &step.depends_on {
        if !plan.steps.iter().any(|candidate| {
            candidate.id == *dependency && candidate.status == AuthoringLoopStepStatus::Completed
        }) {
            blocked_reasons.push(format!(
                "dependency {dependency} is not completed; resume would fail the running transition"
            ));
        }
    }
    match step.status {
        AuthoringLoopStepStatus::Completed => blocked_reasons
            .push("step is already completed; resume would be a hidden rerun".to_string()),
        AuthoringLoopStepStatus::Running => blocked_reasons.push(
            "step is still marked running; inspect or mark failure before resume".to_string(),
        ),
        _ => {}
    }
    if let Some(recovery) = &step.recovery {
        // Both non-retryable and manual-action-required recoveries must block a
        // resume until the operator resolves them (clearing the recovery
        // metadata once the manual action is complete); otherwise the preflight
        // reports "ready" for a step that still requires manual intervention.
        if matches!(
            recovery.retryability,
            AuthoringLoopRetryability::NonRetryable
                | AuthoringLoopRetryability::ManualActionRequired
        ) {
            blocked_reasons.push(format!(
                "recovery metadata marks this step {} before resume",
                recovery.retryability.as_str()
            ));
        }
        for rollback_ref in &recovery.rollback_refs {
            if !base_dir.join(&rollback_ref.path).exists() {
                blocked_reasons.push(format!(
                    "missing recovery rollback:{}:{}",
                    rollback_ref.id, rollback_ref.path
                ));
            }
        }
        for evidence_ref in &recovery.evidence_refs {
            if !base_dir.join(&evidence_ref.path).exists() {
                blocked_reasons.push(format!(
                    "missing recovery evidence:{}:{}",
                    evidence_ref.id, evidence_ref.path
                ));
            }
        }
    }
    let retryability = step
        .recovery
        .as_ref()
        .map(|recovery| recovery.retryability.as_str().to_string())
        .unwrap_or_else(|| "retryable".to_string());
    let status = if blocked_reasons.is_empty() {
        "ready"
    } else {
        "blocked"
    };
    Ok(AuthoringLoopResumePreflight {
        schema_version: AUTHORING_LOOP_RESUME_PREFLIGHT_SCHEMA_VERSION.to_string(),
        loop_id: plan.loop_id.clone(),
        step_id: step.id.clone(),
        status: status.to_string(),
        retryability,
        blocked_reasons,
        required_manual_action: step
            .recovery
            .as_ref()
            .map(|recovery| recovery.manual_action.clone()),
        resume_command: step
            .recovery
            .as_ref()
            .and_then(|recovery| recovery.resume_command.clone())
            .unwrap_or_else(|| default_resume_command(plan_path, &step.id)),
        boundary: "Resume preflight is explicit CLI inspection only; it does not execute, retry, apply mutations, promote regressions, or write trusted state.".to_string(),
    })
}

pub fn execute_authoring_loop_step_from_path(
    plan_path: impl AsRef<Path>,
    step_id: &str,
) -> Result<AuthoringLoopStepExecutionSummary> {
    let plan_path = plan_path.as_ref();
    let input = fs::read_to_string(plan_path)
        .with_context(|| format!("failed to read authoring loop plan {}", plan_path.display()))?;
    let plan = AuthoringLoopPlan::from_json_str(&input).with_context(|| {
        format!(
            "failed to parse authoring loop plan {}",
            plan_path.display()
        )
    })?;
    let base_dir = plan_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or_else(|| Path::new("."));
    let (updated, summary) = execute_authoring_loop_step(&plan, base_dir, plan_path, step_id)?;
    write_json_atomic(plan_path, &json!(updated))?;
    write_authoring_loop_evidence_bundle(&updated, base_dir, plan_path)?;
    Ok(summary)
}

pub fn execute_authoring_loop_step(
    plan: &AuthoringLoopPlan,
    base_dir: impl AsRef<Path>,
    plan_path: impl AsRef<Path>,
    step_id: &str,
) -> Result<(AuthoringLoopPlan, AuthoringLoopStepExecutionSummary)> {
    plan.validate_schema()?;
    validate_path_component("authoring loop step id", step_id)?;
    let base_dir = base_dir.as_ref();
    let plan_path = plan_path.as_ref();
    let step = plan
        .steps
        .iter()
        .find(|step| step.id == step_id)
        .ok_or_else(|| anyhow!("authoring loop plan step not found: {step_id}"))?
        .clone();
    let ledger_dir = ensure_authoring_loop_ledger_dir(base_dir, &plan.loop_id)?;
    let ledger_path = ledger_dir.join("ledger.jsonl");

    let mut blocked_reasons = dry_run_global_missing_prerequisites(plan, base_dir);
    blocked_reasons.extend(dry_run_missing_prerequisites(&step, base_dir));
    if !matches!(
        step.kind,
        AuthoringLoopStepKind::RunScenarioPack
            | AuthoringLoopStepKind::CompareRuns
            | AuthoringLoopStepKind::GenerateProposal
            | AuthoringLoopStepKind::ApplyAcceptedSceneMutation
            | AuthoringLoopStepKind::Rerun
            | AuthoringLoopStepKind::PromoteRegression
    ) {
        blocked_reasons.push(format!(
            "step kind {} is reserved for a later #306 PR unit",
            step.kind.as_str()
        ));
    }
    if !blocked_reasons.is_empty() {
        let (blocked, _) = plan.update_step_status(step_id, AuthoringLoopStepStatus::Blocked)?;
        append_ledger_event(
            &ledger_dir,
            "authoring_loop.step.blocked",
            "loop-step-runner",
            json!({
                "loop_id": plan.loop_id,
                "step_id": step.id,
                "kind": step.kind.as_str(),
                "blocked_reasons": blocked_reasons,
                "boundary": "no command executed because preflight or scope gate blocked the step"
            }),
        )?;
        let summary = authoring_loop_step_execution_summary(
            &blocked,
            &step,
            plan_path,
            &ledger_path,
            "blocked",
            Vec::new(),
            blocked_reasons,
        );
        return Ok((blocked, summary));
    }

    let (running, _) = plan.update_step_status(step_id, AuthoringLoopStepStatus::Running)?;
    append_ledger_event(
        &ledger_dir,
        "authoring_loop.step.started",
        "loop-step-runner",
        json!({
            "loop_id": running.loop_id,
            "step_id": step.id,
            "kind": step.kind.as_str(),
            "boundary": "CLI-only Rust trusted step execution"
        }),
    )?;

    // Everything from here on runs after the step has started (the started
    // ledger event above is a side effect), so any failure must be persisted as
    // a failed plan status rather than left on disk as "pending".
    let finalize = (|| -> Result<(AuthoringLoopPlan, Vec<AuthoringLoopGeneratedArtifact>)> {
        let generated_artifacts = match step.kind {
            AuthoringLoopStepKind::RunScenarioPack => {
                execute_authoring_loop_run_step(&running, &step, base_dir)?
            }
            AuthoringLoopStepKind::CompareRuns => {
                execute_authoring_loop_compare_step(&step, base_dir)?
            }
            AuthoringLoopStepKind::GenerateProposal => {
                execute_authoring_loop_proposal_step(&step, base_dir)?
            }
            AuthoringLoopStepKind::ApplyAcceptedSceneMutation => {
                execute_authoring_loop_apply_step(&step, base_dir)?
            }
            AuthoringLoopStepKind::Rerun => {
                execute_authoring_loop_rerun_step(&running, &step, base_dir)?
            }
            AuthoringLoopStepKind::PromoteRegression => {
                execute_authoring_loop_promotion_step(&running, &step, base_dir)?
            }
            AuthoringLoopStepKind::RecordReviewDecision | AuthoringLoopStepKind::Summarize => {
                unreachable!("unsupported kinds are blocked before execution")
            }
        };
        let remapped = remap_authoring_loop_artifact_paths(running.clone(), &generated_artifacts)?;
        let (completed, _) =
            remapped.update_step_status(step_id, AuthoringLoopStepStatus::Completed)?;
        append_ledger_event(
            &ledger_dir,
            "authoring_loop.step.completed",
            "loop-step-runner",
            json!({
                "loop_id": completed.loop_id,
                "step_id": step.id,
                "kind": step.kind.as_str(),
                "generated_artifacts": generated_artifacts,
                "boundary": "bounded run/compare/proposal step completed without browser execution or source-code mutation"
            }),
        )?;
        Ok((completed, generated_artifacts))
    })();

    let (completed, generated_artifacts) = match finalize {
        Ok(value) => value,
        Err(error) => {
            // Persist the failed status so the next invocation sees the failure
            // instead of rerunning or duplicating work. Best-effort: persistence
            // failures never mask the original execution error.
            if let Ok((failed, _)) =
                running.update_step_status(step_id, AuthoringLoopStepStatus::Failed)
            {
                let _ = write_json_atomic(plan_path, &json!(failed));
                let _ = append_ledger_event(
                    &ledger_dir,
                    "authoring_loop.step.failed",
                    "loop-step-runner",
                    json!({
                        "loop_id": failed.loop_id,
                        "step_id": step.id,
                        "kind": step.kind.as_str(),
                        "error": error.to_string(),
                        "boundary": "step execution failed after start; persisted failed plan state"
                    }),
                );
            }
            return Err(error);
        }
    };
    let summary = authoring_loop_step_execution_summary(
        &completed,
        &step,
        plan_path,
        &ledger_path,
        "completed",
        generated_artifacts,
        Vec::new(),
    );
    Ok((completed, summary))
}

pub fn build_authoring_loop_dry_run_summary(
    plan: &AuthoringLoopPlan,
) -> Result<AuthoringLoopDryRunSummary> {
    build_authoring_loop_dry_run_summary_with_inspection(plan, None)
}

pub fn build_authoring_loop_dry_run_summary_with_base(
    plan: &AuthoringLoopPlan,
    base_dir: impl AsRef<Path>,
) -> Result<AuthoringLoopDryRunSummary> {
    build_authoring_loop_dry_run_summary_with_inspection(plan, Some(base_dir.as_ref()))
}

fn build_authoring_loop_dry_run_summary_with_inspection(
    plan: &AuthoringLoopPlan,
    base_dir: Option<&Path>,
) -> Result<AuthoringLoopDryRunSummary> {
    plan.validate_schema()?;
    let artifact_base_dir = base_dir.map(|base_dir| dry_run_project_artifact_root(plan, base_dir));
    let steps = plan
        .steps
        .iter()
        .map(|step| AuthoringLoopDryRunStep::from_plan_step(step, artifact_base_dir.as_deref()))
        .collect::<Vec<_>>();
    let mut missing_prerequisites = base_dir
        .map(|base_dir| dry_run_global_missing_prerequisites(plan, base_dir))
        .unwrap_or_default();
    missing_prerequisites.extend(steps.iter().flat_map(|step| {
        step.missing_prerequisites
            .iter()
            .map(|missing| format!("{}:{missing}", step.id))
    }));
    let status = if missing_prerequisites.is_empty() {
        "ready"
    } else {
        "blocked"
    };
    Ok(AuthoringLoopDryRunSummary {
        schema_version: AUTHORING_LOOP_DRY_RUN_SCHEMA_VERSION.to_string(),
        loop_id: plan.loop_id.clone(),
        project: plan.project.clone(),
        seed: plan.seed.clone(),
        scenario_pack: plan.scenario_pack.clone(),
        status: status.to_string(),
        steps,
        missing_prerequisites,
        safety_gates: vec![
            "dry-run only: no commands executed".to_string(),
            "dry-run only: no trusted files written".to_string(),
            "browser surfaces must treat command text as inert display data".to_string(),
        ],
        boundary: "Dry-run summary is inert local data; it does not execute, mutate scenes, promote regressions, or bridge browser output to commands.".to_string(),
    })
}

fn dry_run_project_artifact_root(plan: &AuthoringLoopPlan, base_dir: &Path) -> PathBuf {
    let manifest_path = base_dir.join(&plan.project.manifest_path);
    manifest_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .map(Path::to_path_buf)
        .unwrap_or_else(|| base_dir.to_path_buf())
}

impl AuthoringLoopDryRunStep {
    fn from_plan_step(step: &AuthoringLoopStep, base_dir: Option<&Path>) -> Self {
        let prerequisites = dry_run_prerequisites(step);
        let missing_prerequisites = base_dir
            .map(|base_dir| dry_run_missing_prerequisites(step, base_dir))
            .unwrap_or_default();
        let readiness = if missing_prerequisites.is_empty() {
            "ready"
        } else {
            "blocked"
        };
        Self {
            id: step.id.clone(),
            kind: step.kind.as_str().to_string(),
            status: step.status.as_str().to_string(),
            readiness: readiness.to_string(),
            command_text: step.kind.inert_command_text(),
            prerequisites,
            missing_prerequisites,
            expected_artifacts: step.expected_artifacts.clone(),
            required_decisions: step.required_decisions.clone(),
            safety_gates: step.kind.safety_gates(),
        }
    }
}

fn dry_run_global_missing_prerequisites(plan: &AuthoringLoopPlan, base_dir: &Path) -> Vec<String> {
    let mut missing = Vec::new();
    let manifest_path = base_dir.join(&plan.project.manifest_path);
    if !manifest_path.is_file() {
        missing.push(format!(
            "missing project manifest:{}",
            plan.project.manifest_path
        ));
    } else {
        match ProjectManifest::from_path(&manifest_path) {
            Ok(manifest) => {
                if manifest.project.id != plan.project.project_id {
                    missing.push(format!(
                        "stale project context:expected {} found {}",
                        plan.project.project_id, manifest.project.id
                    ));
                }
                let project_root = manifest_path
                    .parent()
                    .filter(|path| !path.as_os_str().is_empty())
                    .unwrap_or(base_dir);
                let seed_declared = manifest.seeds.iter().any(|reference| {
                    reference.id == plan.seed.id && reference.path == plan.seed.path
                });
                if !seed_declared {
                    missing.push(format!(
                        "missing seed declaration:{}:{}",
                        plan.seed.id, plan.seed.path
                    ));
                }
                let scenario_pack_declared = manifest.scenario_packs.iter().any(|reference| {
                    reference.id == plan.scenario_pack.id
                        && reference.path == plan.scenario_pack.path
                });
                if !scenario_pack_declared {
                    missing.push(format!(
                        "missing scenario pack declaration:{}:{}",
                        plan.scenario_pack.id, plan.scenario_pack.path
                    ));
                }
                for (label, reference) in
                    [("seed", &plan.seed), ("scenario pack", &plan.scenario_pack)]
                {
                    if !project_root.join(&reference.path).is_file() {
                        missing.push(format!(
                            "missing {label} file:{}:{}",
                            reference.id, reference.path
                        ));
                    }
                }
            }
            Err(error) => missing.push(format!(
                "invalid project manifest:{}:{error}",
                plan.project.manifest_path
            )),
        }
    }
    missing
}

fn dry_run_missing_prerequisites(step: &AuthoringLoopStep, base_dir: &Path) -> Vec<String> {
    let mut missing = Vec::new();
    for input in &step.inputs {
        if !base_dir.join(&input.path).exists() {
            missing.push(format!("missing artifact:{}:{}", input.id, input.path));
        }
    }
    for rollback_ref in &step.rollback_refs {
        if !base_dir.join(&rollback_ref.path).exists() {
            missing.push(format!(
                "missing rollback:{}:{}",
                rollback_ref.id, rollback_ref.path
            ));
        }
    }
    for decision in &step.required_decisions {
        if !dry_run_decision_is_satisfied(step, decision, base_dir) {
            missing.push(format!(
                "missing decision:{}:{}",
                decision.id,
                decision.kind.as_str()
            ));
        }
    }
    if step.status == AuthoringLoopStepStatus::Completed {
        for artifact in &step.expected_artifacts {
            if !base_dir.join(&artifact.path).exists() {
                missing.push(format!(
                    "missing completed output:{}:{}",
                    artifact.id, artifact.path
                ));
            }
        }
    }
    missing
}

fn dry_run_decision_is_satisfied(
    step: &AuthoringLoopStep,
    decision: &AuthoringLoopDecisionRef,
    base_dir: &Path,
) -> bool {
    step.inputs
        .iter()
        .chain(step.expected_artifacts.iter())
        .any(|artifact| {
            artifact.id == decision.id
                || artifact.path.contains(&decision.id)
                || (base_dir.join(&artifact.path).exists() && artifact.path.contains("decision"))
        })
}

fn dry_run_prerequisites(step: &AuthoringLoopStep) -> Vec<String> {
    let mut prerequisites = Vec::new();
    prerequisites.extend(
        step.depends_on
            .iter()
            .map(|dependency| format!("step:{dependency}")),
    );
    prerequisites.extend(
        step.inputs
            .iter()
            .map(|input| format!("artifact:{}:{}", input.id, input.path)),
    );
    // Rollback refs are a required gate for apply-accepted-scene-mutation steps,
    // so the dry-run prerequisite list must surface them too; otherwise reviewers
    // see a mutation step as fully inspectable while the rollback/provenance
    // artifact that makes the trusted mutation safe is omitted.
    prerequisites.extend(
        step.rollback_refs
            .iter()
            .map(|rollback| format!("rollback:{}:{}", rollback.id, rollback.path)),
    );
    prerequisites.extend(
        step.required_decisions
            .iter()
            .map(|decision| format!("decision:{}:{}", decision.id, decision.kind.as_str())),
    );
    prerequisites
}

fn next_safe_action_for_step(step: &AuthoringLoopStep, missing: &[String]) -> String {
    if let Some(recovery) = &step.recovery {
        if recovery.retryability == AuthoringLoopRetryability::NonRetryable {
            return format!(
                "Do not resume automatically; {}",
                recovery.manual_action.description
            );
        }
        if !missing.is_empty() {
            return format!(
                "Resolve missing prerequisites before resume: {}",
                missing.join(" · ")
            );
        }
        return recovery
            .resume_command
            .as_ref()
            .map(|command| format!("Resume preflight can inspect `{}`.", command.command))
            .unwrap_or_else(|| {
                format!(
                    "Run explicit resume preflight for step `{}` before any execution.",
                    step.id
                )
            });
    }
    if !missing.is_empty() {
        return format!(
            "Resolve missing prerequisites before step execution: {}",
            missing.join(" · ")
        );
    }
    match step.status {
        AuthoringLoopStepStatus::Completed => "No action needed; step is complete.".to_string(),
        AuthoringLoopStepStatus::Running => {
            "Inspect running state before resume; no hidden retry is allowed.".to_string()
        }
        AuthoringLoopStepStatus::Failed | AuthoringLoopStepStatus::Blocked => {
            "Add recovery metadata or run explicit resume preflight before retry.".to_string()
        }
        AuthoringLoopStepStatus::Pending => {
            format!(
                "Step `{}` is pending and can be explicitly executed.",
                step.id
            )
        }
    }
}

fn default_resume_command(plan_path: &Path, step_id: &str) -> AuthoringLoopResumeCommandContext {
    let plan = plan_path.display().to_string();
    AuthoringLoopResumeCommandContext {
        command: format!("cargo run -p ouroforge-cli -- loop resume {plan} --step {step_id}"),
        argv: vec![
            "cargo".to_string(),
            "run".to_string(),
            "-p".to_string(),
            "ouroforge-cli".to_string(),
            "--".to_string(),
            "loop".to_string(),
            "resume".to_string(),
            plan,
            "--step".to_string(),
            step_id.to_string(),
        ],
        boundary:
            "explicit CLI-only resume preflight; browser surfaces may display but not execute"
                .to_string(),
    }
}

fn execute_authoring_loop_run_step(
    plan: &AuthoringLoopPlan,
    step: &AuthoringLoopStep,
    base_dir: &Path,
) -> Result<Vec<AuthoringLoopGeneratedArtifact>> {
    let seed_path = base_dir.join(&plan.seed.path);
    let runs_root = base_dir.join("runs");
    reject_generated_artifact_source_collision(&runs_root, "authoring loop run step")?;
    let artifacts = create_run(&seed_path, &runs_root)?;
    let manifest_path = base_dir.join(&plan.project.manifest_path);
    let mut project_metadata = project_run_metadata_from_manifest(
        &manifest_path,
        &seed_path,
        Some(plan.scenario_pack.id.as_str()),
    )?;
    project_metadata.transaction_id = None;
    let bound_project = bind_run_project_metadata(&artifacts.run_dir, project_metadata)?;
    let command_context =
        run_command_context_for_run(&seed_path, &runs_root, 1, Some(&bound_project), None);
    bind_run_command_context(&artifacts.run_dir, command_context)?;
    append_ledger_event(
        &artifacts.run_dir,
        "authoring_loop.run_step",
        "loop-step-runner",
        json!({
            "loop_step_id": step.id,
            "loop_step_kind": step.kind.as_str(),
            "scenario_pack": plan.scenario_pack.id,
            "boundary": "created run artifacts only; scenario/browser execution is not invoked by this step"
        }),
    )?;
    Ok(vec![AuthoringLoopGeneratedArtifact {
        id: step
            .expected_artifacts
            .first()
            .map(|artifact| artifact.id.clone())
            .unwrap_or_else(|| "run".to_string()),
        path: relative_to_base(base_dir, &artifacts.run_dir.join("run.json"))?,
        kind: "run".to_string(),
    }])
}

fn execute_authoring_loop_compare_step(
    step: &AuthoringLoopStep,
    base_dir: &Path,
) -> Result<Vec<AuthoringLoopGeneratedArtifact>> {
    let run_inputs = step
        .inputs
        .iter()
        .filter(|input| input.path.ends_with("/run.json") || input.path == "run.json")
        .map(|input| base_dir.join(&input.path))
        .collect::<Vec<_>>();
    if run_inputs.len() < 2 {
        return Err(anyhow!(
            "compare-runs step {} requires at least two run.json input artifacts",
            step.id
        ));
    }
    let before_run_dir = run_inputs[0]
        .parent()
        .ok_or_else(|| anyhow!("compare-runs before input has no run directory"))?;
    let after_run_dir = run_inputs[1]
        .parent()
        .ok_or_else(|| anyhow!("compare-runs after input has no run directory"))?;
    let output_dir = step
        .expected_artifacts
        .first()
        .and_then(|artifact| {
            Path::new(&artifact.path)
                .parent()
                .map(|path| base_dir.join(path))
        })
        .unwrap_or_else(|| base_dir.join("runs/comparisons"));
    reject_generated_artifact_source_collision(&output_dir, "authoring loop comparison")?;
    let comparison_path = write_run_comparison_artifact(before_run_dir, after_run_dir, output_dir)?;
    Ok(vec![AuthoringLoopGeneratedArtifact {
        id: step
            .expected_artifacts
            .first()
            .map(|artifact| artifact.id.clone())
            .unwrap_or_else(|| "comparison".to_string()),
        path: relative_to_base(base_dir, &comparison_path)?,
        kind: "run-comparison".to_string(),
    }])
}

fn execute_authoring_loop_proposal_step(
    step: &AuthoringLoopStep,
    base_dir: &Path,
) -> Result<Vec<AuthoringLoopGeneratedArtifact>> {
    let run_json = step
        .inputs
        .iter()
        .find(|input| input.path.ends_with("/run.json") || input.path == "run.json")
        .ok_or_else(|| {
            anyhow!(
                "generate-proposal step {} requires a run.json input artifact",
                step.id
            )
        })?;
    let run_json_path = base_dir.join(&run_json.path);
    let run_dir = run_json_path
        .parent()
        .ok_or_else(|| anyhow!("generate-proposal input has no run directory"))?;
    let summary = evolve_run(run_dir)?;
    if summary.status != "proposed" {
        return Err(anyhow!(
            "generate-proposal step {} did not create a proposal: {}",
            step.id,
            summary.reason
        ));
    }
    let mut artifacts = Vec::new();
    for (id, path, kind) in [
        ("proposal", "mutation/proposals.json", "mutation-proposals"),
        (
            "classification",
            "mutation/classifications.json",
            "mutation-classifications",
        ),
        ("patch-draft", "mutation/patch-drafts.json", "patch-drafts"),
    ] {
        let absolute = run_dir.join(path);
        if absolute.is_file() {
            artifacts.push(AuthoringLoopGeneratedArtifact {
                id: step
                    .expected_artifacts
                    .iter()
                    .find(|artifact| artifact.id == id || artifact.path.ends_with(path))
                    .map(|artifact| artifact.id.clone())
                    .unwrap_or_else(|| id.to_string()),
                path: relative_to_base(base_dir, &absolute)?,
                kind: kind.to_string(),
            });
        }
    }
    if artifacts.is_empty() {
        return Err(anyhow!(
            "generate-proposal step {} completed without proposal artifacts",
            step.id
        ));
    }
    Ok(artifacts)
}

fn execute_authoring_loop_apply_step(
    step: &AuthoringLoopStep,
    base_dir: &Path,
) -> Result<Vec<AuthoringLoopGeneratedArtifact>> {
    let operation_path = find_input_parseable_as::<SceneOnlyMutationOperation>(step, base_dir)
        .ok_or_else(|| {
            anyhow!(
                "apply-accepted-scene-mutation step {} requires a scene mutation operation input",
                step.id
            )
        })?;
    let operation_input = fs::read_to_string(&operation_path)
        .with_context(|| format!("failed to read operation {}", operation_path.display()))?;
    let operation: SceneOnlyMutationOperation = serde_json::from_str(&operation_input)
        .with_context(|| format!("failed to parse operation {}", operation_path.display()))?;
    if operation.review_decision_id.is_none() {
        return Err(anyhow!(
            "apply-accepted-scene-mutation step {} requires reviewDecisionId before writes",
            step.id
        ));
    }
    let run_dir = find_run_dir_for_step(step, base_dir)?;
    let transaction_output = step
        .expected_artifacts
        .first()
        .map(|artifact| base_dir.join(&artifact.path))
        .ok_or_else(|| {
            anyhow!(
                "apply-accepted-scene-mutation step {} requires a transaction expected artifact",
                step.id
            )
        })?;
    reject_transaction_output_target_collision(
        &transaction_output,
        &base_dir.join(&operation.target_scene_path),
    )?;
    let transaction =
        apply_scene_only_mutation_operation(&run_dir, &operation, &transaction_output)?;
    Ok(vec![AuthoringLoopGeneratedArtifact {
        id: step
            .expected_artifacts
            .first()
            .map(|artifact| artifact.id.clone())
            .unwrap_or_else(|| "transaction".to_string()),
        path: relative_to_base(base_dir, &transaction_output)?,
        kind: format!("scene-edit-transaction:{}", transaction.id),
    }])
}

fn execute_authoring_loop_rerun_step(
    plan: &AuthoringLoopPlan,
    step: &AuthoringLoopStep,
    base_dir: &Path,
) -> Result<Vec<AuthoringLoopGeneratedArtifact>> {
    let transaction_path = step
        .inputs
        .iter()
        .map(|input| base_dir.join(&input.path))
        .find(|path| {
            path.file_name()
                .and_then(|name| name.to_str())
                .is_some_and(|name| name.contains("transaction") && name.ends_with(".json"))
        })
        .ok_or_else(|| anyhow!("rerun step {} requires a transaction input", step.id))?;
    let seed_path = base_dir.join(&plan.seed.path);
    let runs_root = base_dir.join("runs");
    reject_generated_artifact_source_collision(&runs_root, "authoring loop rerun step")?;
    let artifacts = create_run(&seed_path, &runs_root)?;
    let provenance = bind_run_transaction_provenance(&artifacts.run_dir, &transaction_path)
        .with_context(|| "rerun step could not bind transaction provenance")?;
    let manifest_path = base_dir.join(&plan.project.manifest_path);
    let mut project_metadata = project_run_metadata_from_manifest(
        &manifest_path,
        &seed_path,
        Some(plan.scenario_pack.id.as_str()),
    )?;
    project_metadata.transaction_id = Some(provenance.transaction_id.clone());
    let bound_project = bind_run_project_metadata(&artifacts.run_dir, project_metadata)?;
    let command_context = run_command_context_for_run(
        &seed_path,
        &runs_root,
        1,
        Some(&bound_project),
        Some(&transaction_path),
    );
    bind_run_command_context(&artifacts.run_dir, command_context)?;
    append_ledger_event(
        &artifacts.run_dir,
        "authoring_loop.rerun_step",
        "loop-step-runner",
        json!({
            "loop_step_id": step.id,
            "transaction_id": provenance.transaction_id,
            "boundary": "created transaction-bound rerun artifacts only; browser execution is not invoked by this step"
        }),
    )?;
    Ok(vec![AuthoringLoopGeneratedArtifact {
        id: step
            .expected_artifacts
            .first()
            .map(|artifact| artifact.id.clone())
            .unwrap_or_else(|| "after-run".to_string()),
        path: relative_to_base(base_dir, &artifacts.run_dir.join("run.json"))?,
        kind: "rerun".to_string(),
    }])
}

fn execute_authoring_loop_promotion_step(
    plan: &AuthoringLoopPlan,
    step: &AuthoringLoopStep,
    base_dir: &Path,
) -> Result<Vec<AuthoringLoopGeneratedArtifact>> {
    if !step_has_accepted_decision(
        step,
        base_dir,
        AuthoringLoopDecisionKind::RegressionPromotion,
    )? {
        return Err(anyhow!(
            "promote-regression step {} requires an accepted regression promotion decision before writes",
            step.id
        ));
    }
    let draft_path = find_input_parseable_as::<RegressionPromotionDraft>(step, base_dir)
        .ok_or_else(|| {
            anyhow!(
                "promote-regression step {} requires a regression promotion draft input",
                step.id
            )
        })?;
    let draft = RegressionPromotionDraft::from_path(&draft_path)?;
    let project_root = dry_run_project_artifact_root(plan, base_dir);
    let result = promote_regression_draft_to_scenario_pack(
        &draft_path,
        project_root.join(&draft.target.project_manifest_path),
        &draft.target.scenario_pack_id,
        false,
    )?;
    let record_path = result.record_path.clone().ok_or_else(|| {
        anyhow!(
            "promote-regression step {} completed without a promotion record",
            step.id
        )
    })?;
    Ok(vec![AuthoringLoopGeneratedArtifact {
        id: step
            .expected_artifacts
            .first()
            .map(|artifact| artifact.id.clone())
            .unwrap_or_else(|| "promotion".to_string()),
        path: format!("{}/{}", draft.source_run.run_dir, record_path),
        kind: "regression-promotion".to_string(),
    }])
}

fn find_input_parseable_as<T>(step: &AuthoringLoopStep, base_dir: &Path) -> Option<PathBuf>
where
    T: for<'de> Deserialize<'de>,
{
    step.inputs.iter().find_map(|input| {
        let path = base_dir.join(&input.path);
        let input = fs::read_to_string(&path).ok()?;
        serde_json::from_str::<T>(&input).ok()?;
        Some(path)
    })
}

fn find_run_dir_for_step(step: &AuthoringLoopStep, base_dir: &Path) -> Result<PathBuf> {
    for input in &step.inputs {
        let mut current = base_dir.join(&input.path);
        if current.is_file() {
            current.pop();
        }
        loop {
            if current.join("run.json").is_file() {
                return Ok(current);
            }
            if !current.pop() {
                break;
            }
        }
    }
    Err(anyhow!(
        "step {} requires an input inside a run directory",
        step.id
    ))
}

fn step_has_accepted_decision(
    step: &AuthoringLoopStep,
    base_dir: &Path,
    expected_kind: AuthoringLoopDecisionKind,
) -> Result<bool> {
    let required_ids = step
        .required_decisions
        .iter()
        .filter(|decision| decision.kind == expected_kind)
        .map(|decision| decision.id.as_str())
        .collect::<Vec<_>>();
    if required_ids.is_empty() {
        return Ok(false);
    }
    for input in &step.inputs {
        let path = base_dir.join(&input.path);
        if !path.is_file() {
            continue;
        }
        let value = match fs::read_to_string(&path)
            .ok()
            .and_then(|input| serde_json::from_str::<serde_json::Value>(&input).ok())
        {
            Some(value) => value,
            None => continue,
        };
        for required_id in &required_ids {
            if json_value_contains_accepted_decision(&value, required_id) {
                return Ok(true);
            }
        }
    }
    Ok(false)
}

fn json_value_contains_accepted_decision(value: &serde_json::Value, required_id: &str) -> bool {
    match value {
        serde_json::Value::Object(map) => {
            // Require an explicit id equal to the required decision id. Treating a
            // missing id as a match would let any nested `{status: "accepted"}`
            // object authorize a promotion for an unapproved decision.
            let id_matches = map
                .get("id")
                .and_then(|value| value.as_str())
                .is_some_and(|id| id == required_id);
            let accepted = ["state", "decision_status", "decisionStatus", "status"]
                .iter()
                .any(|key| {
                    map.get(*key)
                        .and_then(|value| value.as_str())
                        .is_some_and(|state| state == "accepted")
                });
            (id_matches && accepted)
                || map
                    .values()
                    .any(|value| json_value_contains_accepted_decision(value, required_id))
        }
        serde_json::Value::Array(values) => values
            .iter()
            .any(|value| json_value_contains_accepted_decision(value, required_id)),
        _ => false,
    }
}

fn remap_authoring_loop_artifact_paths(
    mut plan: AuthoringLoopPlan,
    artifacts: &[AuthoringLoopGeneratedArtifact],
) -> Result<AuthoringLoopPlan> {
    for generated in artifacts {
        validate_path_component("authoring loop generated artifact id", &generated.id)?;
        validate_project_manifest_path("authoring loop generated artifact path", &generated.path)?;
        for step in &mut plan.steps {
            for artifact in &mut step.expected_artifacts {
                if artifact.id == generated.id {
                    artifact.path = generated.path.clone();
                }
            }
            for input in &mut step.inputs {
                if input.id == generated.id {
                    input.path = generated.path.clone();
                }
            }
            for rollback_ref in &mut step.rollback_refs {
                if rollback_ref.id == generated.id {
                    rollback_ref.path = generated.path.clone();
                }
            }
            if let Some(recovery) = &mut step.recovery {
                for rollback_ref in &mut recovery.rollback_refs {
                    if rollback_ref.id == generated.id {
                        rollback_ref.path = generated.path.clone();
                    }
                }
                for evidence_ref in &mut recovery.evidence_refs {
                    if evidence_ref.id == generated.id {
                        evidence_ref.path = generated.path.clone();
                    }
                }
            }
        }
    }
    plan.validate_schema()?;
    Ok(plan)
}

fn authoring_loop_step_execution_summary(
    plan: &AuthoringLoopPlan,
    step: &AuthoringLoopStep,
    plan_path: &Path,
    ledger_path: &Path,
    status: &str,
    generated_artifacts: Vec<AuthoringLoopGeneratedArtifact>,
    blocked_reasons: Vec<String>,
) -> AuthoringLoopStepExecutionSummary {
    AuthoringLoopStepExecutionSummary {
        schema_version: AUTHORING_LOOP_STEP_EXECUTION_SCHEMA_VERSION.to_string(),
        loop_id: plan.loop_id.clone(),
        step_id: step.id.clone(),
        kind: step.kind.as_str().to_string(),
        status: status.to_string(),
        plan_path: plan_path.display().to_string(),
        ledger_path: ledger_path.display().to_string(),
        generated_artifacts,
        blocked_reasons,
        boundary: "CLI-only Rust trusted step runner; no browser command bridge, source-code mutation, daemon, scheduler, hosted orchestration, or auto-merge behavior".to_string(),
    }
}

fn ensure_authoring_loop_ledger_dir(base_dir: &Path, loop_id: &str) -> Result<PathBuf> {
    validate_path_component("authoring loop id", loop_id)?;
    let ledger_dir = base_dir.join("runs/authoring-loop-ledgers").join(loop_id);
    fs::create_dir_all(&ledger_dir).with_context(|| {
        format!(
            "failed to create authoring loop ledger dir {}",
            ledger_dir.display()
        )
    })?;
    let ledger_path = ledger_dir.join("ledger.jsonl");
    if !ledger_path.exists() {
        write_ledger_created(&ledger_path, unix_millis()?)?;
    }
    Ok(ledger_dir)
}

fn relative_to_base(base_dir: &Path, path: &Path) -> Result<String> {
    let relative = path.strip_prefix(base_dir).unwrap_or(path);
    relative
        .to_str()
        .map(|path| path.replace('\\', "/"))
        .ok_or_else(|| anyhow!("path is not valid UTF-8: {}", path.display()))
}

const PROJECT_MANIFEST_SCHEMA_VERSION: &str = "project-manifest-v1";
const PROJECT_MANIFEST_FILE_NAME: &str = "ouroforge.project.json";
const LOCAL_TOOL_ROOTS: &[&str] = &[".claude", ".git", ".omc", ".omx", ".openchrome"];
const AUTHORING_LOOP_GENERATED_ROOTS: &[&str] = &[".claude", ".omc", ".omx", ".openchrome"];

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct ProjectManifest {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    pub project: ProjectManifestProject,
    #[serde(default)]
    pub scenes: Vec<ProjectManifestPathRef>,
    #[serde(default)]
    pub seeds: Vec<ProjectManifestPathRef>,
    #[serde(default, rename = "scenarioPacks")]
    pub scenario_packs: Vec<ProjectManifestPathRef>,
    #[serde(default, rename = "assetRoots")]
    pub asset_roots: Vec<String>,
    #[serde(rename = "runsRoot")]
    pub runs_root: String,
    pub generated: ProjectManifestGeneratedPolicy,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct ProjectManifestProject {
    pub id: String,
    pub name: String,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct ProjectManifestPathRef {
    pub id: String,
    pub path: String,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct ProjectManifestGeneratedPolicy {
    pub roots: Vec<String>,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
pub struct ProjectManifestValidationReport {
    pub project_id: String,
    pub manifest_path: PathBuf,
    pub source_refs: usize,
    pub asset_roots: usize,
    pub scenario_packs: usize,
    pub runs_root: String,
    pub generated_roots: Vec<String>,
}

impl ProjectManifest {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let manifest: ProjectManifest =
            serde_json::from_str(input).context("failed to parse Project Manifest JSON")?;
        manifest.validate()?;
        Ok(manifest)
    }

    pub fn from_path(path: impl AsRef<Path>) -> Result<Self> {
        let path = path.as_ref();
        if path.file_name().and_then(|name| name.to_str()) != Some(PROJECT_MANIFEST_FILE_NAME) {
            return Err(anyhow!(
                "project manifest file must be named {PROJECT_MANIFEST_FILE_NAME}"
            ));
        }
        let input = fs::read_to_string(path)
            .with_context(|| format!("failed to read project manifest {}", path.display()))?;
        let manifest = Self::from_json_str(&input)
            .with_context(|| format!("failed to parse project manifest {}", path.display()))?;
        let base_dir = match path.parent() {
            Some(parent) if !parent.as_os_str().is_empty() => parent,
            _ => Path::new("."),
        };
        manifest.validate_references(base_dir).with_context(|| {
            format!(
                "project manifest {} references invalid files",
                path.display()
            )
        })?;
        Ok(manifest)
    }

    pub fn validate(&self) -> Result<()> {
        if self.schema_version != PROJECT_MANIFEST_SCHEMA_VERSION {
            return Err(anyhow!(
                "project manifest schemaVersion must be {PROJECT_MANIFEST_SCHEMA_VERSION}"
            ));
        }
        self.project.validate()?;
        if self.scenes.is_empty() {
            return Err(anyhow!("project manifest scenes must not be empty"));
        }
        if self.seeds.is_empty() {
            return Err(anyhow!("project manifest seeds must not be empty"));
        }
        if self.asset_roots.is_empty() {
            return Err(anyhow!("project manifest assetRoots must not be empty"));
        }
        validate_project_manifest_path("project manifest runsRoot", &self.runs_root)?;
        if !self
            .generated
            .roots
            .iter()
            .any(|root| root == &self.runs_root)
        {
            return Err(anyhow!(
                "project manifest generated.roots must include runsRoot {}",
                self.runs_root
            ));
        }
        self.generated.validate()?;
        validate_manifest_ref_list("project manifest scenes", &self.scenes)?;
        validate_manifest_ref_list("project manifest seeds", &self.seeds)?;
        validate_manifest_ref_list("project manifest scenarioPacks", &self.scenario_packs)?;
        validate_project_path_list("project manifest assetRoots", &self.asset_roots)?;
        self.validate_source_generated_overlap()?;
        Ok(())
    }

    pub fn validate_references(&self, base_dir: &Path) -> Result<ProjectManifestValidationReport> {
        self.validate()?;
        let base = base_dir
            .canonicalize()
            .with_context(|| format!("failed to resolve project root {}", base_dir.display()))?;
        for (field, refs) in [
            ("scenes", self.scenes.as_slice()),
            ("seeds", self.seeds.as_slice()),
            ("scenarioPacks", self.scenario_packs.as_slice()),
        ] {
            for reference in refs {
                let path = base_dir.join(&reference.path);
                if !path.is_file() {
                    return Err(anyhow!(
                        "project manifest {field} ref {} missing file: {}",
                        reference.id,
                        reference.path
                    ));
                }
                let resolved = path.canonicalize().with_context(|| {
                    format!(
                        "failed to resolve project manifest {field} ref {} path {}",
                        reference.id, reference.path
                    )
                })?;
                if !resolved.starts_with(&base) {
                    return Err(anyhow!(
                        "project manifest {field} ref {} must stay inside the project root",
                        reference.id
                    ));
                }
            }
        }
        for root in &self.asset_roots {
            let path = base_dir.join(root);
            if !path.is_dir() {
                return Err(anyhow!(
                    "project manifest assetRoots missing directory: {root}"
                ));
            }
            let resolved = path
                .canonicalize()
                .with_context(|| format!("failed to resolve project manifest assetRoot {root}"))?;
            if !resolved.starts_with(&base) {
                return Err(anyhow!(
                    "project manifest assetRoot {root} must stay inside the project root"
                ));
            }
        }
        self.validate_scene_transitions(base_dir)?;
        let scenario_packs = self.resolve_scenario_packs(base_dir)?;
        Ok(ProjectManifestValidationReport {
            project_id: self.project.id.clone(),
            manifest_path: base_dir.join(PROJECT_MANIFEST_FILE_NAME),
            source_refs: self.scenes.len() + self.seeds.len() + self.scenario_packs.len(),
            asset_roots: self.asset_roots.len(),
            scenario_packs: scenario_packs.len(),
            runs_root: self.runs_root.clone(),
            generated_roots: self.generated.roots.clone(),
        })
    }

    fn source_paths(&self) -> Vec<(&'static str, &str)> {
        self.scenes
            .iter()
            .map(|reference| ("scenes", reference.path.as_str()))
            .chain(
                self.seeds
                    .iter()
                    .map(|reference| ("seeds", reference.path.as_str())),
            )
            .chain(
                self.scenario_packs
                    .iter()
                    .map(|reference| ("scenarioPacks", reference.path.as_str())),
            )
            .chain(
                self.asset_roots
                    .iter()
                    .map(|root| ("assetRoots", root.as_str())),
            )
            .collect()
    }

    fn validate_scene_transitions(&self, base_dir: &Path) -> Result<()> {
        self.validate()?;
        let scene_paths = self
            .scenes
            .iter()
            .map(|reference| reference.path.as_str())
            .collect::<BTreeSet<_>>();
        for reference in &self.scenes {
            let transitions =
                read_scene_transitions(base_dir.join(&reference.path)).with_context(|| {
                    format!(
                        "project manifest scenes ref {} failed transition validation: {}",
                        reference.id, reference.path
                    )
                })?;
            for transition in &transitions {
                if !scene_paths.contains(transition.to_scene.as_str()) {
                    return Err(anyhow!(
                        "scene {} transition {} toScene {} is not declared in project manifest scenes",
                        reference.path,
                        transition.id,
                        transition.to_scene
                    ));
                }
            }
        }
        Ok(())
    }

    pub fn resolve_scenario_packs(&self, base_dir: &Path) -> Result<Vec<ScenarioPack>> {
        self.validate()?;
        let mut packs = Vec::new();
        let mut pack_ids = BTreeSet::new();
        let seed_paths = self
            .seeds
            .iter()
            .map(|reference| reference.path.as_str())
            .collect::<BTreeSet<_>>();
        let scene_paths = self
            .scenes
            .iter()
            .map(|reference| reference.path.as_str())
            .collect::<BTreeSet<_>>();
        for reference in &self.scenario_packs {
            let path = base_dir.join(&reference.path);
            let pack = ScenarioPack::from_path(&path).with_context(|| {
                format!(
                    "project manifest scenarioPacks ref {} failed validation: {}",
                    reference.id, reference.path
                )
            })?;
            if pack.id != reference.id {
                return Err(anyhow!(
                    "project manifest scenarioPacks ref {} id mismatch: pack id is {}",
                    reference.id,
                    pack.id
                ));
            }
            if !seed_paths.contains(pack.seed.as_str()) {
                return Err(anyhow!(
                    "scenario pack {} seed {} is not declared in project manifest seeds",
                    pack.id,
                    pack.seed
                ));
            }
            for scene in &pack.scenes {
                if !scene_paths.contains(scene.as_str()) {
                    return Err(anyhow!(
                        "scenario pack {} scene {} is not declared in project manifest scenes",
                        pack.id,
                        scene
                    ));
                }
            }
            if !pack_ids.insert(pack.id.clone()) {
                return Err(anyhow!("duplicate resolved scenario pack id: {}", pack.id));
            }
            packs.push(pack);
        }
        Ok(packs)
    }

    fn validate_source_generated_overlap(&self) -> Result<()> {
        for (field, source_path) in self.source_paths() {
            for generated_root in &self.generated.roots {
                if project_manifest_paths_overlap(source_path, generated_root) {
                    return Err(anyhow!(
                        "project manifest {field} path {source_path} must not overlap generated root {generated_root}"
                    ));
                }
            }
        }
        Ok(())
    }
}

impl ProjectManifestProject {
    fn validate(&self) -> Result<()> {
        validate_path_component("project manifest project.id", &self.id)?;
        require_text("project manifest project.name", &self.name)
    }
}

impl ProjectManifestPathRef {
    fn validate(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field} id"), &self.id)?;
        validate_project_manifest_path(&format!("{field} path"), &self.path)
    }
}

impl ProjectManifestGeneratedPolicy {
    fn validate(&self) -> Result<()> {
        if self.roots.is_empty() {
            return Err(anyhow!(
                "project manifest generated.roots must not be empty"
            ));
        }
        validate_project_path_list("project manifest generated.roots", &self.roots)
    }
}

fn validate_manifest_ref_list(field: &str, refs: &[ProjectManifestPathRef]) -> Result<()> {
    let mut ids = BTreeSet::new();
    let mut paths = BTreeSet::new();
    for (index, reference) in refs.iter().enumerate() {
        reference.validate(&format!("{field}[{index}]"))?;
        if !ids.insert(reference.id.clone()) {
            return Err(anyhow!("duplicate {field} id: {}", reference.id));
        }
        if !paths.insert(reference.path.clone()) {
            return Err(anyhow!("duplicate {field} path: {}", reference.path));
        }
    }
    Ok(())
}

fn validate_project_path_list(field: &str, values: &[String]) -> Result<()> {
    let mut paths = BTreeSet::new();
    for (index, value) in values.iter().enumerate() {
        validate_project_manifest_path(&format!("{field}[{index}]"), value)?;
        if !paths.insert(value.clone()) {
            return Err(anyhow!("duplicate {field} path: {value}"));
        }
    }
    Ok(())
}

/// Validate authoring loop plan `generatedState.roots`. Like
/// [`validate_project_path_list`] it blocks traversal and absolute paths and
/// rejects hidden path components, but it permits a known local-tool/generated
/// root (e.g. `.omx`, `.omc`, `.claude`, `.openchrome`) as the *leading*
/// component, since loop plans must be able to model that ignored generated
/// state. Deeper hidden components are still rejected.
fn validate_authoring_loop_generated_roots(field: &str, values: &[String]) -> Result<()> {
    let mut paths = BTreeSet::new();
    for (index, value) in values.iter().enumerate() {
        validate_authoring_loop_generated_root(&format!("{field}[{index}]"), value)?;
        if !paths.insert(value.clone()) {
            return Err(anyhow!("duplicate {field} path: {value}"));
        }
    }
    Ok(())
}

fn validate_authoring_loop_generated_root(field: &str, value: &str) -> Result<()> {
    require_text(field, value)?;
    if !value
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '/' | '.' | '-' | '_'))
    {
        return Err(anyhow!(
            "{field} may only contain ASCII letters, numbers, '/', '.', '-' or '_'"
        ));
    }
    let path = Path::new(value);
    if path.is_absolute() {
        return Err(anyhow!("{field} must be relative"));
    }
    for (index, component) in path.components().enumerate() {
        match component {
            Component::Normal(component) => {
                let Some(component) = component.to_str() else {
                    return Err(anyhow!("{field} must be valid UTF-8"));
                };
                // The leading component may be a known hidden generated root;
                // any other hidden component is rejected to keep traversal and
                // stray hidden state out of the plan.
                let is_allowed_generated_root =
                    index == 0 && AUTHORING_LOOP_GENERATED_ROOTS.contains(&component);
                if component.starts_with('.') && !is_allowed_generated_root {
                    return Err(anyhow!(
                        "{field} must not use hidden path components other than known generated roots"
                    ));
                }
            }
            Component::CurDir => {}
            _ => return Err(anyhow!("{field} must stay inside the project root")),
        }
    }
    Ok(())
}

fn validate_project_manifest_path(field: &str, value: &str) -> Result<()> {
    require_text(field, value)?;
    if !value
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '/' | '.' | '-' | '_'))
    {
        return Err(anyhow!(
            "{field} may only contain ASCII letters, numbers, '/', '.', '-' or '_'"
        ));
    }
    let path = Path::new(value);
    if path.is_absolute() {
        return Err(anyhow!("{field} must be relative"));
    }
    for component in path.components() {
        match component {
            Component::Normal(value) => {
                let Some(component) = value.to_str() else {
                    return Err(anyhow!("{field} must be valid UTF-8"));
                };
                if component.starts_with('.') {
                    return Err(anyhow!(
                        "{field} must not use hidden local tool directories or hidden path components"
                    ));
                }
                if LOCAL_TOOL_ROOTS.contains(&component) {
                    return Err(anyhow!(
                        "{field} must not point at hidden local tool directory {component}"
                    ));
                }
            }
            Component::CurDir => {}
            _ => return Err(anyhow!("{field} must stay inside the project root")),
        }
    }
    Ok(())
}

fn project_manifest_paths_overlap(left: &str, right: &str) -> bool {
    let left = left.trim_matches('/');
    let right = right.trim_matches('/');
    left == right
        || left
            .strip_prefix(right)
            .is_some_and(|rest| rest.starts_with('/'))
        || right
            .strip_prefix(left)
            .is_some_and(|rest| rest.starts_with('/'))
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ProjectScaffoldFile {
    pub path: &'static str,
    pub contents: &'static str,
}

pub fn minimal_2d_project_scaffold_files() -> Vec<ProjectScaffoldFile> {
    vec![
        ProjectScaffoldFile {
            path: "ouroforge.project.json",
            contents: MINIMAL_2D_PROJECT_MANIFEST,
        },
        ProjectScaffoldFile {
            path: "scenes/main.scene.json",
            contents: MINIMAL_2D_PROJECT_SCENE,
        },
        ProjectScaffoldFile {
            path: "seeds/platformer.yaml",
            contents: MINIMAL_2D_PROJECT_SEED,
        },
        ProjectScaffoldFile {
            path: "scenarios/smoke.scenario-pack.json",
            contents: MINIMAL_2D_PROJECT_SCENARIO_PACK,
        },
        ProjectScaffoldFile {
            path: "assets/README.md",
            contents: MINIMAL_2D_PROJECT_ASSETS_README,
        },
        ProjectScaffoldFile {
            path: "README.md",
            contents: MINIMAL_2D_PROJECT_README,
        },
        ProjectScaffoldFile {
            path: ".gitignore",
            contents: MINIMAL_2D_PROJECT_GITIGNORE,
        },
    ]
}

pub fn create_minimal_2d_project_scaffold(
    destination: impl AsRef<Path>,
) -> Result<ProjectManifestValidationReport> {
    let destination = destination.as_ref();
    validate_project_scaffold_destination_path(destination)?;
    if destination.exists() {
        if !destination.is_dir() {
            return Err(anyhow!(
                "project scaffold destination exists and is not a directory: {}",
                destination.display()
            ));
        }
        if destination
            .read_dir()
            .with_context(|| format!("failed to read destination {}", destination.display()))?
            .next()
            .is_some()
        {
            return Err(anyhow!(
                "project scaffold destination must be empty: {}",
                destination.display()
            ));
        }
    } else {
        fs::create_dir_all(destination).with_context(|| {
            format!(
                "failed to create project scaffold destination {}",
                destination.display()
            )
        })?;
    }

    for file in minimal_2d_project_scaffold_files() {
        let relative = Path::new(file.path);
        let path = destination.join(relative);
        if let Some(parent) = path.parent() {
            fs::create_dir_all(parent).with_context(|| {
                format!("failed to create scaffold directory {}", parent.display())
            })?;
        }
        fs::write(&path, file.contents)
            .with_context(|| format!("failed to write scaffold file {}", path.display()))?;
    }

    let manifest_path = destination.join(PROJECT_MANIFEST_FILE_NAME);
    let manifest = ProjectManifest::from_path(&manifest_path)?;
    let report = manifest.validate_references(destination)?;
    Seed::from_path(destination.join("seeds/platformer.yaml"))?;
    read_scene(destination.join("scenes/main.scene.json"))?;
    Ok(report)
}

pub fn validate_project_scaffold_destination_path(path: impl AsRef<Path>) -> Result<()> {
    let path = path.as_ref();
    require_text("project scaffold destination", &path.to_string_lossy())?;
    for component in path.components() {
        match component {
            Component::ParentDir => {
                return Err(anyhow!(
                    "project scaffold destination must not contain '..' path traversal"
                ))
            }
            Component::Normal(value) => {
                if value.to_str().is_none() {
                    return Err(anyhow!("project scaffold destination must be valid UTF-8"));
                }
            }
            Component::CurDir | Component::RootDir | Component::Prefix(_) => {}
        }
    }
    Ok(())
}

