impl AssetPreviewEvidence {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let evidence: AssetPreviewEvidence =
            serde_json::from_str(input).context("failed to parse Asset Preview Evidence JSON")?;
        evidence.validate()?;
        Ok(evidence)
    }

    pub fn validate(&self) -> Result<()> {
        if self.schema_version != ASSET_PREVIEW_EVIDENCE_SCHEMA_VERSION {
            return Err(anyhow!(
                "asset preview evidence schemaVersion must be {ASSET_PREVIEW_EVIDENCE_SCHEMA_VERSION}"
            ));
        }
        if let Some(run_id) = &self.run_id {
            validate_path_component("asset preview evidence runId", run_id)?;
        }
        validate_path_component("asset preview evidence manifestId", &self.manifest_id)?;
        require_text("asset preview evidence boundary", &self.boundary)?;
        if self.previews.is_empty() && self.warnings.is_empty() {
            return Err(anyhow!(
                "asset preview evidence requires at least one preview record or warning"
            ));
        }
        let mut asset_ids = BTreeSet::new();
        for (index, preview) in self.previews.iter().enumerate() {
            preview.validate(index)?;
            if !asset_ids.insert(preview.asset_id.as_str()) {
                return Err(anyhow!(
                    "duplicate asset preview evidence assetId: {}",
                    preview.asset_id
                ));
            }
        }
        for (index, warning) in self.warnings.iter().enumerate() {
            warning.validate(&format!("asset preview evidence warnings[{index}]"))?;
        }
        Ok(())
    }
}

impl AssetPreviewRecord {
    fn validate(&self, index: usize) -> Result<()> {
        let field = format!("asset preview evidence previews[{index}]");
        validate_path_component(&format!("{field}.assetId"), &self.asset_id)?;
        validate_project_asset_path(
            &format!("{field}.sourcePath"),
            &self.source_path,
            self.asset_type,
            ProjectAssetClassification::SourceLike,
        )?;
        if let Some(preview_path) = &self.preview_path {
            let classification = self
                .preview_classification
                .unwrap_or(ProjectAssetClassification::Generated);
            validate_asset_preview_path(
                &format!("{field}.previewPath"),
                preview_path,
                classification,
            )?;
        }
        if self.preview_path.is_none() && self.preview_classification.is_some() {
            return Err(anyhow!(
                "{field}.previewClassification requires previewPath"
            ));
        }
        if let Some(image) = &self.image {
            image.validate(&format!("{field}.image"))?;
        }
        for (frame_index, frame) in self.atlas_frames.iter().enumerate() {
            frame.validate(&format!("{field}.atlasFrames[{frame_index}]"))?;
        }
        if let Some(tilemap) = &self.tilemap {
            tilemap.validate(&format!("{field}.tilemap"))?;
        }
        if let Some(audio) = &self.audio {
            audio.validate(&format!("{field}.audio"))?;
        }
        if let Some(font) = &self.font {
            font.validate(&format!("{field}.font"))?;
        }
        for (warning_index, warning) in self.warnings.iter().enumerate() {
            warning.validate(&format!("{field}.warnings[{warning_index}]"))?;
        }
        Ok(())
    }
}

impl AssetPreviewImageMetadata {
    fn validate(&self, field: &str) -> Result<()> {
        if self.width == 0 || self.height == 0 {
            return Err(anyhow!("{field} dimensions must be positive"));
        }
        Ok(())
    }
}

impl AssetPreviewAtlasFrame {
    fn validate(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.frameId"), &self.frame_id)?;
        if self.rect.width == 0 || self.rect.height == 0 {
            return Err(anyhow!("{field}.rect dimensions must be positive"));
        }
        Ok(())
    }
}

impl AssetPreviewTilemapMetadata {
    fn validate(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.tilesetAssetId"), &self.tileset_asset_id)?;
        if self.width == 0 || self.height == 0 {
            return Err(anyhow!("{field} dimensions must be positive"));
        }
        if self.layer_count == 0 {
            return Err(anyhow!("{field}.layerCount must be positive"));
        }
        Ok(())
    }
}

impl AssetPreviewAudioMetadata {
    fn validate(&self, field: &str) -> Result<()> {
        if self.duration_ms == Some(0) {
            return Err(anyhow!("{field}.durationMs must be positive when present"));
        }
        if self.channels == Some(0) {
            return Err(anyhow!("{field}.channels must be positive when present"));
        }
        Ok(())
    }
}

impl AssetPreviewFontMetadata {
    fn validate(&self, field: &str) -> Result<()> {
        if let Some(family) = &self.family {
            require_bounded_display_text(&format!("{field}.family"), family)?;
        }
        if let Some(style) = &self.style {
            require_bounded_display_text(&format!("{field}.style"), style)?;
        }
        Ok(())
    }
}

impl AssetPreviewWarning {
    fn validate(&self, field: &str) -> Result<()> {
        if let Some(asset_id) = &self.asset_id {
            validate_path_component(&format!("{field}.assetId"), asset_id)?;
        }
        validate_path_component(&format!("{field}.kind"), &self.kind)?;
        require_bounded_display_text(&format!("{field}.message"), &self.message)?;
        if let Some(path) = &self.path {
            validate_project_manifest_path(&format!("{field}.path"), path)?;
        }
        Ok(())
    }
}

pub fn generate_asset_preview_evidence(
    manifest: &ProjectAssetManifest,
    manifest_base_dir: impl AsRef<Path>,
    run_id: Option<String>,
    generated_at_unix_ms: u128,
) -> Result<AssetPreviewEvidence> {
    let manifest_base_dir = manifest_base_dir.as_ref();
    let manifest_base = manifest_base_dir.canonicalize().with_context(|| {
        format!(
            "failed to resolve project asset manifest base {}",
            manifest_base_dir.display()
        )
    })?;
    let mut previews = Vec::new();
    let mut warnings = Vec::new();
    for asset in &manifest.assets {
        if let Some(warning) =
            preview_warning_from_integrity(asset, manifest_base_dir, &manifest_base)
        {
            warnings.push(warning);
        }
        previews.push(AssetPreviewRecord {
            asset_id: asset.id.clone(),
            asset_type: asset.asset_type,
            source_path: asset.path.clone(),
            preview_kind: preview_kind_for_asset(asset),
            preview_path: None,
            preview_classification: None,
            image: asset
                .dimensions
                .as_ref()
                .map(|dimensions| AssetPreviewImageMetadata {
                    width: dimensions.width,
                    height: dimensions.height,
                }),
            atlas_frames: asset
                .atlas
                .as_ref()
                .map(|atlas| {
                    atlas
                        .frames
                        .iter()
                        .map(|frame| AssetPreviewAtlasFrame {
                            frame_id: frame.id.clone(),
                            rect: frame.rect.clone(),
                        })
                        .collect()
                })
                .unwrap_or_default(),
            tilemap: asset
                .tilemap
                .as_ref()
                .map(|tilemap| AssetPreviewTilemapMetadata {
                    tileset_asset_id: tilemap.tileset_asset_id.clone(),
                    width: tilemap.width,
                    height: tilemap.height,
                    layer_count: tilemap.layers.len(),
                    tile_count: tilemap
                        .layers
                        .iter()
                        .flat_map(|layer| layer.data.iter())
                        .filter(|tile| tile.is_some())
                        .count(),
                }),
            audio: (asset.asset_type == ProjectAssetType::Audio).then(|| {
                AssetPreviewAudioMetadata {
                    duration_ms: asset.duration_ms.map(u64::from),
                    channels: asset
                        .metadata
                        .get("channels")
                        .and_then(|value| value.parse::<u8>().ok()),
                }
            }),
            font: (asset.asset_type == ProjectAssetType::Font).then(|| AssetPreviewFontMetadata {
                family: asset.metadata.get("family").cloned(),
                style: asset.metadata.get("style").cloned(),
            }),
            warnings: Vec::new(),
        });
    }
    let evidence = AssetPreviewEvidence {
        schema_version: ASSET_PREVIEW_EVIDENCE_SCHEMA_VERSION.to_string(),
        run_id,
        manifest_id: manifest.id.clone(),
        generated_at_unix_ms,
        previews,
        warnings,
        boundary: "Read-only local asset preview metadata; generated previews remain local/untracked and browser surfaces must not upload, write, fetch remote assets, or execute commands.".to_string(),
    };
    evidence.validate()?;
    Ok(evidence)
}

fn preview_kind_for_asset(asset: &ProjectAssetManifestEntry) -> AssetPreviewKind {
    match asset.asset_type {
        ProjectAssetType::Image | ProjectAssetType::SpriteAtlas => AssetPreviewKind::Thumbnail,
        ProjectAssetType::Tileset
        | ProjectAssetType::Tilemap
        | ProjectAssetType::Audio
        | ProjectAssetType::Font => AssetPreviewKind::Metadata,
    }
}

fn preview_warning_from_integrity(
    asset: &ProjectAssetManifestEntry,
    manifest_base_dir: &Path,
    manifest_base: &Path,
) -> Option<AssetPreviewWarning> {
    project_asset_entry_file_integrity_warning(
        asset,
        manifest_base_dir,
        manifest_base,
        "asset preview evidence source asset",
    )
    .map(|warning| AssetPreviewWarning {
        asset_id: Some(warning.asset_id),
        kind: warning.kind,
        message: warning.message,
        path: warning.path,
    })
}

fn validate_asset_preview_path(
    field: &str,
    value: &str,
    classification: ProjectAssetClassification,
) -> Result<()> {
    validate_project_manifest_path(field, value)?;
    if classification == ProjectAssetClassification::SourceLike {
        for generated_root in PROJECT_ASSET_SOURCE_GENERATED_ROOTS {
            if project_manifest_paths_overlap(value, generated_root) {
                return Err(anyhow!(
                    "{field} for source-like previews must not overlap generated root {generated_root}"
                ));
            }
        }
    }
    let extension = Path::new(value)
        .extension()
        .and_then(|value| value.to_str())
        .unwrap_or_default()
        .to_ascii_lowercase();
    if matches!(
        extension.as_str(),
        "png" | "jpg" | "jpeg" | "svg" | "webp" | "json"
    ) {
        Ok(())
    } else {
        Err(anyhow!(
            "{field} has unsupported extension for asset preview evidence"
        ))
    }
}

const ROUTE_ATTEMPT_EVIDENCE_SCHEMA_VERSION: &str = "route-attempt-evidence-v1";
const MAX_ROUTE_ATTEMPT_ACTIONS: u32 = 1_000;
const MAX_ROUTE_ATTEMPT_ROUTE_NODES: u32 = 1_000;
const MAX_ROUTE_ATTEMPT_DURATION_MS: u64 = 600_000;

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct RouteAttemptEvidenceArtifact {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    #[serde(rename = "attemptId")]
    pub attempt_id: String,
    #[serde(rename = "runId")]
    pub run_id: String,
    #[serde(rename = "objectiveId")]
    pub objective_id: String,
    #[serde(rename = "scenarioId")]
    pub scenario_id: String,
    #[serde(rename = "startState")]
    pub start_state: RouteAttemptStartState,
    #[serde(rename = "strategyId")]
    pub strategy_id: String,
    #[serde(rename = "strategyKind")]
    pub strategy_kind: RouteAttemptStrategyKind,
    #[serde(rename = "actionSequence")]
    pub action_sequence: Vec<RouteAttemptAction>,
    pub route: Vec<RouteAttemptRouteNode>,
    pub outcome: RouteAttemptOutcome,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub blockers: Vec<RouteAttemptBlocker>,
    #[serde(rename = "evidenceRefs")]
    pub evidence_refs: Vec<String>,
    #[serde(rename = "budgetUsed")]
    pub budget_used: RouteAttemptBudgetUsed,
    #[serde(rename = "unsupportedReason", skip_serializing_if = "Option::is_none")]
    pub unsupported_reason: Option<String>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub guardrails: Vec<String>,
}

