impl RuntimeInvariantModel {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let model: RuntimeInvariantModel =
            serde_json::from_str(input).context("failed to parse Runtime Invariant Model JSON")?;
        model.validate()?;
        Ok(model)
    }
    pub fn validate(&self) -> Result<()> {
        if self.schema_version != RUNTIME_INVARIANT_MODEL_SCHEMA_VERSION {
            return Err(anyhow!("runtime invariant model schemaVersion must be {RUNTIME_INVARIANT_MODEL_SCHEMA_VERSION}"));
        }
        validate_path_component("runtime invariant model modelId", &self.model_id)?;
        validate_path_component("runtime invariant model runId", &self.run_id)?;
        if let Some(scenario_id) = &self.scenario_id {
            validate_path_component("runtime invariant model scenarioId", scenario_id)?;
        }
        validate_runtime_invariant_world_state_ref(&self.world_state_path)?;
        if let Some(path) = &self.scenario_result_path {
            validate_scenario_result_ref(path)?;
        }
        validate_runtime_invariant_evidence_index_ref(&self.evidence_index_path)?;
        if self.invariants.is_empty() {
            return Err(anyhow!(
                "runtime invariant model invariants must not be empty"
            ));
        }
        let mut ids = BTreeSet::new();
        for (index, invariant) in self.invariants.iter().enumerate() {
            invariant.validate(index)?;
            if !ids.insert(invariant.invariant_id.as_str()) {
                return Err(anyhow!(
                    "duplicate runtime invariant model invariantId: {}",
                    invariant.invariant_id
                ));
            }
        }
        Ok(())
    }
}

impl RuntimeInvariantSpec {
    fn validate(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("runtime invariant model invariants[{index}].invariantId"),
            &self.invariant_id,
        )?;
        validate_scenario_path(&self.target_path).with_context(|| {
            format!("runtime invariant model invariants[{index}].targetPath is invalid")
        })?;
        validate_runtime_invariant_evidence_ref(&self.evidence_path)?;
        if let Some(entity_id) = &self.required_entity_id {
            validate_path_component(
                &format!("runtime invariant model invariants[{index}].requiredEntityId"),
                entity_id,
            )?;
        }
        if let Some(path) = &self.bounds_path {
            validate_scenario_path(path).with_context(|| {
                format!("runtime invariant model invariants[{index}].boundsPath is invalid")
            })?;
        }
        if let Some(path) = &self.transition_target_path {
            validate_scenario_path(path).with_context(|| {
                format!(
                    "runtime invariant model invariants[{index}].transitionTargetPath is invalid"
                )
            })?;
        }
        if let Some(path) = &self.behavior_state_path {
            validate_scenario_path(path).with_context(|| {
                format!("runtime invariant model invariants[{index}].behaviorStatePath is invalid")
            })?;
        }
        for state in &self.allowed_states {
            validate_path_component(
                &format!("runtime invariant model invariants[{index}].allowedStates"),
                state,
            )?;
        }
        match self.invariant_type {
            RuntimeInvariantType::PlayerInBounds | RuntimeInvariantType::EntityInBounds if self.bounds_path.is_none() => Err(anyhow!("runtime invariant model invariants[{index}] in-bounds invariants require boundsPath")),
            RuntimeInvariantType::SceneTransitionValid if self.transition_target_path.is_none() => Err(anyhow!("runtime invariant model invariants[{index}] scene transition invariants require transitionTargetPath")),
            RuntimeInvariantType::BehaviorStateConsistent if self.behavior_state_path.is_none() || self.allowed_states.is_empty() => Err(anyhow!("runtime invariant model invariants[{index}] behavior state invariants require behaviorStatePath and allowedStates")),
            RuntimeInvariantType::RequiredEntityPresent if self.required_entity_id.is_none() => Err(anyhow!("runtime invariant model invariants[{index}] required entity invariants require requiredEntityId")),
            _ => Ok(()),
        }
    }
}

impl RuntimeInvariantEvidence {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let evidence: RuntimeInvariantEvidence = serde_json::from_str(input)
            .context("failed to parse Runtime Invariant Evidence JSON")?;
        evidence.validate()?;
        Ok(evidence)
    }
    pub fn validate(&self) -> Result<()> {
        if self.schema_version != RUNTIME_INVARIANT_EVIDENCE_SCHEMA_VERSION {
            return Err(anyhow!("runtime invariant evidence schemaVersion must be {RUNTIME_INVARIANT_EVIDENCE_SCHEMA_VERSION}"));
        }
        validate_path_component("runtime invariant evidence modelId", &self.model_id)?;
        validate_path_component("runtime invariant evidence runId", &self.run_id)?;
        if let Some(scenario_id) = &self.scenario_id {
            validate_path_component("runtime invariant evidence scenarioId", scenario_id)?;
        }
        validate_runtime_invariant_world_state_ref(&self.world_state_path)?;
        if let Some(path) = &self.scenario_result_path {
            validate_scenario_result_ref(path)?;
        }
        if self.checks.is_empty() {
            return Err(anyhow!(
                "runtime invariant evidence checks must not be empty"
            ));
        }
        let mut ids = BTreeSet::new();
        for (index, check) in self.checks.iter().enumerate() {
            check.validate(index)?;
            if !ids.insert(check.invariant_id.as_str()) {
                return Err(anyhow!(
                    "duplicate runtime invariant evidence invariantId: {}",
                    check.invariant_id
                ));
            }
        }
        Ok(())
    }
    pub fn summary(&self) -> RuntimeInvariantEvidenceSummary {
        let count = |status: RuntimeInvariantStatus| -> usize {
            self.checks
                .iter()
                .filter(|check| check.status == status)
                .count()
        };
        RuntimeInvariantEvidenceSummary {
            schema_version: "runtime-invariant-evidence-summary-v1".to_string(),
            model_id: self.model_id.clone(),
            run_id: self.run_id.clone(),
            scenario_id: self.scenario_id.clone(),
            check_count: self.checks.len(),
            passed_count: count(RuntimeInvariantStatus::Passed),
            failed_count: count(RuntimeInvariantStatus::Failed),
            unsupported_count: count(RuntimeInvariantStatus::Unsupported),
            missing_count: count(RuntimeInvariantStatus::Missing),
            malformed_count: count(RuntimeInvariantStatus::Malformed),
            stale_count: count(RuntimeInvariantStatus::Stale),
        }
    }
}

impl RuntimeInvariantCheck {
    fn validate(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("runtime invariant evidence checks[{index}].invariantId"),
            &self.invariant_id,
        )?;
        validate_scenario_path(&self.target_path).with_context(|| {
            format!("runtime invariant evidence checks[{index}].targetPath is invalid")
        })?;
        if self.evidence_refs.is_empty() {
            return Err(anyhow!(
                "runtime invariant evidence checks[{index}].evidenceRefs must not be empty"
            ));
        }
        for evidence_ref in &self.evidence_refs {
            validate_runtime_invariant_evidence_ref(evidence_ref)?;
        }
        match self.status {
            RuntimeInvariantStatus::Passed if self.message.is_some() => Err(anyhow!(
                "runtime invariant evidence checks[{index}] passed status must not include message"
            )),
            RuntimeInvariantStatus::Failed
            | RuntimeInvariantStatus::Unsupported
            | RuntimeInvariantStatus::Missing
            | RuntimeInvariantStatus::Malformed
            | RuntimeInvariantStatus::Stale => {
                let Some(message) = &self.message else {
                    return Err(anyhow!(
                        "runtime invariant evidence checks[{index}] {:?} status requires message",
                        self.status
                    ));
                };
                require_bounded_display_text(
                    &format!("runtime invariant evidence checks[{index}].message"),
                    message,
                )?;
                Ok(())
            }
            _ => Ok(()),
        }
    }
}

fn validate_runtime_invariant_world_state_ref(reference: &str) -> Result<()> {
    validate_evidence_artifact_path(reference)?;
    if !reference.starts_with("evidence/scenarios/") || !reference.ends_with("/world-state.json") {
        return Err(anyhow!("runtime invariant worldStatePath must reference evidence/scenarios/<scenario-id>/world-state.json"));
    }
    Ok(())
}
fn validate_runtime_invariant_evidence_index_ref(reference: &str) -> Result<()> {
    validate_evidence_artifact_path(reference)?;
    if reference != "evidence/index.json" {
        return Err(anyhow!(
            "runtime invariant evidenceIndexPath must reference evidence/index.json"
        ));
    }
    Ok(())
}
fn validate_runtime_invariant_evidence_ref(reference: &str) -> Result<()> {
    require_text("runtime invariant evidence ref", reference)?;
    if reference.starts_with("evidence/") {
        return validate_evidence_artifact_path(reference);
    }
    if reference.starts_with("invariants/") {
        // Reject raw backslash separators and repeated path separators before the
        // component check. On Unix `Path::components()` treats a backslash as an
        // ordinary character, so a ref like `invariants/..\secret.json` would
        // otherwise pass as a single normal component yet escape the subtree in a
        // consumer that normalizes `\` to `/`. Fail closed on those raw shapes.
        if reference.contains('\\') {
            return Err(anyhow!(
                "runtime invariant evidence ref must not contain backslash separators"
            ));
        }
        if reference.contains("//") {
            return Err(anyhow!(
                "runtime invariant evidence ref must not contain repeated path separators"
            ));
        }
        let path = Path::new(reference);
        if path.is_absolute()
            || path.components().any(|component| {
                matches!(
                    component,
                    Component::ParentDir | Component::RootDir | Component::Prefix(_)
                )
            })
        {
            return Err(anyhow!(
                "runtime invariant evidence ref must be run-relative and must not escape the run"
            ));
        }
        if !reference.ends_with(".json") {
            return Err(anyhow!(
                "runtime invariant evidence ref under invariants/ must point to a JSON artifact"
            ));
        }
        return Ok(());
    }
    Err(anyhow!(
        "runtime invariant evidence refs must point to evidence/ or invariants/"
    ))
}

pub fn write_runtime_invariant_evidence(
    run_dir: impl AsRef<Path>,
    evidence: &RuntimeInvariantEvidence,
) -> Result<EvidenceArtifact> {
    let run_dir = run_dir.as_ref();
    evidence.validate()?;
    let run = read_json_value(run_dir.join("run.json"))?;
    let current_run_id = json_string(&run, "id").unwrap_or_else(|| run_id_from_run_dir(run_dir));
    if evidence.run_id != current_run_id {
        return Err(anyhow!(
            "runtime invariant evidence runId {} is stale for current run {current_run_id}",
            evidence.run_id
        ));
    }
    let scenario_dir = evidence
        .scenario_id
        .as_deref()
        .map(|scenario_id| format!("scenarios/{scenario_id}"))
        .unwrap_or_else(|| "run".to_string());
    let artifact_path = format!(
        "evidence/{scenario_dir}/runtime-invariant-evidence-{}.json",
        evidence.model_id
    );
    if let Some(parent) = run_dir.join(&artifact_path).parent() {
        fs::create_dir_all(parent)?;
    }
    write_json(&run_dir.join(&artifact_path), &json!(evidence))?;
    let summary = evidence.summary();
    add_evidence_artifact(
        run_dir,
        &format!("runtime-invariant-evidence-{}", evidence.model_id),
        "application/json",
        &artifact_path,
        json!({
            "artifact": "runtime_invariant_evidence",
            "schemaVersion": evidence.schema_version,
            "modelId": evidence.model_id,
            "runId": evidence.run_id,
            "scenarioId": evidence.scenario_id,
            "checkCount": summary.check_count,
            "passedCount": summary.passed_count,
            "failedCount": summary.failed_count,
            "unsupportedCount": summary.unsupported_count,
            "missingCount": summary.missing_count,
            "malformedCount": summary.malformed_count,
            "staleCount": summary.stale_count,
            "boundary": "runtime invariant evidence is Rust-written validation evidence only; it does not mutate source, launch workers, execute browser commands, auto-fix, auto-apply, or auto-merge"
        }),
    )
}

pub fn evaluate_runtime_invariants(
    model: &RuntimeInvariantModel,
    world_state: &serde_json::Value,
    scenario_result: Option<&serde_json::Value>,
    recorded_at_unix_ms: u128,
) -> Result<RuntimeInvariantEvidence> {
    model.validate()?;
    let mut checks = Vec::new();
    for invariant in &model.invariants {
        checks.push(evaluate_runtime_invariant(
            model,
            invariant,
            world_state,
            scenario_result,
        ));
    }
    let evidence = RuntimeInvariantEvidence {
        schema_version: RUNTIME_INVARIANT_EVIDENCE_SCHEMA_VERSION.to_string(),
        model_id: model.model_id.clone(),
        run_id: model.run_id.clone(),
        scenario_id: model.scenario_id.clone(),
        world_state_path: model.world_state_path.clone(),
        scenario_result_path: model.scenario_result_path.clone(),
        recorded_at_unix_ms,
        checks,
    };
    evidence.validate()?;
    Ok(evidence)
}

fn evaluate_runtime_invariant(
    model: &RuntimeInvariantModel,
    invariant: &RuntimeInvariantSpec,
    world_state: &serde_json::Value,
    scenario_result: Option<&serde_json::Value>,
) -> RuntimeInvariantCheck {
    let Some(source) = runtime_invariant_source(model, invariant, world_state, scenario_result)
    else {
        return runtime_invariant_check(
            invariant,
            RuntimeInvariantStatus::Unsupported,
            None,
            Some("invariant evidencePath is not a supported world-state or scenario-result source"),
        );
    };

    let target = runtime_invariant_path_value(source, &invariant.target_path);
    if target.is_none() {
        return runtime_invariant_check(
            invariant,
            RuntimeInvariantStatus::Missing,
            None,
            Some("targetPath was not present in referenced runtime evidence"),
        );
    }
    let target = target.unwrap_or(&serde_json::Value::Null);
    let (status, observed, message) = match invariant.invariant_type {
        RuntimeInvariantType::PlayerInBounds | RuntimeInvariantType::EntityInBounds => {
            evaluate_in_bounds(source, target, invariant.bounds_path.as_deref())
        }
        RuntimeInvariantType::FiniteTransform => evaluate_finite_transform(target),
        RuntimeInvariantType::HealthNonNegative => evaluate_health_non_negative(target),
        RuntimeInvariantType::ObjectiveFlagsConsistent => {
            evaluate_objective_flags_consistent(target)
        }
        RuntimeInvariantType::SceneTransitionValid => evaluate_scene_transition_valid(
            source,
            target,
            invariant.transition_target_path.as_deref(),
        ),
        RuntimeInvariantType::NoImpossibleState => evaluate_no_impossible_state(target),
        RuntimeInvariantType::RequiredEntityPresent => {
            evaluate_required_entity_present(target, invariant.required_entity_id.as_deref())
        }
        RuntimeInvariantType::BehaviorStateConsistent => evaluate_behavior_state_consistent(
            source,
            invariant.behavior_state_path.as_deref(),
            &invariant.allowed_states,
        ),
    };
    runtime_invariant_check(invariant, status, observed, message.as_deref())
}

fn runtime_invariant_source<'a>(
    model: &RuntimeInvariantModel,
    invariant: &RuntimeInvariantSpec,
    world_state: &'a serde_json::Value,
    scenario_result: Option<&'a serde_json::Value>,
) -> Option<&'a serde_json::Value> {
    if invariant.evidence_path == model.world_state_path {
        return Some(world_state);
    }
    if invariant.evidence_path == model.scenario_result_path.as_deref().unwrap_or_default() {
        return scenario_result;
    }
    None
}

fn runtime_invariant_check(
    invariant: &RuntimeInvariantSpec,
    status: RuntimeInvariantStatus,
    observed: Option<serde_json::Value>,
    message: Option<&str>,
) -> RuntimeInvariantCheck {
    RuntimeInvariantCheck {
        invariant_id: invariant.invariant_id.clone(),
        invariant_type: invariant.invariant_type,
        status,
        target_path: invariant.target_path.clone(),
        evidence_refs: vec![invariant.evidence_path.clone()],
        observed,
        message: message.map(ToString::to_string),
    }
}

fn runtime_invariant_path_value<'a>(
    source: &'a serde_json::Value,
    path: &str,
) -> Option<&'a serde_json::Value> {
    let mut current = source;
    for segment in path.split('.') {
        current = match current {
            serde_json::Value::Object(map) => map.get(segment)?,
            serde_json::Value::Array(items) => {
                let index = segment.parse::<usize>().ok()?;
                items.get(index)?
            }
            _ => return None,
        };
    }
    Some(current)
}

fn evaluate_in_bounds(
    source: &serde_json::Value,
    target: &serde_json::Value,
    bounds_path: Option<&str>,
) -> (
    RuntimeInvariantStatus,
    Option<serde_json::Value>,
    Option<String>,
) {
    let Some(bounds_path) = bounds_path else {
        return (
            RuntimeInvariantStatus::Unsupported,
            Some(target.clone()),
            Some("in-bounds invariant is missing boundsPath".to_string()),
        );
    };
    let Some(bounds) = runtime_invariant_path_value(source, bounds_path) else {
        return (
            RuntimeInvariantStatus::Missing,
            Some(target.clone()),
            Some("boundsPath was not present in referenced runtime evidence".to_string()),
        );
    };
    let Some((x, y)) = runtime_invariant_xy(target) else {
        return (
            RuntimeInvariantStatus::Malformed,
            Some(target.clone()),
            Some("targetPath did not contain finite numeric x/y values".to_string()),
        );
    };
    let Some((min_x, max_x, min_y, max_y)) = runtime_invariant_bounds(bounds) else {
        return (
            RuntimeInvariantStatus::Malformed,
            Some(bounds.clone()),
            Some(
                "boundsPath did not contain finite min/max or x/y/width/height bounds".to_string(),
            ),
        );
    };
    if x >= min_x && x <= max_x && y >= min_y && y <= max_y {
        (
            RuntimeInvariantStatus::Passed,
            Some(json!({ "x": x, "y": y })),
            None,
        )
    } else {
        (
            RuntimeInvariantStatus::Failed,
            Some(
                json!({ "x": x, "y": y, "bounds": { "minX": min_x, "maxX": max_x, "minY": min_y, "maxY": max_y } }),
            ),
            Some("entity transform was outside configured bounds".to_string()),
        )
    }
}

fn evaluate_finite_transform(
    target: &serde_json::Value,
) -> (
    RuntimeInvariantStatus,
    Option<serde_json::Value>,
    Option<String>,
) {
    let Some(object) = target.as_object() else {
        return (
            RuntimeInvariantStatus::Malformed,
            Some(target.clone()),
            Some("transform target must be an object".to_string()),
        );
    };
    let numeric_keys = ["x", "y", "z", "rotation", "scale", "scaleX", "scaleY"];
    let mut found = false;
    for key in numeric_keys {
        if let Some(value) = object.get(key) {
            found = true;
            if runtime_invariant_f64(value).is_none() {
                return (
                    RuntimeInvariantStatus::Malformed,
                    Some(target.clone()),
                    Some(format!("transform field {key} was not a finite number")),
                );
            }
        }
    }
    if found {
        (RuntimeInvariantStatus::Passed, Some(target.clone()), None)
    } else {
        (
            RuntimeInvariantStatus::Missing,
            Some(target.clone()),
            Some("transform target had no recognized numeric fields".to_string()),
        )
    }
}

fn evaluate_health_non_negative(
    target: &serde_json::Value,
) -> (
    RuntimeInvariantStatus,
    Option<serde_json::Value>,
    Option<String>,
) {
    let Some(value) = runtime_invariant_f64(target) else {
        return (
            RuntimeInvariantStatus::Malformed,
            Some(target.clone()),
            Some("health target was not numeric".to_string()),
        );
    };
    if value >= 0.0 {
        (RuntimeInvariantStatus::Passed, Some(json!(value)), None)
    } else {
        (
            RuntimeInvariantStatus::Failed,
            Some(json!(value)),
            Some("health target was below zero".to_string()),
        )
    }
}

fn evaluate_objective_flags_consistent(
    target: &serde_json::Value,
) -> (
    RuntimeInvariantStatus,
    Option<serde_json::Value>,
    Option<String>,
) {
    match target {
        serde_json::Value::Bool(_) => (RuntimeInvariantStatus::Passed, Some(target.clone()), None),
        serde_json::Value::Object(map) => {
            let contradiction = map.get("completed").and_then(|v| v.as_bool()) == Some(true)
                && map.get("failed").and_then(|v| v.as_bool()) == Some(true);
            if contradiction {
                (
                    RuntimeInvariantStatus::Failed,
                    Some(target.clone()),
                    Some("objective flags were both completed and failed".to_string()),
                )
            } else {
                (RuntimeInvariantStatus::Passed, Some(target.clone()), None)
            }
        }
        _ => (
            RuntimeInvariantStatus::Malformed,
            Some(target.clone()),
            Some("objective flag target must be boolean or object".to_string()),
        ),
    }
}

fn evaluate_scene_transition_valid(
    source: &serde_json::Value,
    target: &serde_json::Value,
    transition_target_path: Option<&str>,
) -> (
    RuntimeInvariantStatus,
    Option<serde_json::Value>,
    Option<String>,
) {
    let Some(path) = transition_target_path else {
        return (
            RuntimeInvariantStatus::Unsupported,
            Some(target.clone()),
            Some("scene transition invariant is missing transitionTargetPath".to_string()),
        );
    };
    let Some(transition_target) = runtime_invariant_path_value(source, path) else {
        return (
            RuntimeInvariantStatus::Missing,
            Some(target.clone()),
            Some("transitionTargetPath was not present in referenced runtime evidence".to_string()),
        );
    };
    let current = target.as_str();
    let valid = match transition_target {
        serde_json::Value::String(next) => current.is_some_and(|current| current == next),
        serde_json::Value::Array(items) => {
            current.is_some_and(|current| items.iter().any(|item| item.as_str() == Some(current)))
        }
        serde_json::Value::Object(map) => current.is_some_and(|current| map.contains_key(current)),
        _ => false,
    };
    if valid {
        (
            RuntimeInvariantStatus::Passed,
            Some(json!({ "current": target, "declared": transition_target })),
            None,
        )
    } else {
        (
            RuntimeInvariantStatus::Failed,
            Some(json!({ "current": target, "declared": transition_target })),
            Some("scene transition target was not declared".to_string()),
        )
    }
}

fn evaluate_no_impossible_state(
    target: &serde_json::Value,
) -> (
    RuntimeInvariantStatus,
    Option<serde_json::Value>,
    Option<String>,
) {
    match target.as_bool() {
        Some(false) => (RuntimeInvariantStatus::Passed, Some(target.clone()), None),
        Some(true) => (
            RuntimeInvariantStatus::Failed,
            Some(target.clone()),
            Some("impossible-state marker was true".to_string()),
        ),
        None => (
            RuntimeInvariantStatus::Malformed,
            Some(target.clone()),
            Some("impossible-state marker must be boolean".to_string()),
        ),
    }
}

fn evaluate_required_entity_present(
    target: &serde_json::Value,
    required_entity_id: Option<&str>,
) -> (
    RuntimeInvariantStatus,
    Option<serde_json::Value>,
    Option<String>,
) {
    let Some(required) = required_entity_id else {
        return (
            RuntimeInvariantStatus::Unsupported,
            Some(target.clone()),
            Some("required entity invariant is missing requiredEntityId".to_string()),
        );
    };
    let present = match target {
        serde_json::Value::Object(map) => {
            map.contains_key(required) || map.get("id").and_then(|v| v.as_str()) == Some(required)
        }
        serde_json::Value::Array(items) => items.iter().any(|item| {
            item.as_str() == Some(required)
                || item.get("id").and_then(|v| v.as_str()) == Some(required)
        }),
        serde_json::Value::String(value) => value == required,
        _ => false,
    };
    if present {
        (RuntimeInvariantStatus::Passed, Some(target.clone()), None)
    } else {
        (
            RuntimeInvariantStatus::Failed,
            Some(target.clone()),
            Some(format!("required entity {required} was not present")),
        )
    }
}

fn evaluate_behavior_state_consistent(
    source: &serde_json::Value,
    behavior_state_path: Option<&str>,
    allowed_states: &[String],
) -> (
    RuntimeInvariantStatus,
    Option<serde_json::Value>,
    Option<String>,
) {
    let Some(path) = behavior_state_path else {
        return (
            RuntimeInvariantStatus::Unsupported,
            None,
            Some("behavior invariant is missing behaviorStatePath".to_string()),
        );
    };
    if allowed_states.is_empty() {
        return (
            RuntimeInvariantStatus::Unsupported,
            None,
            Some("behavior invariant has no allowedStates".to_string()),
        );
    }
    let Some(state) = runtime_invariant_path_value(source, path) else {
        return (
            RuntimeInvariantStatus::Missing,
            None,
            Some("behaviorStatePath was not present in referenced runtime evidence".to_string()),
        );
    };
    let Some(state) = state.as_str() else {
        return (
            RuntimeInvariantStatus::Malformed,
            Some(state.clone()),
            Some("behavior state was not a string".to_string()),
        );
    };
    if allowed_states.iter().any(|allowed| allowed == state) {
        (RuntimeInvariantStatus::Passed, Some(json!(state)), None)
    } else {
        (
            RuntimeInvariantStatus::Failed,
            Some(json!(state)),
            Some("behavior state was outside allowedStates".to_string()),
        )
    }
}

fn runtime_invariant_xy(value: &serde_json::Value) -> Option<(f64, f64)> {
    let object = value.as_object()?;
    Some((
        runtime_invariant_f64(object.get("x")?)?,
        runtime_invariant_f64(object.get("y")?)?,
    ))
}

fn runtime_invariant_bounds(value: &serde_json::Value) -> Option<(f64, f64, f64, f64)> {
    let object = value.as_object()?;
    if let (Some(min_x), Some(max_x), Some(min_y), Some(max_y)) = (
        object.get("minX").and_then(runtime_invariant_f64),
        object.get("maxX").and_then(runtime_invariant_f64),
        object.get("minY").and_then(runtime_invariant_f64),
        object.get("maxY").and_then(runtime_invariant_f64),
    ) {
        return Some((min_x, max_x, min_y, max_y));
    }
    let x = object.get("x").and_then(runtime_invariant_f64)?;
    let y = object.get("y").and_then(runtime_invariant_f64)?;
    let width = object.get("width").and_then(runtime_invariant_f64)?;
    let height = object.get("height").and_then(runtime_invariant_f64)?;
    Some((x, x + width, y, y + height))
}

fn runtime_invariant_f64(value: &serde_json::Value) -> Option<f64> {
    let number = value.as_f64()?;
    number.is_finite().then_some(number)
}

const RUNTIME_ASSET_LOAD_EVIDENCE_SCHEMA_VERSION: &str = "runtime-asset-load-evidence-v1";

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct RuntimeAssetLoadEvidence {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    #[serde(rename = "runId")]
    pub run_id: String,
    #[serde(rename = "workerId")]
    pub worker_id: String,
    #[serde(rename = "workerSessionId")]
    pub worker_session_id: String,
    #[serde(rename = "scenarioId", skip_serializing_if = "Option::is_none")]
    pub scenario_id: Option<String>,
    #[serde(rename = "manifestId", skip_serializing_if = "Option::is_none")]
    pub manifest_id: Option<String>,
    #[serde(rename = "recordedAtUnixMs")]
    pub recorded_at_unix_ms: u128,
    pub loads: Vec<RuntimeAssetLoadRecord>,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct RuntimeAssetLoadRecord {
    #[serde(rename = "attemptId")]
    pub attempt_id: String,
    #[serde(rename = "assetId")]
    pub asset_id: String,
    #[serde(rename = "assetType")]
    pub asset_type: ProjectAssetType,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub path: Option<String>,
    pub status: RuntimeAssetLoadStatus,
    #[serde(rename = "startedAtUnixMs")]
    pub started_at_unix_ms: u128,
    #[serde(rename = "endedAtUnixMs", skip_serializing_if = "Option::is_none")]
    pub ended_at_unix_ms: Option<u128>,
    #[serde(rename = "loadDurationMs", skip_serializing_if = "Option::is_none")]
    pub load_duration_ms: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub width: Option<u32>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub height: Option<u32>,
    #[serde(rename = "mediaDurationMs", skip_serializing_if = "Option::is_none")]
    pub media_duration_ms: Option<u64>,
    #[serde(rename = "failureReason", skip_serializing_if = "Option::is_none")]
    pub failure_reason: Option<String>,
}

#[derive(Debug, Clone, Copy, Deserialize, Serialize, PartialEq, Eq, PartialOrd, Ord)]
#[serde(rename_all = "snake_case")]
pub enum RuntimeAssetLoadStatus {
    Attempted,
    Loaded,
    Failed,
    Rejected,
    Fallback,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct RuntimeAssetLoadEvidenceSummary {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    #[serde(rename = "runId")]
    pub run_id: String,
    #[serde(rename = "workerId")]
    pub worker_id: String,
    #[serde(rename = "workerSessionId")]
    pub worker_session_id: String,
    #[serde(rename = "scenarioId", skip_serializing_if = "Option::is_none")]
    pub scenario_id: Option<String>,
    #[serde(rename = "manifestId", skip_serializing_if = "Option::is_none")]
    pub manifest_id: Option<String>,
    #[serde(rename = "attemptCount")]
    pub attempt_count: usize,
    #[serde(rename = "loadedAssetIds")]
    pub loaded_asset_ids: Vec<String>,
    #[serde(rename = "failedAssetIds")]
    pub failed_asset_ids: Vec<String>,
    #[serde(rename = "rejectedAssetIds")]
    pub rejected_asset_ids: Vec<String>,
    #[serde(rename = "fallbackAssetIds")]
    pub fallback_asset_ids: Vec<String>,
}

impl RuntimeAssetLoadEvidence {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let evidence: RuntimeAssetLoadEvidence = serde_json::from_str(input)
            .context("failed to parse Runtime Asset Load Evidence JSON")?;
        evidence.validate()?;
        Ok(evidence)
    }

    pub fn validate(&self) -> Result<()> {
        if self.schema_version != RUNTIME_ASSET_LOAD_EVIDENCE_SCHEMA_VERSION {
            return Err(anyhow!(
                "runtime asset load evidence schemaVersion must be {RUNTIME_ASSET_LOAD_EVIDENCE_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("runtime asset load evidence runId", &self.run_id)?;
        validate_path_component("runtime asset load evidence workerId", &self.worker_id)?;
        require_text(
            "runtime asset load evidence workerSessionId",
            &self.worker_session_id,
        )?;
        // The session id correlates a record to its run and worker: it must be
        // exactly "{runId}:{workerId}" so a blob from another worker session
        // cannot be summarized under a different run or worker.
        let expected_session = format!("{}:{}", self.run_id, self.worker_id);
        if self.worker_session_id != expected_session {
            return Err(anyhow!(
                "runtime asset load evidence workerSessionId must equal \"{{runId}}:{{workerId}}\" ({expected_session}), got {}",
                self.worker_session_id
            ));
        }
        if let Some(scenario_id) = &self.scenario_id {
            validate_path_component("runtime asset load evidence scenarioId", scenario_id)?;
        }
        if let Some(manifest_id) = &self.manifest_id {
            validate_path_component("runtime asset load evidence manifestId", manifest_id)?;
        }
        if self.loads.is_empty() {
            return Err(anyhow!(
                "runtime asset load evidence loads must not be empty"
            ));
        }
        let mut attempt_ids = BTreeSet::new();
        for (index, load) in self.loads.iter().enumerate() {
            load.validate(index)?;
            if !attempt_ids.insert(load.attempt_id.as_str()) {
                return Err(anyhow!(
                    "duplicate runtime asset load evidence attemptId: {}",
                    load.attempt_id
                ));
            }
        }
        Ok(())
    }

    pub fn summary(&self) -> RuntimeAssetLoadEvidenceSummary {
        let ids_with_status = |status: RuntimeAssetLoadStatus| -> Vec<String> {
            let mut ids = self
                .loads
                .iter()
                .filter(|load| load.status == status)
                .map(|load| load.asset_id.clone())
                .collect::<Vec<_>>();
            ids.sort();
            ids.dedup();
            ids
        };
        RuntimeAssetLoadEvidenceSummary {
            schema_version: self.schema_version.clone(),
            run_id: self.run_id.clone(),
            worker_id: self.worker_id.clone(),
            worker_session_id: self.worker_session_id.clone(),
            scenario_id: self.scenario_id.clone(),
            manifest_id: self.manifest_id.clone(),
            attempt_count: self.loads.len(),
            loaded_asset_ids: ids_with_status(RuntimeAssetLoadStatus::Loaded),
            failed_asset_ids: ids_with_status(RuntimeAssetLoadStatus::Failed),
            rejected_asset_ids: ids_with_status(RuntimeAssetLoadStatus::Rejected),
            fallback_asset_ids: ids_with_status(RuntimeAssetLoadStatus::Fallback),
        }
    }
}

impl RuntimeAssetLoadRecord {
    fn validate(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("runtime asset load evidence loads[{index}].attemptId"),
            &self.attempt_id,
        )?;
        validate_path_component(
            &format!("runtime asset load evidence loads[{index}].assetId"),
            &self.asset_id,
        )?;
        if let Some(path) = &self.path {
            validate_project_asset_path(
                &format!("runtime asset load evidence loads[{index}].path"),
                path,
                self.asset_type,
                ProjectAssetClassification::SourceLike,
            )?;
        }
        if let Some(ended_at) = self.ended_at_unix_ms {
            if ended_at < self.started_at_unix_ms {
                return Err(anyhow!(
                    "runtime asset load evidence loads[{index}].endedAtUnixMs must be greater than or equal to startedAtUnixMs"
                ));
            }
        }
        if self.load_duration_ms == Some(0) {
            return Err(anyhow!(
                "runtime asset load evidence loads[{index}].loadDurationMs must be positive when present"
            ));
        }
        if self.media_duration_ms == Some(0) {
            return Err(anyhow!(
                "runtime asset load evidence loads[{index}].mediaDurationMs must be positive when present"
            ));
        }
        if self.width == Some(0) || self.height == Some(0) {
            return Err(anyhow!(
                "runtime asset load evidence loads[{index}] dimensions must be positive when present"
            ));
        }
        match self.status {
            RuntimeAssetLoadStatus::Loaded => {
                if self.failure_reason.is_some() {
                    return Err(anyhow!(
                        "runtime asset load evidence loads[{index}] loaded status must not include failureReason"
                    ));
                }
                if self.ended_at_unix_ms.is_none() {
                    return Err(anyhow!(
                        "runtime asset load evidence loads[{index}] loaded status requires endedAtUnixMs"
                    ));
                }
            }
            RuntimeAssetLoadStatus::Failed
            | RuntimeAssetLoadStatus::Rejected
            | RuntimeAssetLoadStatus::Fallback => {
                let Some(reason) = &self.failure_reason else {
                    return Err(anyhow!(
                        "runtime asset load evidence loads[{index}] {:?} status requires failureReason",
                        self.status
                    ));
                };
                require_bounded_display_text(
                    &format!("runtime asset load evidence loads[{index}].failureReason"),
                    reason,
                )?;
            }
            RuntimeAssetLoadStatus::Attempted => {}
        }
        Ok(())
    }
}

impl ProjectAssetManifest {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let manifest: ProjectAssetManifest =
            serde_json::from_str(input).context("failed to parse Project Asset Manifest JSON")?;
        manifest.validate_schema()?;
        Ok(manifest)
    }

    pub fn from_path(path: impl AsRef<Path>) -> Result<Self> {
        let path = path.as_ref();
        let input = fs::read_to_string(path)
            .with_context(|| format!("failed to read project asset manifest {}", path.display()))?;
        let manifest = Self::from_json_str(&input).with_context(|| {
            format!("failed to parse project asset manifest {}", path.display())
        })?;
        let base_dir = match path.parent() {
            Some(parent) if !parent.as_os_str().is_empty() => parent,
            _ => Path::new("."),
        };
        manifest.validate_assets(base_dir).with_context(|| {
            format!(
                "project asset manifest {} references invalid assets",
                path.display()
            )
        })?;
        Ok(manifest)
    }

    pub fn validate_schema(&self) -> Result<()> {
        if self.schema_version != PROJECT_ASSET_MANIFEST_SCHEMA_VERSION {
            return Err(anyhow!(
                "project asset manifest schemaVersion must be {PROJECT_ASSET_MANIFEST_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("project asset manifest id", &self.id)?;
        if self.assets.is_empty() {
            return Err(anyhow!("project asset manifest assets must not be empty"));
        }
        if let Some(notes) = &self.notes {
            require_text("project asset manifest notes", notes)?;
        }
        for (index, asset) in self.assets.iter().enumerate() {
            asset.validate_schema(index)?;
        }
        Ok(())
    }

    pub fn validate_assets(&self, base_dir: &Path) -> Result<ProjectAssetManifestValidationReport> {
        self.validate_schema()?;
        let base = base_dir.canonicalize().with_context(|| {
            format!(
                "failed to resolve project asset manifest base {}",
                base_dir.display()
            )
        })?;
        let mut ids = BTreeSet::new();
        let mut paths = BTreeSet::new();
        let mut asset_types = BTreeMap::new();
        let mut source_like_assets = 0;
        let mut generated_assets = 0;
        let mut sprite_atlases = 0;
        let mut sprite_atlas_frames = 0;
        let mut sprite_atlas_animations = 0;

        for (index, asset) in self.assets.iter().enumerate() {
            asset.validate_integrity(index, base_dir, &base)?;
            if !ids.insert(asset.id.clone()) {
                return Err(anyhow!(
                    "duplicate project asset manifest asset id: {}",
                    asset.id
                ));
            }
            if !paths.insert(asset.path.clone()) {
                return Err(anyhow!(
                    "duplicate project asset manifest asset path: {}",
                    asset.path
                ));
            }
            *asset_types.entry(asset.asset_type).or_insert(0) += 1;
            match asset.classification {
                ProjectAssetClassification::SourceLike => source_like_assets += 1,
                ProjectAssetClassification::Generated => generated_assets += 1,
            }
            if asset.asset_type == ProjectAssetType::SpriteAtlas {
                sprite_atlases += 1;
                if let Some(atlas) = &asset.atlas {
                    sprite_atlas_frames += atlas.frames.len();
                    sprite_atlas_animations += atlas.animations.len();
                }
            }
        }

        self.validate_sprite_atlases()?;
        self.validate_tilemaps()?;

        Ok(ProjectAssetManifestValidationReport {
            manifest_id: self.id.clone(),
            assets: self.assets.len(),
            source_like_assets,
            generated_assets,
            sprite_atlases,
            sprite_atlas_frames,
            sprite_atlas_animations,
            asset_types,
        })
    }

    fn validate_sprite_atlases(&self) -> Result<()> {
        let assets_by_id: BTreeMap<&str, &ProjectAssetManifestEntry> = self
            .assets
            .iter()
            .map(|asset| (asset.id.as_str(), asset))
            .collect();

        for atlas_asset in self
            .assets
            .iter()
            .filter(|asset| asset.asset_type == ProjectAssetType::SpriteAtlas)
        {
            let Some(atlas) = &atlas_asset.atlas else {
                continue;
            };
            let image_asset = assets_by_id
                .get(atlas.image_asset_id.as_str())
                .ok_or_else(|| {
                    anyhow!(
                        "sprite atlas {} imageAssetId references unknown asset {}",
                        atlas_asset.id,
                        atlas.image_asset_id
                    )
                })?;
            if image_asset.asset_type != ProjectAssetType::Image {
                return Err(anyhow!(
                    "sprite atlas {} imageAssetId {} must reference an image asset",
                    atlas_asset.id,
                    atlas.image_asset_id
                ));
            }
            let dimensions = image_asset.dimensions.as_ref().ok_or_else(|| {
                anyhow!(
                    "sprite atlas {} imageAssetId {} must reference an image asset with dimensions",
                    atlas_asset.id,
                    atlas.image_asset_id
                )
            })?;
            atlas.validate_integrity(&atlas_asset.id, dimensions)?;
        }
        Ok(())
    }

    fn validate_tilemaps(&self) -> Result<()> {
        let assets_by_id: BTreeMap<&str, &ProjectAssetManifestEntry> = self
            .assets
            .iter()
            .map(|asset| (asset.id.as_str(), asset))
            .collect();
        for tileset_asset in self
            .assets
            .iter()
            .filter(|asset| asset.asset_type == ProjectAssetType::Tileset)
        {
            if let Some(tileset) = &tileset_asset.tileset {
                tileset.validate_integrity(&tileset_asset.id)?;
            }
        }
        for tilemap_asset in self
            .assets
            .iter()
            .filter(|asset| asset.asset_type == ProjectAssetType::Tilemap)
        {
            let Some(tilemap) = &tilemap_asset.tilemap else {
                continue;
            };
            let tileset_asset = assets_by_id
                .get(tilemap.tileset_asset_id.as_str())
                .ok_or_else(|| {
                    anyhow!(
                        "tilemap {} tilesetAssetId references unknown asset {}",
                        tilemap_asset.id,
                        tilemap.tileset_asset_id
                    )
                })?;
            if tileset_asset.asset_type != ProjectAssetType::Tileset {
                return Err(anyhow!(
                    "tilemap {} tilesetAssetId {} must reference a tileset asset",
                    tilemap_asset.id,
                    tilemap.tileset_asset_id
                ));
            }
            let tileset = tileset_asset.tileset.as_ref().ok_or_else(|| {
                anyhow!(
                    "tilemap {} tilesetAssetId {} must reference a tileset payload",
                    tilemap_asset.id,
                    tilemap.tileset_asset_id
                )
            })?;
            tilemap.validate_integrity(&tilemap_asset.id, tileset)?;
        }
        Ok(())
    }

    pub fn extract_tilemap_authoring(&self) -> Result<ProjectTilemapAuthoringExtractionReport> {
        self.validate_schema()?;
        self.validate_tilemaps()?;
        let tilesets_by_id: BTreeMap<&str, &ProjectAssetManifestEntry> = self
            .assets
            .iter()
            .filter(|asset| asset.asset_type == ProjectAssetType::Tileset)
            .map(|asset| (asset.id.as_str(), asset))
            .collect();
        let mut tilemaps = Vec::new();
        for tilemap_asset in self
            .assets
            .iter()
            .filter(|asset| asset.asset_type == ProjectAssetType::Tilemap)
        {
            let Some(tilemap) = &tilemap_asset.tilemap else {
                continue;
            };
            let tileset_asset = tilesets_by_id
                .get(tilemap.tileset_asset_id.as_str())
                .expect("validated tileset exists");
            let tileset = tileset_asset
                .tileset
                .as_ref()
                .expect("validated tileset payload");
            tilemaps.push(tilemap.extract(&tilemap_asset.id, tileset));
        }
        Ok(ProjectTilemapAuthoringExtractionReport { tilemaps })
    }

    pub fn validate_scene_references(
        &self,
        scene: &SceneDocument,
    ) -> Result<ProjectAssetReferenceValidationReport> {
        self.validate_schema()?;
        let assets_by_id = self
            .assets
            .iter()
            .map(|asset| (asset.id.as_str(), asset))
            .collect::<BTreeMap<_, _>>();
        let mut resolved_refs = Vec::new();
        for reference in collect_project_scene_asset_refs(scene) {
            validate_path_component(&reference.field, &reference.asset_id)?;
            let asset = assets_by_id
                .get(reference.asset_id.as_str())
                .ok_or_else(|| {
                    anyhow!(
                        "{} references unknown project asset id: {}",
                        reference.field,
                        reference.asset_id
                    )
                })?;
            if !reference.expected_types.contains(&asset.asset_type) {
                return Err(anyhow!(
                    "{} references project asset {} of type {:?}, expected one of {:?}",
                    reference.field,
                    reference.asset_id,
                    asset.asset_type,
                    reference.expected_types
                ));
            }
            resolved_refs.push(ProjectAssetResolvedReference {
                field: reference.field,
                asset_id: asset.id.clone(),
                asset_type: asset.asset_type,
                path: asset.path.clone(),
            });
        }
        resolved_refs.sort_by(|left, right| {
            (left.field.as_str(), left.asset_id.as_str())
                .cmp(&(right.field.as_str(), right.asset_id.as_str()))
        });
        Ok(ProjectAssetReferenceValidationReport {
            manifest_id: self.id.clone(),
            scene_id: scene.id.clone(),
            resolved_refs,
        })
    }

    pub fn check_scene_reference_integrity(
        &self,
        scene: &SceneDocument,
        base_dir: &Path,
    ) -> Result<ProjectAssetReferenceIntegrityReport> {
        self.validate_schema()?;
        let base = base_dir.canonicalize().with_context(|| {
            format!(
                "failed to resolve project asset manifest base {}",
                base_dir.display()
            )
        })?;
        let assets_by_id = self
            .assets
            .iter()
            .map(|asset| (asset.id.as_str(), asset))
            .collect::<BTreeMap<_, _>>();
        let mut resolved_refs = Vec::new();
        let mut warnings = Vec::new();

        for reference in collect_project_scene_asset_refs(scene) {
            if let Err(error) = validate_path_component(&reference.field, &reference.asset_id) {
                warnings.push(ProjectAssetReferenceIntegrityWarning {
                    field: reference.field,
                    asset_id: reference.asset_id,
                    kind: "invalid_asset_id".to_string(),
                    message: error.to_string(),
                    expected_types: reference.expected_types.to_vec(),
                    observed_type: None,
                    path: None,
                });
                continue;
            }
            let Some(asset) = assets_by_id.get(reference.asset_id.as_str()) else {
                warnings.push(ProjectAssetReferenceIntegrityWarning {
                    field: reference.field.clone(),
                    asset_id: reference.asset_id.clone(),
                    kind: "missing_asset_ref".to_string(),
                    message: format!(
                        "{} references unknown project asset id: {}",
                        reference.field, reference.asset_id
                    ),
                    expected_types: reference.expected_types.to_vec(),
                    observed_type: None,
                    path: None,
                });
                continue;
            };
            if !reference.expected_types.contains(&asset.asset_type) {
                warnings.push(ProjectAssetReferenceIntegrityWarning {
                    field: reference.field.clone(),
                    asset_id: reference.asset_id.clone(),
                    kind: "invalid_asset_type".to_string(),
                    message: format!(
                        "{} references project asset {} of type {:?}, expected one of {:?}",
                        reference.field,
                        reference.asset_id,
                        asset.asset_type,
                        reference.expected_types
                    ),
                    expected_types: reference.expected_types.to_vec(),
                    observed_type: Some(asset.asset_type),
                    path: Some(asset.path.clone()),
                });
                continue;
            }
            match project_asset_entry_file_integrity_warning(
                asset,
                base_dir,
                &base,
                &reference.field,
            ) {
                Some(warning) => warnings.push(warning),
                None => resolved_refs.push(ProjectAssetResolvedReference {
                    field: reference.field,
                    asset_id: asset.id.clone(),
                    asset_type: asset.asset_type,
                    path: asset.path.clone(),
                }),
            }
        }

        resolved_refs.sort_by(|left, right| {
            (left.field.as_str(), left.asset_id.as_str())
                .cmp(&(right.field.as_str(), right.asset_id.as_str()))
        });
        warnings.sort_by(|left, right| {
            (
                left.kind.as_str(),
                left.field.as_str(),
                left.asset_id.as_str(),
            )
                .cmp(&(
                    right.kind.as_str(),
                    right.field.as_str(),
                    right.asset_id.as_str(),
                ))
        });
        Ok(ProjectAssetReferenceIntegrityReport {
            schema_version: "asset-reference-integrity-v1".to_string(),
            manifest_id: self.id.clone(),
            scene_id: scene.id.clone(),
            resolved_refs,
            warnings,
        })
    }
}

fn project_asset_entry_file_integrity_warning(
    asset: &ProjectAssetManifestEntry,
    base_dir: &Path,
    base: &Path,
    field: &str,
) -> Option<ProjectAssetReferenceIntegrityWarning> {
    let path = base_dir.join(&asset.path);
    if !path.is_file() {
        return Some(ProjectAssetReferenceIntegrityWarning {
            field: field.to_string(),
            asset_id: asset.id.clone(),
            kind: "missing_asset_file".to_string(),
            message: format!(
                "project asset manifest asset {} missing file: {}",
                asset.id, asset.path
            ),
            expected_types: Vec::new(),
            observed_type: Some(asset.asset_type),
            path: Some(asset.path.clone()),
        });
    }
    match path.canonicalize() {
        Ok(resolved) if !resolved.starts_with(base) => Some(ProjectAssetReferenceIntegrityWarning {
            field: field.to_string(),
            asset_id: asset.id.clone(),
            kind: "asset_path_outside_project".to_string(),
            message: format!(
                "project asset manifest asset {} must stay inside the project root",
                asset.id
            ),
            expected_types: Vec::new(),
            observed_type: Some(asset.asset_type),
            path: Some(asset.path.clone()),
        }),
        Err(error) => Some(ProjectAssetReferenceIntegrityWarning {
            field: field.to_string(),
            asset_id: asset.id.clone(),
            kind: "asset_path_unresolved".to_string(),
            message: format!(
                "failed to resolve project asset manifest asset {} path {}: {}",
                asset.id, asset.path, error
            ),
            expected_types: Vec::new(),
            observed_type: Some(asset.asset_type),
            path: Some(asset.path.clone()),
        }),
        Ok(_) => match hash_project_asset_file(&path) {
            Ok(observed)
                if asset.content_hash.algorithm == observed.algorithm
                    && asset.content_hash.value == observed.value =>
            {
                None
            }
            Ok(observed) => Some(ProjectAssetReferenceIntegrityWarning {
                field: field.to_string(),
                asset_id: asset.id.clone(),
                kind: "stale_asset_hash".to_string(),
                message: format!(
                    "project asset manifest asset {} contentHash mismatch: expected {}:{}, observed {}:{}",
                    asset.id,
                    asset.content_hash.algorithm,
                    asset.content_hash.value,
                    observed.algorithm,
                    observed.value
                ),
                expected_types: Vec::new(),
                observed_type: Some(asset.asset_type),
                path: Some(asset.path.clone()),
            }),
            Err(error) => Some(ProjectAssetReferenceIntegrityWarning {
                field: field.to_string(),
                asset_id: asset.id.clone(),
                kind: "asset_hash_unreadable".to_string(),
                message: error.to_string(),
                expected_types: Vec::new(),
                observed_type: Some(asset.asset_type),
                path: Some(asset.path.clone()),
            }),
        },
    }
}

struct ProjectSceneAssetRef {
    field: String,
    asset_id: String,
    expected_types: &'static [ProjectAssetType],
}

const PROJECT_SCENE_IMAGE_REF_TYPES: &[ProjectAssetType] =
    &[ProjectAssetType::Image, ProjectAssetType::SpriteAtlas];
const PROJECT_SCENE_AUDIO_REF_TYPES: &[ProjectAssetType] = &[ProjectAssetType::Audio];

fn collect_project_scene_asset_refs(scene: &SceneDocument) -> Vec<ProjectSceneAssetRef> {
    let mut refs = Vec::new();
    for entity in &scene.entities {
        if let Some(asset) = &entity.sprite.asset {
            refs.push(ProjectSceneAssetRef {
                field: format!("scene entity {} sprite asset", entity.id),
                asset_id: asset.clone(),
                expected_types: PROJECT_SCENE_IMAGE_REF_TYPES,
            });
        }
        if let Some(animation) = &entity.components.animation {
            for (index, frame) in animation.frames.iter().enumerate() {
                if let Some(asset) = &frame.asset {
                    refs.push(ProjectSceneAssetRef {
                        field: format!("scene entity {} animation frame {index} asset", entity.id),
                        asset_id: asset.clone(),
                        expected_types: PROJECT_SCENE_IMAGE_REF_TYPES,
                    });
                }
            }
            for clip in &animation.clips {
                for (index, frame) in clip.frames.iter().enumerate() {
                    if let Some(asset) = &frame.asset {
                        refs.push(ProjectSceneAssetRef {
                            field: format!(
                                "scene entity {} animation clip {} frame {index} asset",
                                entity.id, clip.id
                            ),
                            asset_id: asset.clone(),
                            expected_types: PROJECT_SCENE_IMAGE_REF_TYPES,
                        });
                    }
                }
            }
        }
        if let Some(audio) = &entity.components.audio {
            for event in &audio.events {
                if let Some(asset) = &event.asset {
                    refs.push(ProjectSceneAssetRef {
                        field: format!(
                            "scene entity {} audio event {} asset",
                            entity.id, event.name
                        ),
                        asset_id: asset.clone(),
                        expected_types: PROJECT_SCENE_AUDIO_REF_TYPES,
                    });
                }
            }
        }
    }
    for tilemap in &scene.tilemaps {
        for tile in &tilemap.tiles {
            if let Some(asset) = &tile.asset {
                refs.push(ProjectSceneAssetRef {
                    field: format!("scene tilemap {} tile {} asset", tilemap.id, tile.id),
                    asset_id: asset.clone(),
                    expected_types: PROJECT_SCENE_IMAGE_REF_TYPES,
                });
            }
        }
    }
    refs
}

impl ProjectAssetManifestEntry {
    fn validate_schema(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("project asset manifest assets[{index}].id"),
            &self.id,
        )?;
        require_text(
            &format!("project asset manifest assets[{index}].path"),
            &self.path,
        )?;
        self.content_hash.validate_schema(&format!(
            "project asset manifest assets[{index}].contentHash"
        ))?;
        if let Some(dimensions) = &self.dimensions {
            dimensions.validate_schema(&format!(
                "project asset manifest assets[{index}].dimensions"
            ))?;
        }
        let field = format!("project asset manifest assets[{index}]");
        match (&self.asset_type, &self.atlas) {
            (ProjectAssetType::SpriteAtlas, Some(atlas)) => {
                atlas.validate_schema(&format!("{field}.atlas"))?;
            }
            (ProjectAssetType::SpriteAtlas, None) => {
                return Err(anyhow!("{field}.atlas is required for sprite_atlas assets"));
            }
            (_, Some(_)) => {
                return Err(anyhow!(
                    "{field}.atlas is only allowed for sprite_atlas assets"
                ));
            }
            (_, None) => {}
        }
        match (&self.asset_type, &self.tileset) {
            (ProjectAssetType::Tileset, Some(tileset)) => {
                tileset.validate_schema(&format!("{field}.tileset"))?;
            }
            (ProjectAssetType::Tileset, None) => {
                return Err(anyhow!("{field}.tileset is required for tileset assets"));
            }
            (_, Some(_)) => {
                return Err(anyhow!(
                    "{field}.tileset is only allowed for tileset assets"
                ));
            }
            (_, None) => {}
        }
        match (&self.asset_type, &self.tilemap) {
            (ProjectAssetType::Tilemap, Some(tilemap)) => {
                tilemap.validate_schema(&format!("{field}.tilemap"))?;
            }
            (ProjectAssetType::Tilemap, None) => {
                return Err(anyhow!("{field}.tilemap is required for tilemap assets"));
            }
            (_, Some(_)) => {
                return Err(anyhow!(
                    "{field}.tilemap is only allowed for tilemap assets"
                ));
            }
            (_, None) => {}
        }
        if self.duration_ms == Some(0) {
            return Err(anyhow!(
                "project asset manifest assets[{index}].durationMs must be positive when present"
            ));
        }
        if let Some(license) = &self.license {
            require_text(
                &format!("project asset manifest assets[{index}].license"),
                license,
            )?;
        }
        if let Some(source) = &self.source {
            require_text(
                &format!("project asset manifest assets[{index}].source"),
                source,
            )?;
        }
        for (key, value) in &self.metadata {
            require_text(
                &format!("project asset manifest assets[{index}].metadata key"),
                key,
            )?;
            require_text(
                &format!("project asset manifest assets[{index}].metadata.{key}"),
                value,
            )?;
        }
        Ok(())
    }

    fn validate_integrity(&self, index: usize, base_dir: &Path, base: &Path) -> Result<()> {
        self.validate_schema(index)?;
        validate_project_asset_path(
            &format!("project asset manifest assets[{index}].path"),
            &self.path,
            self.asset_type,
            self.classification,
        )?;
        let path = base_dir.join(&self.path);
        if !path.is_file() {
            return Err(anyhow!(
                "project asset manifest asset {} missing file: {}",
                self.id,
                self.path
            ));
        }
        let resolved = path.canonicalize().with_context(|| {
            format!(
                "failed to resolve project asset manifest asset {} path {}",
                self.id, self.path
            )
        })?;
        if !resolved.starts_with(base) {
            return Err(anyhow!(
                "project asset manifest asset {} must stay inside the project root",
                self.id
            ));
        }
        let observed = hash_project_asset_file(&path)?;
        if self.content_hash.algorithm != observed.algorithm
            || self.content_hash.value != observed.value
        {
            return Err(anyhow!(
                "project asset manifest asset {} contentHash mismatch: expected {}:{}, observed {}:{}",
                self.id,
                self.content_hash.algorithm,
                self.content_hash.value,
                observed.algorithm,
                observed.value
            ));
        }
        Ok(())
    }
}

impl ProjectAssetContentHash {
    fn validate_schema(&self, field: &str) -> Result<()> {
        require_text(&format!("{field}.algorithm"), &self.algorithm)?;
        require_text(&format!("{field}.value"), &self.value)?;
        if self.algorithm != PROJECT_ASSET_CONTENT_HASH_ALGORITHM {
            return Err(anyhow!(
                "{field}.algorithm must be {PROJECT_ASSET_CONTENT_HASH_ALGORITHM}"
            ));
        }
        if self.value.len() != 16 || !self.value.chars().all(|ch| ch.is_ascii_hexdigit()) {
            return Err(anyhow!(
                "{field}.value must be a 16-character lowercase hex content hash"
            ));
        }
        if self.value.chars().any(|ch| ch.is_ascii_uppercase()) {
            return Err(anyhow!("{field}.value must use lowercase hex"));
        }
        Ok(())
    }
}

impl ProjectAssetDimensions {
    fn validate_schema(&self, field: &str) -> Result<()> {
        if self.width == 0 || self.height == 0 {
            return Err(anyhow!("{field} width and height must be positive"));
        }
        Ok(())
    }
}

impl ProjectSpriteAtlasManifest {
    fn validate_schema(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.imageAssetId"), &self.image_asset_id)?;
        if self.frames.is_empty() {
            return Err(anyhow!("{field}.frames must not be empty"));
        }
        for (index, frame) in self.frames.iter().enumerate() {
            frame.validate_schema(&format!("{field}.frames[{index}]"))?;
        }
        for (index, animation) in self.animations.iter().enumerate() {
            animation.validate_schema(&format!("{field}.animations[{index}]"))?;
        }
        Ok(())
    }

    fn validate_integrity(
        &self,
        atlas_asset_id: &str,
        dimensions: &ProjectAssetDimensions,
    ) -> Result<()> {
        let mut frame_ids = BTreeSet::new();
        for frame in &self.frames {
            if !frame_ids.insert(frame.id.as_str()) {
                return Err(anyhow!(
                    "sprite atlas {atlas_asset_id} duplicate frame id: {}",
                    frame.id
                ));
            }
            frame.validate_bounds(atlas_asset_id, dimensions)?;
        }
        for animation in &self.animations {
            animation.validate_frame_refs(atlas_asset_id, &frame_ids)?;
        }
        Ok(())
    }
}

impl ProjectSpriteAtlasFrame {
    fn validate_schema(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.id"), &self.id)?;
        self.rect.validate_schema(&format!("{field}.rect"))
    }

    fn validate_bounds(
        &self,
        atlas_asset_id: &str,
        dimensions: &ProjectAssetDimensions,
    ) -> Result<()> {
        let right = self.rect.x.checked_add(self.rect.width).ok_or_else(|| {
            anyhow!(
                "sprite atlas {atlas_asset_id} frame {} rectangle overflows image bounds",
                self.id
            )
        })?;
        let bottom = self.rect.y.checked_add(self.rect.height).ok_or_else(|| {
            anyhow!(
                "sprite atlas {atlas_asset_id} frame {} rectangle overflows image bounds",
                self.id
            )
        })?;
        if right > dimensions.width || bottom > dimensions.height {
            return Err(anyhow!(
                "sprite atlas {atlas_asset_id} frame {} rectangle is outside atlas image bounds",
                self.id
            ));
        }
        Ok(())
    }
}

impl ProjectSpriteAtlasFrameRect {
    fn validate_schema(&self, field: &str) -> Result<()> {
        if self.width == 0 || self.height == 0 {
            return Err(anyhow!(
                "{field}.width and height must be greater than zero"
            ));
        }
        Ok(())
    }
}

impl ProjectSpriteAtlasAnimation {
    fn validate_schema(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.id"), &self.id)?;
        if self.frames.is_empty() {
            return Err(anyhow!("{field}.frames must not be empty"));
        }
        for (index, frame) in self.frames.iter().enumerate() {
            frame.validate_schema(&format!("{field}.frames[{index}]"))?;
        }
        Ok(())
    }

    fn validate_frame_refs(&self, atlas_asset_id: &str, frame_ids: &BTreeSet<&str>) -> Result<()> {
        for frame in &self.frames {
            if !frame_ids.contains(frame.frame_id.as_str()) {
                return Err(anyhow!(
                    "sprite atlas {atlas_asset_id} animation {} references unknown frame {}",
                    self.id,
                    frame.frame_id
                ));
            }
        }
        Ok(())
    }
}

impl ProjectSpriteAtlasAnimationFrame {
    fn validate_schema(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.frameId"), &self.frame_id)?;
        if self.duration_ms == 0 {
            return Err(anyhow!("{field}.durationMs must be greater than zero"));
        }
        Ok(())
    }
}

impl ProjectTilesetManifest {
    fn validate_schema(&self, field: &str) -> Result<()> {
        if self.tile_width == 0 || self.tile_height == 0 {
            return Err(anyhow!(
                "{field}.tileWidth and tileHeight must be greater than zero"
            ));
        }
        if self.tiles.is_empty() {
            return Err(anyhow!("{field}.tiles must not be empty"));
        }
        for (index, tile) in self.tiles.iter().enumerate() {
            tile.validate_schema(&format!("{field}.tiles[{index}]"))?;
        }
        Ok(())
    }

    fn validate_integrity(&self, tileset_asset_id: &str) -> Result<()> {
        let mut tile_ids = BTreeSet::new();
        let mut indexes = BTreeSet::new();
        for tile in &self.tiles {
            if !tile_ids.insert(tile.id.as_str()) {
                return Err(anyhow!(
                    "tileset {tileset_asset_id} duplicate tile id: {}",
                    tile.id
                ));
            }
            if !indexes.insert(tile.index) {
                return Err(anyhow!(
                    "tileset {tileset_asset_id} duplicate tile index: {}",
                    tile.index
                ));
            }
        }
        Ok(())
    }

    fn tiles_by_id(&self) -> BTreeMap<&str, &ProjectTilesetTile> {
        self.tiles
            .iter()
            .map(|tile| (tile.id.as_str(), tile))
            .collect()
    }
}

impl ProjectTilesetTile {
    fn validate_schema(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.id"), &self.id)?;
        if let Some(trigger) = &self.trigger {
            validate_path_component(&format!("{field}.trigger"), trigger)?;
        }
        for (key, value) in &self.metadata {
            require_text(&format!("{field}.metadata key"), key)?;
            require_text(&format!("{field}.metadata.{key}"), value)?;
        }
        Ok(())
    }
}

impl ProjectTilemapManifest {
    fn validate_schema(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.tilesetAssetId"), &self.tileset_asset_id)?;
        if self.width == 0 || self.height == 0 {
            return Err(anyhow!(
                "{field}.width and height must be greater than zero"
            ));
        }
        if self.layers.is_empty() {
            return Err(anyhow!("{field}.layers must not be empty"));
        }
        for (index, layer) in self.layers.iter().enumerate() {
            layer.validate_schema(&format!("{field}.layers[{index}]"))?;
        }
        Ok(())
    }

    fn validate_integrity(
        &self,
        tilemap_asset_id: &str,
        tileset: &ProjectTilesetManifest,
    ) -> Result<()> {
        let expected_cells = (self.width as usize)
            .checked_mul(self.height as usize)
            .ok_or_else(|| anyhow!("tilemap {tilemap_asset_id} dimensions overflow"))?;
        let tiles_by_id = tileset.tiles_by_id();
        let mut layer_ids = BTreeSet::new();
        for layer in &self.layers {
            if !layer_ids.insert(layer.id.as_str()) {
                return Err(anyhow!(
                    "tilemap {tilemap_asset_id} duplicate layer id: {}",
                    layer.id
                ));
            }
            layer.validate_integrity(tilemap_asset_id, expected_cells, &tiles_by_id)?;
        }
        Ok(())
    }

    fn extract(
        &self,
        tilemap_asset_id: &str,
        tileset: &ProjectTilesetManifest,
    ) -> ProjectTilemapExtraction {
        let tiles_by_id = tileset.tiles_by_id();
        let mut collision_cells = Vec::new();
        let mut trigger_cells = Vec::new();
        let mut hazard_cells = Vec::new();
        let mut goal_cells = Vec::new();
        for layer in &self.layers {
            for (index, tile_id) in layer.data.iter().enumerate() {
                let Some(tile_id) = tile_id else {
                    continue;
                };
                let Some(tile) = tiles_by_id.get(tile_id.as_str()) else {
                    continue;
                };
                let cell = ProjectTilemapExtractedCell {
                    layer_id: layer.id.clone(),
                    x: (index as u32) % self.width,
                    y: (index as u32) / self.width,
                    index,
                    tile_id: tile.id.clone(),
                    trigger: tile.trigger.clone(),
                };
                if tile.solid || layer.kind == ProjectTilemapLayerKind::Collision {
                    collision_cells.push(cell.clone());
                }
                if tile.trigger.is_some() || layer.kind == ProjectTilemapLayerKind::Trigger {
                    trigger_cells.push(cell.clone());
                }
                if tile.hazard {
                    hazard_cells.push(cell.clone());
                }
                if tile.goal {
                    goal_cells.push(cell);
                }
            }
        }
        ProjectTilemapExtraction {
            tilemap_asset_id: tilemap_asset_id.to_string(),
            tileset_asset_id: self.tileset_asset_id.clone(),
            width: self.width,
            height: self.height,
            collision_cells,
            trigger_cells,
            hazard_cells,
            goal_cells,
        }
    }
}

impl ProjectTilemapLayer {
    fn validate_schema(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.id"), &self.id)?;
        if self.data.is_empty() {
            return Err(anyhow!("{field}.data must not be empty"));
        }
        for (index, tile_id) in self.data.iter().enumerate() {
            if let Some(tile_id) = tile_id {
                validate_path_component(&format!("{field}.data[{index}]"), tile_id)?;
            }
        }
        for (key, value) in &self.metadata {
            require_text(&format!("{field}.metadata key"), key)?;
            require_text(&format!("{field}.metadata.{key}"), value)?;
        }
        Ok(())
    }

    fn validate_integrity(
        &self,
        tilemap_asset_id: &str,
        expected_cells: usize,
        tiles_by_id: &BTreeMap<&str, &ProjectTilesetTile>,
    ) -> Result<()> {
        if self.data.len() != expected_cells {
            return Err(anyhow!(
                "tilemap {tilemap_asset_id} layer {} data length must equal width*height ({expected_cells})",
                self.id
            ));
        }
        for tile_id in self.data.iter().flatten() {
            if !tiles_by_id.contains_key(tile_id.as_str()) {
                return Err(anyhow!(
                    "tilemap {tilemap_asset_id} layer {} references unknown tile id: {tile_id}",
                    self.id
                ));
            }
        }
        Ok(())
    }
}

pub fn hash_project_asset_file(path: impl AsRef<Path>) -> Result<ProjectAssetContentHash> {
    let path = path.as_ref();
    let bytes = fs::read(path)
        .with_context(|| format!("failed to read project asset file {}", path.display()))?;
    Ok(ProjectAssetContentHash {
        algorithm: PROJECT_ASSET_CONTENT_HASH_ALGORITHM.to_string(),
        value: format!("{:016x}", fnv1a64(&bytes)),
    })
}

fn validate_project_asset_path(
    field: &str,
    value: &str,
    asset_type: ProjectAssetType,
    classification: ProjectAssetClassification,
) -> Result<()> {
    validate_project_manifest_path(field, value)?;
    if classification == ProjectAssetClassification::SourceLike {
        for generated_root in PROJECT_ASSET_SOURCE_GENERATED_ROOTS {
            if project_manifest_paths_overlap(value, generated_root) {
                return Err(anyhow!(
                    "{field} for source-like assets must not overlap generated root {generated_root}"
                ));
            }
        }
    }
    let extension = Path::new(value)
        .extension()
        .and_then(|value| value.to_str())
        .unwrap_or_default()
        .to_ascii_lowercase();
    let supported = match asset_type {
        ProjectAssetType::Image => {
            matches!(extension.as_str(), "png" | "jpg" | "jpeg" | "svg" | "webp")
        }
        ProjectAssetType::SpriteAtlas | ProjectAssetType::Tileset | ProjectAssetType::Tilemap => {
            extension == "json"
        }
        ProjectAssetType::Audio => matches!(extension.as_str(), "ogg" | "mp3" | "wav"),
        ProjectAssetType::Font => matches!(extension.as_str(), "ttf" | "otf" | "woff" | "woff2"),
    };
    if supported {
        Ok(())
    } else {
        Err(anyhow!(
            "{field} has unsupported extension for project asset type {:?}",
            asset_type
        ))
    }
}

const ASSET_MANIFEST_SCHEMA_VERSION: &str = "1";

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct AssetManifest {
    #[serde(rename = "schemaVersion")]
    #[serde(default = "asset_manifest_schema_v1")]
    pub schema_version: String,
    pub id: String,
    pub assets: Vec<AssetManifestEntry>,
    #[serde(default = "empty_json_object")]
    pub metadata: serde_json::Value,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct AssetManifestEntry {
    pub id: String,
    pub kind: AssetManifestKind,
    pub path: String,
    #[serde(default = "empty_json_object")]
    pub metadata: serde_json::Value,
}

#[derive(Debug, Clone, Copy, Deserialize, Serialize, PartialEq, Eq, PartialOrd, Ord)]
#[serde(rename_all = "snake_case")]
pub enum AssetManifestKind {
    Image,
    Sprite,
    Audio,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct ResolvedAssetManifestEntry {
    pub id: String,
    pub kind: AssetManifestKind,
    pub path: String,
}

fn asset_manifest_schema_v1() -> String {
    ASSET_MANIFEST_SCHEMA_VERSION.to_string()
}

impl AssetManifest {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let manifest: AssetManifest =
            serde_json::from_str(input).context("failed to parse Asset Manifest JSON")?;
        manifest.validate()?;
        Ok(manifest)
    }

    pub fn from_path(path: impl AsRef<Path>) -> Result<Self> {
        let path = path.as_ref();
        let input = fs::read_to_string(path)
            .with_context(|| format!("failed to read asset manifest {}", path.display()))?;
        let manifest = Self::from_json_str(&input)
            .with_context(|| format!("failed to parse asset manifest {}", path.display()))?;
        // `Path::parent()` returns `Some("")` (not `None`) for a bare filename
        // with no directory component, and an empty path fails to canonicalize;
        // treat that as the current directory.
        let base_dir = match path.parent() {
            Some(parent) if !parent.as_os_str().is_empty() => parent,
            _ => Path::new("."),
        };
        manifest
            .validate_files(base_dir)
            .with_context(|| format!("asset manifest {} references invalid files", manifest.id))?;
        Ok(manifest)
    }

    pub fn validate(&self) -> Result<()> {
        if self.schema_version != ASSET_MANIFEST_SCHEMA_VERSION {
            return Err(anyhow!(
                "asset manifest schemaVersion must be {ASSET_MANIFEST_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("asset manifest id", &self.id)?;
        validate_scene_metadata("asset manifest metadata", &self.metadata)?;
        if self.assets.is_empty() {
            return Err(anyhow!("asset manifest assets must not be empty"));
        }

        let mut ids = BTreeSet::new();
        let mut paths = BTreeSet::new();
        for asset in &self.assets {
            asset.validate()?;
            if !ids.insert(asset.id.clone()) {
                return Err(anyhow!("duplicate asset manifest asset id: {}", asset.id));
            }
            if !paths.insert(asset.path.clone()) {
                return Err(anyhow!(
                    "duplicate asset manifest asset path: {}",
                    asset.path
                ));
            }
        }
        Ok(())
    }

    pub fn validate_files(&self, base_dir: &Path) -> Result<()> {
        self.validate()?;
        let base = base_dir.canonicalize().with_context(|| {
            format!(
                "failed to resolve asset manifest base {}",
                base_dir.display()
            )
        })?;
        for asset in &self.assets {
            let path = base_dir.join(&asset.path);
            if !path.is_file() {
                return Err(anyhow!(
                    "asset manifest asset {} missing file: {}",
                    asset.id,
                    asset.path
                ));
            }
            let resolved = path.canonicalize().with_context(|| {
                format!(
                    "failed to resolve asset manifest asset {} path {}",
                    asset.id, asset.path
                )
            })?;
            if !resolved.starts_with(&base) {
                return Err(anyhow!(
                    "asset manifest asset {} must stay inside the manifest asset tree",
                    asset.id
                ));
            }
        }
        Ok(())
    }

    pub fn resolved_assets(&self) -> Vec<ResolvedAssetManifestEntry> {
        let mut assets = self
            .assets
            .iter()
            .map(|asset| ResolvedAssetManifestEntry {
                id: asset.id.clone(),
                kind: asset.kind,
                path: asset.path.clone(),
            })
            .collect::<Vec<_>>();
        assets.sort_by(|left, right| {
            (left.id.as_str(), left.kind, left.path.as_str()).cmp(&(
                right.id.as_str(),
                right.kind,
                right.path.as_str(),
            ))
        });
        assets
    }
}

impl AssetManifestEntry {
    fn validate(&self) -> Result<()> {
        validate_path_component("asset manifest asset id", &self.id)?;
        validate_asset_manifest_path("asset manifest asset path", &self.path, self.kind)?;
        validate_scene_metadata(
            &format!("asset manifest asset {} metadata", self.id),
            &self.metadata,
        )
    }
}

fn validate_asset_manifest_path(field: &str, value: &str, kind: AssetManifestKind) -> Result<()> {
    validate_scene_local_asset_path(field, value)?;
    let extension = Path::new(value)
        .extension()
        .and_then(|value| value.to_str())
        .unwrap_or_default()
        .to_ascii_lowercase();
    let supported = match kind {
        AssetManifestKind::Image | AssetManifestKind::Sprite => {
            matches!(extension.as_str(), "png" | "jpg" | "jpeg" | "svg" | "webp")
        }
        AssetManifestKind::Audio => matches!(extension.as_str(), "ogg" | "mp3" | "wav"),
    };
    if supported {
        Ok(())
    } else {
        Err(anyhow!(
            "{field} has unsupported extension for asset kind {:?}",
            kind
        ))
    }
}

impl ScenarioAssertion {
    fn validate(&self, scenario_index: usize, assertion_index: usize) -> Result<()> {
        let assertion = match self {
            ScenarioAssertion::WorldState { world_state } => world_state,
            ScenarioAssertion::FrameStats { frame_stats } => frame_stats,
            ScenarioAssertion::RuntimeEvents { runtime_events } => runtime_events,
            ScenarioAssertion::WorldFlags { world_flags } => world_flags,
            ScenarioAssertion::PhysicsEvidence { physics_evidence } => physics_evidence,
            ScenarioAssertion::PerformanceMetrics {
                performance_metrics,
            } => performance_metrics,
            ScenarioAssertion::ConsoleErrors { console_errors } => console_errors,
            ScenarioAssertion::CollisionEvidence { collision_evidence } => collision_evidence,
            ScenarioAssertion::AudioEvidence { audio_evidence } => audio_evidence,
            ScenarioAssertion::AnimationEvidence { animation_evidence } => animation_evidence,
            ScenarioAssertion::TransitionEvidence {
                transition_evidence,
            } => transition_evidence,
        };
        assertion.validate(scenario_index, assertion_index)
    }
}

impl JsonPathAssertion {
    fn validate(&self, scenario_index: usize, assertion_index: usize) -> Result<()> {
        require_text(
            &format!("scenarios[{scenario_index}].assertions[{assertion_index}].path"),
            &self.path,
        )?;
        validate_scenario_path(&self.path).with_context(|| {
            format!("scenarios[{scenario_index}].assertions[{assertion_index}].path is invalid")
        })?;
        let operator_count = [
            self.equals.is_some(),
            self.not_equals.is_some(),
            self.exists.is_some(),
            self.contains.is_some(),
            self.greater_than.is_some(),
            self.less_than.is_some(),
            self.count_equals.is_some(),
            self.count_greater_than.is_some(),
            self.count_less_than.is_some(),
            self.contains_type.is_some(),
        ]
        .into_iter()
        .filter(|present| *present)
        .count();
        if operator_count != 1 {
            return Err(anyhow!(
                "scenarios[{scenario_index}].assertions[{assertion_index}] must define exactly one bounded assertion operator"
            ));
        }
        for (operator, value) in [
            ("equals", &self.equals),
            ("notEquals", &self.not_equals),
            ("contains", &self.contains),
        ] {
            if value.as_ref().is_some_and(serde_json::Value::is_null) {
                return Err(anyhow!(
                    "scenarios[{scenario_index}].assertions[{assertion_index}].{operator} must not be null"
                ));
            }
        }
        for (operator, value) in [
            ("greaterThan", &self.greater_than),
            ("lessThan", &self.less_than),
        ] {
            if value.as_ref().is_some_and(|value| !value.is_number()) {
                return Err(anyhow!(
                    "scenarios[{scenario_index}].assertions[{assertion_index}].{operator} must be numeric"
                ));
            }
        }
        if self
            .contains_type
            .as_ref()
            .is_some_and(|value| value.trim().is_empty())
        {
            return Err(anyhow!(
                "scenarios[{scenario_index}].assertions[{assertion_index}].containsType must not be empty"
            ));
        }
        Ok(())
    }
}

fn validate_scenario_path(path: &str) -> Result<()> {
    for segment in path.split('.') {
        require_text("scenario assertion path segment", segment)?;
        if !segment
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || ch == '_' || ch == '-')
        {
            return Err(anyhow!(
                "scenario assertion paths may only contain ASCII letters, numbers, '_', '-' and '.'"
            ));
        }
    }
    Ok(())
}

fn validate_path_component(field: &str, value: &str) -> Result<()> {
    require_text(field, value)?;
    if !value
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || ch == '-' || ch == '_')
    {
        return Err(anyhow!(
            "{field} may only contain ASCII letters, numbers, '-' or '_'"
        ));
    }
    Ok(())
}

fn require_text(field: &str, value: &str) -> Result<()> {
    if value.trim().is_empty() {
        Err(anyhow!("{field} is required"))
    } else {
        Ok(())
    }
}

/// Fail-closed validation for URLs that reach a browser navigation sink.
///
/// The local smoke/scenario paths only ever drive `http`/`https` targets, so we
/// reject other schemes (for example `file:`, `chrome:`, `data:`) before the URL
/// is handed to CDP `Page.navigate`, preventing capture of unintended local pages.
fn require_http_url(field: &str, value: &str) -> Result<()> {
    require_text(field, value)?;
    let lowered = value.trim().to_ascii_lowercase();
    if lowered.starts_with("http://") || lowered.starts_with("https://") {
        Ok(())
    } else {
        Err(anyhow!("{field} must use http:// or https://"))
    }
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct EvidenceArtifact {
    pub id: String,
    pub kind: String,
    pub path: String,
    #[serde(default)]
    pub metadata: serde_json::Value,
    pub added_at_unix_ms: u128,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct EvidenceIndex {
    pub artifacts: Vec<EvidenceArtifact>,
}

pub fn append_ledger_event(
    run_dir: impl AsRef<Path>,
    kind: &str,
    actor: &str,
    payload: serde_json::Value,
) -> Result<serde_json::Value> {
    require_text("ledger event kind", kind)?;
    require_text("ledger event actor", actor)?;

    let event = json!({
        "event": kind,
        "actor": actor,
        "payload": payload,
        "created_at_unix_ms": unix_millis()?,
    });
    let ledger_path = run_dir.as_ref().join("ledger.jsonl");
    let line = serde_json::to_string(&event).context("failed to serialize ledger event")?;
    let _guard = LEDGER_APPEND_LOCK
        .get_or_init(|| Mutex::new(()))
        .lock()
        .map_err(|_| anyhow!("ledger append lock poisoned"))?;
    let mut file = OpenOptions::new()
        .create(false)
        .append(true)
        .open(&ledger_path)
        .with_context(|| format!("failed to open ledger for append {}", ledger_path.display()))?;
    writeln!(file, "{line}").context("failed to append ledger event")?;
    Ok(event)
}

pub fn read_ledger_events(run_dir: impl AsRef<Path>) -> Result<Vec<serde_json::Value>> {
    let ledger_path = run_dir.as_ref().join("ledger.jsonl");
    let file = File::open(&ledger_path)
        .with_context(|| format!("failed to read ledger {}", ledger_path.display()))?;
    let reader = BufReader::new(file);
    let mut events = Vec::new();

    for (line_number, line) in reader.lines().enumerate() {
        let line = line.with_context(|| {
            format!(
                "failed to read ledger line {} from {}",
                line_number + 1,
                ledger_path.display()
            )
        })?;
        if line.trim().is_empty() {
            continue;
        }
        let event: serde_json::Value = serde_json::from_str(&line).with_context(|| {
            format!(
                "failed to parse ledger JSON on line {} from {}",
                line_number + 1,
                ledger_path.display()
            )
        })?;
        events.push(event);
    }

    Ok(events)
}

pub fn add_evidence_artifact(
    run_dir: impl AsRef<Path>,
    id: &str,
    kind: &str,
    path: &str,
    metadata: serde_json::Value,
) -> Result<EvidenceArtifact> {
    require_text("evidence artifact id", id)?;
    require_text("evidence artifact kind", kind)?;
    require_text("evidence artifact path", path)?;
    validate_evidence_artifact_path(path)?;

    let _guard = EVIDENCE_INDEX_LOCK
        .get_or_init(|| Mutex::new(()))
        .lock()
        .map_err(|_| anyhow!("evidence index lock poisoned"))?;
    let mut index = read_evidence_index(&run_dir)?;
    if index.artifacts.iter().any(|artifact| artifact.id == id) {
        return Err(anyhow!("evidence artifact id already exists: {id}"));
    }

    let artifact = EvidenceArtifact {
        id: id.to_string(),
        kind: kind.to_string(),
        path: path.to_string(),
        metadata,
        added_at_unix_ms: unix_millis()?,
    };
    index.artifacts.push(artifact.clone());
    write_evidence_index(run_dir, &index)?;
    Ok(artifact)
}

pub fn list_evidence_artifacts(run_dir: impl AsRef<Path>) -> Result<Vec<EvidenceArtifact>> {
    Ok(read_evidence_index(run_dir)?.artifacts)
}

fn validate_evidence_artifact_path(path: &str) -> Result<()> {
    let evidence_path = Path::new(path);
    if evidence_path.is_absolute() {
        return Err(anyhow!("evidence artifact path must be relative"));
    }
    if !path.starts_with("evidence/") {
        return Err(anyhow!("evidence artifact path must start with evidence/"));
    }
    for component in evidence_path.components() {
        match component {
            Component::Normal(_) | Component::CurDir => {}
            _ => {
                return Err(anyhow!(
                    "evidence artifact path must stay inside the run evidence tree"
                ));
            }
        }
    }
    Ok(())
}

fn read_evidence_index(run_dir: impl AsRef<Path>) -> Result<EvidenceIndex> {
    let index_path = run_dir.as_ref().join("evidence/index.json");
    let input = fs::read_to_string(&index_path)
        .with_context(|| format!("failed to read evidence index {}", index_path.display()))?;
    let index: EvidenceIndex = serde_json::from_str(&input)
        .with_context(|| format!("failed to parse evidence index {}", index_path.display()))?;
    Ok(index)
}

fn write_evidence_index(run_dir: impl AsRef<Path>, index: &EvidenceIndex) -> Result<()> {
    write_json_atomic(&run_dir.as_ref().join("evidence/index.json"), &json!(index))
}

