fn canonical_json_digest(value: serde_json::Value) -> Result<String> {
    let bytes = serde_json::to_vec(&canonical_json_value(value))
        .context("failed to serialize canonical JSON for digest")?;
    Ok(format!("{:016x}", fnv1a64(&bytes)))
}

pub fn validate_visual_edit_draft_review_preflight(
    run_dir: impl AsRef<Path>,
    draft: &VisualEditDraftArtifact,
) -> Result<VisualEditDraftReviewPreflight> {
    let run_dir = run_dir.as_ref();
    draft.validate()?;
    let review_gate = draft
        .review_gate
        .as_ref()
        .ok_or_else(|| anyhow!("visual edit draft review preflight requires reviewGate linkage"))?;
    review_gate.validate()?;

    let proposals = read_mutation_proposals(run_dir)?;
    let proposal = proposals
        .proposals
        .iter()
        .find(|proposal| proposal.id == review_gate.proposal_id)
        .ok_or_else(|| {
            anyhow!(
                "visual edit draft review preflight proposal id not found: {}",
                review_gate.proposal_id
            )
        })?;
    if proposal.status != "proposed" {
        return Err(anyhow!(
            "visual edit draft review preflight proposal {} must remain proposed; found {}",
            proposal.id,
            proposal.status
        ));
    }

    let patch_drafts = read_patch_draft_artifact(run_dir)?;
    let patch_draft = patch_drafts
        .drafts
        .iter()
        .find(|patch_draft| patch_draft.id == review_gate.patch_draft_id)
        .ok_or_else(|| {
            anyhow!(
                "visual edit draft review preflight patch draft id not found: {}",
                review_gate.patch_draft_id
            )
        })?;
    if patch_draft.proposal_id != review_gate.proposal_id {
        return Err(anyhow!(
            "visual edit draft review preflight patch draft {} is linked to proposal {}, not {}",
            patch_draft.id,
            patch_draft.proposal_id,
            review_gate.proposal_id
        ));
    }

    let review = read_mutation_review_artifact(run_dir)?;
    let decision = review
        .decisions
        .iter()
        .find(|decision| decision.id == review_gate.review_decision_id)
        .ok_or_else(|| {
            anyhow!(
                "visual edit draft review preflight decision id not found: {}",
                review_gate.review_decision_id
            )
        })?;
    validate_accepted_mutation_review_decision(
        run_dir,
        decision,
        &review_gate.proposal_id,
        Some(&review_gate.patch_draft_id),
        true,
    )?;

    Ok(VisualEditDraftReviewPreflight {
        draft_id: draft.draft_id.clone(),
        proposal_id: review_gate.proposal_id.clone(),
        patch_draft_id: review_gate.patch_draft_id.clone(),
        review_decision_id: review_gate.review_decision_id.clone(),
        status: "review_preflight_passed".to_string(),
    })
}

fn validate_accepted_mutation_review_decision(
    run_dir: &Path,
    decision: &MutationReviewDecision,
    expected_proposal_id: &str,
    expected_patch_draft_id: Option<&str>,
    require_expected_hashes: bool,
) -> Result<()> {
    if decision.state != MutationReviewState::Accepted
        || decision.decision_status.as_ref() != Some(&MutationReviewState::Accepted)
    {
        return Err(anyhow!(
            "review-gated preflight requires an accepted decision; found {:?}",
            decision.decision_status.as_ref().unwrap_or(&decision.state)
        ));
    }
    if decision.proposal_id.as_deref() != Some(expected_proposal_id) {
        return Err(anyhow!(
            "review-gated preflight decision {} is not linked to proposal {}",
            decision.id,
            expected_proposal_id
        ));
    }
    if let Some(expected_patch_draft_id) = expected_patch_draft_id {
        if decision.patch_draft_id != expected_patch_draft_id {
            return Err(anyhow!(
                "review-gated preflight decision {} is linked to patch draft {}, not {}",
                decision.id,
                decision.patch_draft_id,
                expected_patch_draft_id
            ));
        }
    }
    if decision.evidence_refs.is_empty() {
        return Err(anyhow!(
            "review-gated preflight decision {} requires evidence refs",
            decision.id
        ));
    }
    let checklist = decision.guardrail_checklist.as_ref().ok_or_else(|| {
        anyhow!(
            "review-gated preflight decision {} requires a guardrail checklist",
            decision.id
        )
    })?;
    checklist.validate()?;
    let Some(expected_hashes) = decision.expected_hashes.as_ref() else {
        if require_expected_hashes {
            return Err(anyhow!(
                "review-gated preflight decision {} requires expected proposal, patch draft, and evidence hashes",
                decision.id
            ));
        }
        return Ok(());
    };
    if let Some(expected) = expected_hashes.proposal_index_hash.as_deref() {
        let actual = canonical_json_digest(json!(read_mutation_proposals(run_dir)?))?;
        if expected != actual {
            return Err(anyhow!(
                "review-gated preflight decision {} proposal index hash mismatch; expected {}, found {}",
                decision.id, expected, actual
            ));
        }
    } else if require_expected_hashes {
        return Err(anyhow!(
            "review-gated preflight decision {} requires proposal index hash",
            decision.id
        ));
    }
    if let Some(expected) = expected_hashes.patch_draft_hash.as_deref() {
        let actual = canonical_json_digest(json!(read_patch_draft_artifact(run_dir)?))?;
        if expected != actual {
            return Err(anyhow!(
                "review-gated preflight decision {} patch draft hash mismatch; expected {}, found {}",
                decision.id, expected, actual
            ));
        }
    } else if require_expected_hashes {
        return Err(anyhow!(
            "review-gated preflight decision {} requires patch draft hash",
            decision.id
        ));
    }
    if let Some(expected) = expected_hashes.evidence_index_hash.as_deref() {
        let actual = canonical_json_digest(json!(read_evidence_index(run_dir)?))?;
        if expected != actual {
            return Err(anyhow!(
                "review-gated preflight decision {} evidence index hash mismatch; expected {}, found {}",
                decision.id, expected, actual
            ));
        }
    } else if require_expected_hashes {
        return Err(anyhow!(
            "review-gated preflight decision {} requires evidence index hash",
            decision.id
        ));
    }
    Ok(())
}

fn validate_review_gated_scene_apply_decision(
    run_dir: &Path,
    operation: &SceneOnlyMutationOperation,
) -> Result<Option<String>> {
    let Some(decision_id) = operation.review_decision_id.as_deref() else {
        return Ok(None);
    };
    require_text("scene-only mutation reviewDecisionId", decision_id)?;
    let review = read_mutation_review_artifact(run_dir)?;
    let decision = review
        .decisions
        .iter()
        .find(|decision| decision.id == decision_id)
        .ok_or_else(|| {
            anyhow!(
                "review-gated scene apply decision id not found: {}",
                decision_id
            )
        })?;
    if decision.state != MutationReviewState::Accepted
        || decision.decision_status.as_ref() != Some(&MutationReviewState::Accepted)
    {
        return Err(anyhow!(
            "review-gated scene apply requires an accepted decision; found {:?}",
            decision.decision_status.as_ref().unwrap_or(&decision.state)
        ));
    }
    if decision.proposal_id.as_deref() != Some(operation.proposal_id.as_str()) {
        return Err(anyhow!(
            "review-gated scene apply decision {} is not linked to proposal {}",
            decision_id,
            operation.proposal_id
        ));
    }
    if decision.evidence_refs.is_empty() {
        return Err(anyhow!(
            "review-gated scene apply decision {} requires evidence refs",
            decision_id
        ));
    }
    let checklist = decision.guardrail_checklist.as_ref().ok_or_else(|| {
        anyhow!(
            "review-gated scene apply decision {} requires a guardrail checklist",
            decision_id
        )
    })?;
    checklist.validate()?;
    if let Some(expected_hashes) = &decision.expected_hashes {
        if let Some(expected) = expected_hashes.proposal_index_hash.as_deref() {
            let actual = canonical_json_digest(json!(read_mutation_proposals(run_dir)?))?;
            if expected != actual {
                return Err(anyhow!(
                    "review-gated scene apply decision {} proposal index hash mismatch; expected {}, found {}",
                    decision_id, expected, actual
                ));
            }
        }
        if let Some(expected) = expected_hashes.patch_draft_hash.as_deref() {
            let actual = canonical_json_digest(json!(read_patch_draft_artifact(run_dir)?))?;
            if expected != actual {
                return Err(anyhow!(
                    "review-gated scene apply decision {} patch draft hash mismatch; expected {}, found {}",
                    decision_id, expected, actual
                ));
            }
        }
        if let Some(expected) = expected_hashes.evidence_index_hash.as_deref() {
            let actual = canonical_json_digest(json!(read_evidence_index(run_dir)?))?;
            if expected != actual {
                return Err(anyhow!(
                    "review-gated scene apply decision {} evidence index hash mismatch; expected {}, found {}",
                    decision_id, expected, actual
                ));
            }
        }
    }
    let applications = read_scene_only_mutation_applications(run_dir)?;
    if applications
        .applications
        .iter()
        .any(|application| application.review_decision_id.as_deref() == Some(decision_id))
    {
        return Err(anyhow!(
            "review-gated scene apply decision {} was already used",
            decision_id
        ));
    }
    if applications.applications.iter().any(|application| {
        application.proposal_id == operation.proposal_id && application.status == "applied"
    }) {
        return Err(anyhow!(
            "review-gated scene apply proposal {} already has an applied scene mutation",
            operation.proposal_id
        ));
    }
    Ok(Some(decision_id.to_string()))
}

fn validate_project_scene_mutation_context(
    operation: &SceneOnlyMutationOperation,
    before_scene_hash: &SceneHash,
) -> Result<Option<ProjectSceneMutationContext>> {
    let Some(project) = &operation.project else {
        return Ok(None);
    };
    require_text("scene-only mutation project projectId", &project.project_id)?;
    require_text(
        "scene-only mutation project manifestPath",
        &project.manifest_path,
    )?;
    validate_project_manifest_path("scene-only mutation project scenePath", &project.scene_path)?;
    let manifest_path = Path::new(&project.manifest_path);
    let manifest = ProjectManifest::from_path(manifest_path).with_context(|| {
        format!(
            "scene-only mutation project manifest failed validation: {}",
            manifest_path.display()
        )
    })?;
    if manifest.project.id != project.project_id {
        return Err(anyhow!(
            "scene-only mutation project id mismatch; expected {}, found {}",
            project.project_id,
            manifest.project.id
        ));
    }
    let manifest_hash = hash_project_manifest_file(manifest_path)?;
    if manifest_hash != project.manifest_hash {
        return Err(anyhow!(
            "scene-only mutation project manifest hash mismatch; expected {}, found {}",
            project.manifest_hash.value,
            manifest_hash.value
        ));
    }
    let project_root = manifest_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or_else(|| Path::new("."));
    let declared_scene = manifest
        .scenes
        .iter()
        .find(|scene| scene.path == project.scene_path)
        .ok_or_else(|| {
            anyhow!(
                "scene-only mutation target scene {} is not declared in project manifest scenes",
                project.scene_path
            )
        })?;
    let declared_scene_path = project_root.join(&declared_scene.path);
    let declared_scene_canonical = declared_scene_path.canonicalize().with_context(|| {
        format!(
            "failed to resolve project scene {}",
            declared_scene_path.display()
        )
    })?;
    let target_scene_path = Path::new(&operation.target_scene_path);
    let target_scene_canonical = target_scene_path.canonicalize().with_context(|| {
        format!(
            "failed to resolve scene-only mutation targetScenePath {}",
            target_scene_path.display()
        )
    })?;
    if target_scene_canonical != declared_scene_canonical {
        return Err(anyhow!(
            "scene-only mutation targetScenePath {} is not the manifest-authorized project scene {}",
            operation.target_scene_path,
            project.scene_path
        ));
    }
    if &project.scene_hash != before_scene_hash {
        return Err(anyhow!(
            "scene-only mutation project scene hash mismatch; expected {}, found {}",
            project.scene_hash.value,
            before_scene_hash.value
        ));
    }
    if &operation.expected_before_scene_hash != before_scene_hash {
        return Err(anyhow!(
            "scene-only mutation before hash mismatch; expected {}, found {}",
            operation.expected_before_scene_hash.value,
            before_scene_hash.value
        ));
    }
    Ok(Some(project.clone()))
}

pub fn validate_scene_only_mutation_operation(
    run_dir: impl AsRef<Path>,
    operation: &SceneOnlyMutationOperation,
) -> Result<SceneOnlyMutationValidation> {
    let run_dir = run_dir.as_ref();
    if operation.schema_version != "scene-only-mutation-v1" {
        return Err(anyhow!(
            "scene-only mutation schemaVersion must be scene-only-mutation-v1"
        ));
    }
    if !operation.validation_required {
        return Err(anyhow!(
            "scene-only mutation requires validationRequired=true"
        ));
    }
    require_text("scene-only mutation proposalId", &operation.proposal_id)?;
    require_text(
        "scene-only mutation targetScenePath",
        &operation.target_scene_path,
    )?;
    if !supported_scene_edit_paths().contains(&operation.edit.path.as_str()) {
        return Err(anyhow!(
            "scene-only mutation edit path is not allowed: {}",
            operation.edit.path
        ));
    }
    let proposals = read_mutation_proposals(run_dir)?;
    let proposal = proposals
        .proposals
        .iter()
        .find(|proposal| proposal.id == operation.proposal_id)
        .ok_or_else(|| {
            anyhow!(
                "scene-only mutation proposal id not found: {}",
                operation.proposal_id
            )
        })?;
    if proposal.status != "proposed" {
        return Err(anyhow!(
            "scene-only mutation requires a proposed mutation; found status {}",
            proposal.status
        ));
    }
    let scene = read_scene(&operation.target_scene_path)?;
    let before_scene_hash = hash_scene_document(&scene)?;
    let project = validate_project_scene_mutation_context(operation, &before_scene_hash)?;
    let review_decision_id = validate_review_gated_scene_apply_decision(run_dir, operation)?;
    if before_scene_hash != operation.expected_before_scene_hash {
        return Err(anyhow!(
            "scene-only mutation before hash mismatch; expected {}, found {}",
            operation.expected_before_scene_hash.value,
            before_scene_hash.value
        ));
    }
    let mut candidate_scene = scene.clone();
    apply_scene_edit(&mut candidate_scene, operation.edit.clone())?;
    validate_scene(&candidate_scene).context("scene-only mutation candidate validation failed")?;
    Ok(SceneOnlyMutationValidation {
        status: "passed".to_string(),
        proposal_id: operation.proposal_id.clone(),
        target_scene_path: operation.target_scene_path.clone(),
        before_scene_hash,
        allowed_path: true,
        review_decision_id,
        project,
    })
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "kebab-case")]
pub enum SourceFileClassDecision {
    Allowed,
    NeedsApproval,
    Blocked,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "kebab-case")]
pub enum SourceFileClassLabel {
    DeterministicSceneFixture,
    ScenarioRegressionFixture,
    RuntimeDemoConfig,
    DeterministicSourceLikeTemplate,
    DocumentationGovernance,
    RustTrustBoundary,
    TestsEvidenceReader,
    BrowserStudioDisplay,
    DependencyManifest,
    CiWorkflowSecrets,
    BuildScriptTooling,
    AuthNetworkCloud,
    PluginExtension,
    NativeExportPackaging,
    GeneratedLocalState,
    BinaryOpaque,
    UnsafePath,
    Unknown,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct SourceFileClassReport {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    pub path: String,
    pub class: SourceFileClassLabel,
    pub decision: SourceFileClassDecision,
    #[serde(rename = "reviewLevel")]
    pub review_level: String,
    pub rationale: String,
    #[serde(rename = "blockedReasons")]
    pub blocked_reasons: Vec<String>,
    pub guardrails: Vec<String>,
}

impl SourceFileClassReport {
    pub fn is_blocked(&self) -> bool {
        self.decision == SourceFileClassDecision::Blocked
    }

    pub fn needs_approval(&self) -> bool {
        self.decision == SourceFileClassDecision::NeedsApproval
    }
}

pub fn classify_source_file_path(path: impl AsRef<Path>) -> SourceFileClassReport {
    classify_source_file_path_str(&path.as_ref().to_string_lossy())
}

pub fn classify_source_file_path_str(path: &str) -> SourceFileClassReport {
    let normalized = path.replace('\\', "/");
    let path_ref = Path::new(&normalized);
    let components: Vec<String> = path_ref
        .components()
        .filter_map(|component| match component {
            Component::Normal(value) => Some(value.to_string_lossy().to_string()),
            _ => None,
        })
        .collect();
    let lower_components: Vec<String> = components
        .iter()
        .map(|value| value.to_ascii_lowercase())
        .collect();
    let file_name = lower_components.last().map(String::as_str).unwrap_or("");
    let extension = path_ref
        .extension()
        .and_then(|value| value.to_str())
        .map(|value| value.to_ascii_lowercase());

    if normalized.trim().is_empty() {
        return source_class_report(
            normalized,
            SourceFileClassLabel::UnsafePath,
            SourceFileClassDecision::Blocked,
            "Reject by default",
            "empty source patch target path is unsafe",
            vec!["empty target path"],
        );
    }
    if path_ref.is_absolute()
        || path_ref.components().any(|component| {
            matches!(
                component,
                Component::ParentDir | Component::RootDir | Component::Prefix(_)
            )
        })
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::UnsafePath,
            SourceFileClassDecision::Blocked,
            "Reject by default",
            "source patch target path must be repository-relative and traversal-free",
            vec!["absolute, rooted, prefixed, or parent-dir path"],
        );
    }
    // Check the raw separator-split segments rather than the collected
    // `Path::components()`: `Component::Normal` filtering already drops empty
    // segments produced by repeated separators (e.g. `examples//scenes/foo`),
    // so an emptiness check on `components` can never fire. Reject any empty
    // raw segment so repeated/leading/trailing separators stay unsafe-path.
    if normalized.split('/').any(|segment| segment.is_empty()) {
        return source_class_report(
            normalized,
            SourceFileClassLabel::UnsafePath,
            SourceFileClassDecision::Blocked,
            "Reject by default",
            "source patch target path contains an empty component",
            vec!["empty path component"],
        );
    }
    if let Some(root) = lower_components.first() {
        if source_file_generated_roots().contains(&root.as_str())
            || normalized == "examples/evidence-dashboard/dashboard-data.json"
        {
            return source_class_report(
                normalized,
                SourceFileClassLabel::GeneratedLocalState,
                SourceFileClassDecision::Blocked,
                "Reject by default",
                "ignored local/generated state is not source patch input",
                vec![format!("generated or local root {root}")],
            );
        }
        if root.starts_with('.') && root != ".github" {
            return source_class_report(
                normalized,
                SourceFileClassLabel::UnsafePath,
                SourceFileClassDecision::Blocked,
                "Reject by default",
                "hidden repository roots are not eligible for source patch preview",
                vec![format!("hidden root {root}")],
            );
        }
    }
    if lower_components
        .iter()
        .skip(1)
        .any(|component| component.starts_with('.'))
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::UnsafePath,
            SourceFileClassDecision::Blocked,
            "Reject by default",
            "hidden nested path components are ambiguous for source patch preview",
            vec!["hidden nested path component"],
        );
    }
    if lower_components.first().map(String::as_str) == Some(".github") {
        return source_class_report(
            normalized,
            SourceFileClassLabel::CiWorkflowSecrets,
            SourceFileClassDecision::Blocked,
            "Separate governance approval",
            "CI/workflow and secrets-adjacent config can change automation authority",
            vec!["ci, workflow, or secrets configuration"],
        );
    }
    if source_file_dependency_manifest_names().contains(&file_name) {
        return source_class_report(
            normalized,
            SourceFileClassLabel::DependencyManifest,
            SourceFileClassDecision::Blocked,
            "Separate governance approval",
            "dependency manifests and lockfiles require supply-chain review",
            vec!["dependency manifest or lockfile"],
        );
    }
    if file_name == "build.rs"
        || matches!(
            extension.as_deref(),
            Some("sh" | "bash" | "zsh" | "ps1" | "bat" | "cmd")
        )
        || lower_components
            .iter()
            .any(|component| component == "scripts")
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::BuildScriptTooling,
            SourceFileClassDecision::Blocked,
            "Separate governance approval",
            "build scripts and host-executed tooling can execute local commands",
            vec!["build script, shell script, or host-executed tooling"],
        );
    }
    if lower_components.iter().any(|component| {
        matches!(
            component.as_str(),
            "auth" | "oauth" | "server" | "servers" | "cloud" | "network" | "net" | "deploy"
        )
    }) {
        return source_class_report(
            normalized,
            SourceFileClassLabel::AuthNetworkCloud,
            SourceFileClassDecision::Blocked,
            "Separate governance approval",
            "auth/network/cloud/server code is outside the local-first preview boundary",
            vec!["auth, network, cloud, deploy, or server path"],
        );
    }
    if lower_components.iter().any(|component| {
        matches!(
            component.as_str(),
            "plugin" | "plugins" | "marketplace" | "extension" | "extensions"
        )
    }) && lower_components.first().map(String::as_str) != Some("docs")
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::PluginExtension,
            SourceFileClassDecision::Blocked,
            "Separate governance approval",
            "plugin or dynamic extension code expands execution authority",
            vec!["plugin, marketplace, or extension runtime path"],
        );
    }
    if lower_components.iter().any(|component| {
        matches!(
            component.as_str(),
            "native" | "export" | "exports" | "packaging" | "release" | "releases" | "dist"
        )
    }) && lower_components.first().map(String::as_str) != Some("docs")
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::NativeExportPackaging,
            SourceFileClassDecision::Blocked,
            "Separate governance approval",
            "native export, packaging, and release code is out of preview scope",
            vec!["native export, packaging, release, or distribution path"],
        );
    }
    if matches!(
        extension.as_deref(),
        Some(
            "png"
                | "jpg"
                | "jpeg"
                | "gif"
                | "webp"
                | "ico"
                | "wasm"
                | "bin"
                | "zip"
                | "gz"
                | "tar"
                | "mp3"
                | "ogg"
                | "wav"
                | "ttf"
                | "otf"
                | "woff"
                | "woff2"
        )
    ) {
        return source_class_report(
            normalized,
            SourceFileClassLabel::BinaryOpaque,
            SourceFileClassDecision::Blocked,
            "Reject by default",
            "binary or opaque generated assets are not reviewer-visible source patch targets",
            vec!["binary or opaque file extension"],
        );
    }
    if lower_components
        .iter()
        .any(|component| component == "tests")
        || file_name.ends_with(".test.cjs")
        || file_name.ends_with("_test.rs")
        || file_name.ends_with(".spec.js")
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::TestsEvidenceReader,
            SourceFileClassDecision::NeedsApproval,
            "Elevated behavior review",
            "tests and evidence readers can hide failures or spoof confidence",
            Vec::<String>::new(),
        );
    }
    if lower_components.first().map(String::as_str) == Some("crates") {
        return source_class_report(
            normalized,
            SourceFileClassLabel::RustTrustBoundary,
            SourceFileClassDecision::NeedsApproval,
            "Separate governance approval",
            "Rust trust-boundary code owns validation, persistence, and artifact writes",
            Vec::<String>::new(),
        );
    }
    if lower_components.first().map(String::as_str) == Some("docs")
        || file_name == "readme.md"
        || file_name == "agents.md"
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::DocumentationGovernance,
            SourceFileClassDecision::NeedsApproval,
            "Standard design review",
            "documentation and governance wording can alter roadmap or public claims",
            Vec::<String>::new(),
        );
    }
    if lower_components.first().map(String::as_str) == Some("examples")
        && lower_components.get(1).is_some_and(|component| {
            matches!(
                component.as_str(),
                "evidence-dashboard" | "authoring-cockpit"
            )
        })
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::BrowserStudioDisplay,
            SourceFileClassDecision::NeedsApproval,
            "Elevated behavior review",
            "browser/dashboard/Studio display code must remain read-only and command-inert",
            Vec::<String>::new(),
        );
    }
    if lower_components.first().map(String::as_str) == Some("seeds")
        && matches!(extension.as_deref(), Some("yaml" | "yml"))
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::DeterministicSceneFixture,
            SourceFileClassDecision::Allowed,
            "Elevated source-like data review",
            "deterministic seed fixtures may be previewed later with stale-target and rollback controls",
            Vec::<String>::new(),
        );
    }
    if lower_components.first().map(String::as_str) == Some("examples")
        && (file_name.contains("scenario") || file_name.contains("regression"))
        && matches!(extension.as_deref(), Some("json" | "yaml" | "yml" | "md"))
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::ScenarioRegressionFixture,
            SourceFileClassDecision::Allowed,
            "Elevated source-like data review",
            "scenario and deterministic regression fixtures are source-like data",
            Vec::<String>::new(),
        );
    }
    if lower_components.first().map(String::as_str) == Some("examples")
        && (file_name.ends_with(".scene.json")
            || file_name == "scene.json"
            || file_name == "manifest.json"
            || normalized.contains("/scenes/")
            || normalized.contains("/assets/"))
        && matches!(
            extension.as_deref(),
            Some("json" | "yaml" | "yml" | "md" | "toml")
        )
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::RuntimeDemoConfig,
            SourceFileClassDecision::Allowed,
            "Elevated source-like data review",
            "bounded local demo configuration may be previewed later as data, not executable authority",
            Vec::<String>::new(),
        );
    }
    if lower_components
        .iter()
        .any(|component| component == "templates")
        && matches!(
            extension.as_deref(),
            Some("json" | "yaml" | "yml" | "md" | "txt")
        )
    {
        return source_class_report(
            normalized,
            SourceFileClassLabel::DeterministicSourceLikeTemplate,
            SourceFileClassDecision::Allowed,
            "Elevated source-like data review",
            "deterministic promoted templates may be previewed only with provenance",
            Vec::<String>::new(),
        );
    }
    source_class_report(
        normalized,
        SourceFileClassLabel::Unknown,
        SourceFileClassDecision::Blocked,
        "Reject by default",
        "unclassified source patch targets default to reject/hold",
        vec!["unknown file class"],
    )
}

fn source_class_report(
    path: String,
    class: SourceFileClassLabel,
    decision: SourceFileClassDecision,
    review_level: &str,
    rationale: &str,
    blocked_reasons: Vec<impl Into<String>>,
) -> SourceFileClassReport {
    SourceFileClassReport {
        schema_version: "source-file-class-v1".to_string(),
        path,
        class,
        decision,
        review_level: review_level.to_string(),
        rationale: rationale.to_string(),
        blocked_reasons: blocked_reasons.into_iter().map(Into::into).collect(),
        guardrails: vec![
            "preview classification only; no source patch apply".to_string(),
            "no merge, auto-merge, auto-apply, or hidden command execution".to_string(),
            "generated/local state remains untracked unless explicitly fixture-scoped".to_string(),
            "#1 and #23 remain open".to_string(),
        ],
    }
}

fn source_file_generated_roots() -> &'static [&'static str] {
    &[
        "runs",
        "sandbox",
        "target",
        "dashboard-data",
        ".omx",
        ".openchrome",
        ".omc",
        ".claude",
    ]
}

fn source_file_dependency_manifest_names() -> &'static [&'static str] {
    &[
        "cargo.toml",
        "cargo.lock",
        "package.json",
        "package-lock.json",
        "pnpm-lock.yaml",
        "yarn.lock",
        "npm-shrinkwrap.json",
    ]
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct SourcePatchTargetClassValidation {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    pub status: String,
    pub targets: Vec<SourceFileClassReport>,
    #[serde(rename = "blockedReasons")]
    pub blocked_reasons: Vec<String>,
    pub guardrails: Vec<String>,
}

impl SourcePatchTargetClassValidation {
    pub fn has_blocked_targets(&self) -> bool {
        self.targets.iter().any(SourceFileClassReport::is_blocked)
    }
}

pub fn classify_source_patch_preview_targets<I, P>(paths: I) -> SourcePatchTargetClassValidation
where
    I: IntoIterator<Item = P>,
    P: AsRef<Path>,
{
    let targets: Vec<SourceFileClassReport> =
        paths.into_iter().map(classify_source_file_path).collect();
    source_patch_target_class_validation(targets)
}

pub fn validate_source_patch_preview_targets<I, P>(
    paths: I,
) -> Result<SourcePatchTargetClassValidation>
where
    I: IntoIterator<Item = P>,
    P: AsRef<Path>,
{
    let validation = classify_source_patch_preview_targets(paths);
    if validation.has_blocked_targets() {
        return Err(anyhow!(
            "source patch preview target class validation blocked: {}",
            validation.blocked_reasons.join("; ")
        ));
    }
    Ok(validation)
}

fn source_patch_target_class_validation(
    targets: Vec<SourceFileClassReport>,
) -> SourcePatchTargetClassValidation {
    let blocked_reasons: Vec<String> = targets
        .iter()
        .filter(|target| target.is_blocked())
        .flat_map(|target| {
            let path = target.path.clone();
            let class = serde_json::to_value(&target.class)
                .ok()
                .and_then(|value| value.as_str().map(ToOwned::to_owned))
                .unwrap_or_else(|| "unknown".to_string());
            target
                .blocked_reasons
                .iter()
                .map(move |reason| format!("{} ({class}): {reason}", path))
        })
        .collect();
    SourcePatchTargetClassValidation {
        schema_version: "source-patch-target-class-validation-v1".to_string(),
        status: if blocked_reasons.is_empty() {
            "passed".to_string()
        } else {
            "blocked".to_string()
        },
        targets,
        blocked_reasons,
        guardrails: vec![
            "target class validation only; no diff evaluation or patch preview artifact"
                .to_string(),
            "blocked classes stop before sandbox dry-run or trusted source writes".to_string(),
            "source patch apply and merge automation remain unimplemented".to_string(),
            "browser/dashboard/Studio surfaces remain read-only and command-inert".to_string(),
        ],
    }
}

