    #[test]
    fn asset_preview_evidence_model_accepts_preview_metadata_and_warnings() {
        let evidence = AssetPreviewEvidence::from_json_str(
            &json!({
                "schemaVersion": "asset-preview-evidence-v1",
                "runId": "run_1",
                "manifestId": "asset_manifest",
                "generatedAtUnixMs": 1000,
                "boundary": "Read-only local preview evidence; no browser writes or remote hosting.",
                "previews": [
                    {
                        "assetId": "player_sprite",
                        "assetType": "image",
                        "sourcePath": "assets/sprites/player.png",
                        "previewKind": "thumbnail",
                        "previewPath": "runs/run_1/previews/player.png",
                        "previewClassification": "generated",
                        "image": { "width": 16, "height": 16 }
                    },
                    {
                        "assetId": "player_atlas",
                        "assetType": "sprite_atlas",
                        "sourcePath": "assets/atlases/player.atlas.json",
                        "previewKind": "metadata",
                        "atlasFrames": [
                            { "frameId": "idle_0", "rect": { "x": 0, "y": 0, "width": 16, "height": 16 } }
                        ]
                    },
                    {
                        "assetId": "level_tilemap",
                        "assetType": "tilemap",
                        "sourcePath": "assets/tilemaps/level.json",
                        "previewKind": "metadata",
                        "tilemap": { "tilesetAssetId": "terrain_tiles", "width": 20, "height": 12, "layerCount": 2, "tileCount": 240 }
                    },
                    {
                        "assetId": "jump_sound",
                        "assetType": "audio",
                        "sourcePath": "assets/audio/jump.ogg",
                        "previewKind": "metadata",
                        "audio": { "durationMs": 350, "channels": 2 }
                    },
                    {
                        "assetId": "ui_font",
                        "assetType": "font",
                        "sourcePath": "assets/fonts/ui.woff2",
                        "previewKind": "reference",
                        "font": { "family": "UI Sans", "style": "Regular" },
                        "warnings": [{ "assetId": "ui_font", "kind": "metadata_missing", "message": "Font metrics are not available yet." }]
                    }
                ],
                "warnings": [{ "kind": "missing_preview", "message": "One optional preview was skipped.", "path": "assets/fonts/ui.woff2" }]
            })
            .to_string(),
        )
        .expect("asset preview evidence parses");

        assert_eq!(evidence.manifest_id, "asset_manifest");
        assert_eq!(evidence.previews.len(), 5);
        assert_eq!(evidence.previews[1].atlas_frames[0].frame_id, "idle_0");
        assert_eq!(
            evidence.previews[2].tilemap.as_ref().unwrap().tile_count,
            240
        );
        assert_eq!(
            evidence.previews[3].audio.as_ref().unwrap().channels,
            Some(2)
        );
        assert_eq!(
            evidence.previews[4]
                .font
                .as_ref()
                .unwrap()
                .family
                .as_deref(),
            Some("UI Sans")
        );
        assert_eq!(evidence.warnings[0].kind, "missing_preview");
    }

    #[test]
    fn asset_preview_evidence_model_rejects_unsafe_or_silent_records() {
        let base = |preview: serde_json::Value| {
            json!({
                "schemaVersion": "asset-preview-evidence-v1",
                "manifestId": "asset_manifest",
                "generatedAtUnixMs": 1000,
                "boundary": "Read-only local preview evidence.",
                "previews": [preview]
            })
            .to_string()
        };

        let unsafe_source = AssetPreviewEvidence::from_json_str(&base(json!({
            "assetId": "remote_sprite",
            "assetType": "image",
            "sourcePath": "https://example.com/player.png",
            "previewKind": "thumbnail"
        })));
        assert!(unsafe_source.is_err());

        let source_like_generated_preview = AssetPreviewEvidence::from_json_str(&base(json!({
            "assetId": "player_sprite",
            "assetType": "image",
            "sourcePath": "assets/sprites/player.png",
            "previewKind": "thumbnail",
            "previewPath": "runs/run_1/previews/player.png",
            "previewClassification": "source_like"
        })));
        assert!(source_like_generated_preview.is_err());

        let zero_dimension = AssetPreviewEvidence::from_json_str(&base(json!({
            "assetId": "player_sprite",
            "assetType": "image",
            "sourcePath": "assets/sprites/player.png",
            "previewKind": "thumbnail",
            "image": { "width": 0, "height": 16 }
        })));
        assert!(zero_dimension.is_err());

        let duplicate_assets = AssetPreviewEvidence::from_json_str(
            &json!({
                "schemaVersion": "asset-preview-evidence-v1",
                "manifestId": "asset_manifest",
                "generatedAtUnixMs": 1000,
                "boundary": "Read-only local preview evidence.",
                "previews": [
                    { "assetId": "player_sprite", "assetType": "image", "sourcePath": "assets/sprites/player.png", "previewKind": "thumbnail" },
                    { "assetId": "player_sprite", "assetType": "image", "sourcePath": "assets/sprites/player.png", "previewKind": "reference" }
                ]
            })
            .to_string(),
        );
        assert!(duplicate_assets.is_err());

        let empty = AssetPreviewEvidence::from_json_str(
            &json!({
                "schemaVersion": "asset-preview-evidence-v1",
                "manifestId": "asset_manifest",
                "generatedAtUnixMs": 1000,
                "boundary": "Read-only local preview evidence.",
                "previews": []
            })
            .to_string(),
        );
        assert!(empty.is_err());
    }

    #[test]
    fn dashboard_asset_inspector_combines_preview_integrity_and_loading() {
        let integrity = RunDashboardAssetIntegrity {
            present: true,
            empty_state: String::new(),
            warning_count: 1,
            stale_hash_count: 1,
            missing_ref_count: 0,
            invalid_type_count: 0,
            evidence_refs: vec!["evidence/assets/integrity.json".to_string()],
            warnings: vec![ProjectAssetReferenceIntegrityWarning {
                field: "scene sprite".to_string(),
                asset_id: "player_sprite".to_string(),
                kind: "stale_asset_hash".to_string(),
                message: "hash mismatch".to_string(),
                expected_types: vec![ProjectAssetType::Image],
                observed_type: Some(ProjectAssetType::Image),
                path: Some("assets/sprites/player.png".to_string()),
            }],
            artifacts: Vec::new(),
        };
        let loading = RunDashboardAssetLoading {
            present: true,
            empty_state: String::new(),
            attempt_count: 2,
            loaded_count: 1,
            failed_count: 1,
            rejected_count: 0,
            fallback_count: 0,
            evidence_refs: vec!["evidence/assets/load.json".to_string()],
            records: vec![RuntimeAssetLoadRecord {
                attempt_id: "load-player".to_string(),
                asset_id: "player_sprite".to_string(),
                asset_type: ProjectAssetType::Image,
                path: Some("assets/sprites/player.png".to_string()),
                status: RuntimeAssetLoadStatus::Loaded,
                started_at_unix_ms: 1,
                ended_at_unix_ms: Some(2),
                load_duration_ms: Some(1),
                width: Some(16),
                height: Some(16),
                media_duration_ms: None,
                failure_reason: None,
            }],
            artifacts: Vec::new(),
            boundary: "loading boundary".to_string(),
        };
        let preview = RunDashboardAssetPreview {
            present: true,
            empty_state: String::new(),
            preview_count: 1,
            warning_count: 0,
            image_count: 1,
            atlas_frame_count: 2,
            tilemap_count: 0,
            audio_count: 0,
            font_count: 0,
            evidence_refs: vec!["evidence/assets/preview.json".to_string()],
            records: vec![AssetPreviewRecord {
                asset_id: "player_sprite".to_string(),
                asset_type: ProjectAssetType::Image,
                source_path: "assets/sprites/player.png".to_string(),
                preview_kind: AssetPreviewKind::Thumbnail,
                preview_path: None,
                preview_classification: None,
                image: Some(AssetPreviewImageMetadata {
                    width: 16,
                    height: 16,
                }),
                atlas_frames: Vec::new(),
                tilemap: None,
                audio: None,
                font: None,
                warnings: Vec::new(),
            }],
            warnings: Vec::new(),
            artifacts: Vec::new(),
            boundary: "preview boundary".to_string(),
        };

        let inspector = dashboard_asset_inspector(&integrity, &loading, &preview);
        assert!(inspector.present);
        assert_eq!(inspector.status, "warnings");
        assert_eq!(inspector.asset_count, 1);
        assert_eq!(inspector.warning_count, 1);
        assert_eq!(inspector.runtime_attempt_count, 2);
        assert_eq!(inspector.preview_count, 1);
        assert_eq!(inspector.atlas_frame_count, 2);
        assert_eq!(inspector.evidence_refs.len(), 3);
        assert_eq!(inspector.assets[0].asset_id, "player_sprite");
        assert_eq!(
            inspector.assets[0].runtime_statuses,
            vec!["Loaded".to_string()]
        );
        assert!(inspector.assets[0].warnings[0].contains("stale_asset_hash"));
        assert!(inspector.boundary.contains("must not upload"));
    }

    #[test]
    fn generate_asset_preview_evidence_exports_manifest_metadata_and_warnings() {
        let root = unique_temp_dir("asset-preview-generation");
        fs::create_dir_all(root.join("assets/sprites")).expect("sprite dir");
        fs::create_dir_all(root.join("assets/atlases")).expect("atlas dir");
        fs::create_dir_all(root.join("assets/tilemaps")).expect("tilemap dir");
        let sprite_path = root.join("assets/sprites/player.png");
        let atlas_path = root.join("assets/atlases/player.atlas.json");
        let tilemap_path = root.join("assets/tilemaps/level.json");
        fs::write(&sprite_path, b"deterministic sprite").expect("sprite written");
        fs::write(&atlas_path, br#"{"frames":["idle_0"]}"#).expect("atlas written");
        fs::write(&tilemap_path, br#"{"layers":["terrain"]}"#).expect("tilemap written");
        let sprite_hash = hash_project_asset_file(&sprite_path).expect("sprite hash");
        let atlas_hash = hash_project_asset_file(&atlas_path).expect("atlas hash");
        let tilemap_hash = hash_project_asset_file(&tilemap_path).expect("tilemap hash");
        let manifest = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "preview_manifest",
                "assets": [
                    {
                        "id": "player_sprite",
                        "type": "image",
                        "path": "assets/sprites/player.png",
                        "contentHash": sprite_hash,
                        "classification": "source_like",
                        "dimensions": { "width": 16, "height": 16 }
                    },
                    {
                        "id": "player_atlas",
                        "type": "sprite_atlas",
                        "path": "assets/atlases/player.atlas.json",
                        "contentHash": atlas_hash,
                        "classification": "source_like",
                        "atlas": {
                            "imageAssetId": "player_sprite",
                            "frames": [{ "id": "idle_0", "rect": { "x": 0, "y": 0, "width": 16, "height": 16 } }]
                        }
                    },
                    {
                        "id": "level_tilemap",
                        "type": "tilemap",
                        "path": "assets/tilemaps/level.json",
                        "contentHash": tilemap_hash,
                        "classification": "source_like",
                        "tilemap": {
                            "tilesetAssetId": "terrain_tiles",
                            "width": 2,
                            "height": 2,
                            "layers": [{ "id": "terrain", "kind": "visual", "data": ["solid", null, "solid", null] }]
                        }
                    },
                    {
                        "id": "missing_audio",
                        "type": "audio",
                        "path": "assets/audio/missing.ogg",
                        "contentHash": { "algorithm": "fnv1a64-file-v1", "value": "0000000000000000" },
                        "classification": "source_like",
                        "durationMs": 250,
                        "metadata": { "channels": "2" }
                    }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");

        let evidence =
            generate_asset_preview_evidence(&manifest, &root, Some("run_1".to_string()), 1234)
                .expect("preview evidence generated");

        assert_eq!(evidence.schema_version, "asset-preview-evidence-v1");
        assert_eq!(evidence.manifest_id, "preview_manifest");
        assert_eq!(evidence.previews.len(), 4);
        assert_eq!(
            evidence.previews[0].preview_kind,
            AssetPreviewKind::Thumbnail
        );
        assert_eq!(evidence.previews[0].image.as_ref().unwrap().width, 16);
        assert_eq!(evidence.previews[1].atlas_frames[0].frame_id, "idle_0");
        assert_eq!(evidence.previews[2].tilemap.as_ref().unwrap().tile_count, 2);
        assert_eq!(
            evidence.previews[3].audio.as_ref().unwrap().channels,
            Some(2)
        );
        assert_eq!(evidence.warnings.len(), 1);
        assert_eq!(
            evidence.warnings[0].asset_id.as_deref(),
            Some("missing_audio")
        );
        assert_eq!(evidence.warnings[0].kind, "missing_asset_file");

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn route_attempt_evidence_accepts_success_fixture_and_outcomes() {
        let fixture = include_str!(
            "../../../examples/route-attempt-evidence-v1/route-attempt-success.sample.json"
        );
        let attempt = RouteAttemptEvidenceArtifact::from_json_str(fixture)
            .expect("route attempt fixture parses");

        assert_eq!(attempt.schema_version, "route-attempt-evidence-v1");
        assert_eq!(attempt.objective_id, "collect-goal-then-exit");
        assert_eq!(
            attempt.strategy_kind,
            RouteAttemptStrategyKind::SimpleHeuristic
        );
        assert_eq!(attempt.outcome, RouteAttemptOutcome::Passed);
        assert_eq!(attempt.action_sequence.len(), 2);
        assert_eq!(attempt.route.len(), 2);
        assert!(attempt
            .guardrails
            .iter()
            .any(|guardrail| guardrail.contains("not proof of global objective solvability")));
    }

    #[test]
    fn route_attempt_evidence_rejects_blocked_unsupported_and_malformed_shapes() {
        let blocked = include_str!(
            "../../../examples/route-attempt-evidence-v1/invalid/blocked-route-attempt.json"
        );
        let error = RouteAttemptEvidenceArtifact::from_json_str(blocked)
            .expect_err("blocked route attempts require blockers");
        assert!(error.to_string().contains("blockers"));

        let unsupported = include_str!(
            "../../../examples/route-attempt-evidence-v1/invalid/unsupported-route-attempt.json"
        );
        let error = RouteAttemptEvidenceArtifact::from_json_str(unsupported)
            .expect_err("unsupported route attempts require reason");
        assert!(error.to_string().contains("unsupportedReason"));

        let malformed = include_str!(
            "../../../examples/route-attempt-evidence-v1/invalid/malformed-route-attempt.json"
        );
        let error = RouteAttemptEvidenceArtifact::from_json_str(malformed)
            .expect_err("malformed route attempts are rejected");
        assert!(
            error.to_string().contains("route")
                || error.to_string().contains("evidenceRefs")
                || error.to_string().contains("budgetUsed")
        );
    }

    #[test]
    fn route_attempt_evidence_rejects_unbounded_budget_and_invalid_action_sequences() {
        let mut attempt = RouteAttemptEvidenceArtifact::from_json_str(include_str!(
            "../../../examples/route-attempt-evidence-v1/route-attempt-success.sample.json"
        ))
        .expect("success fixture parses");

        attempt.budget_used.max_actions = MAX_ROUTE_ATTEMPT_ACTIONS + 1;
        let error = attempt
            .validate()
            .expect_err("unbounded action budget rejected");
        assert!(error.to_string().contains("maxActions"));

        let mut attempt = RouteAttemptEvidenceArtifact::from_json_str(include_str!(
            "../../../examples/route-attempt-evidence-v1/route-attempt-success.sample.json"
        ))
        .expect("success fixture parses");
        attempt.action_sequence[0].frame = Some(12);
        attempt.action_sequence[1].frame = Some(1);
        let error = attempt
            .validate()
            .expect_err("nondecreasing action frames are required");
        assert!(error.to_string().contains("nondecreasing"));

        let mut graph = RouteAttemptEvidenceArtifact::from_json_str(include_str!(
            "../../../examples/route-attempt-evidence-v1/route-attempt-success.sample.json"
        ))
        .expect("success fixture parses");
        graph.strategy_kind = RouteAttemptStrategyKind::GraphSearch;
        let error = graph
            .validate()
            .expect_err("graph search cannot silently pass unsupported interact mechanics");
        assert!(error.to_string().contains("unsupported mechanics"));
    }

    #[test]
    fn route_attempt_evidence_ref_validation_accepts_indexed_refs_and_blocks_stale_state() {
        let (root, artifacts) = create_test_run("route-attempt-refs");
        let mut attempt = RouteAttemptEvidenceArtifact::from_json_str(include_str!(
            "../../../examples/route-attempt-evidence-v1/route-attempt-success.sample.json"
        ))
        .expect("success fixture parses");
        let run = read_json_value(artifacts.run_dir.join("run.json")).expect("run reads");
        attempt.run_id = json_string(&run, "id").expect("run id present");

        let mut refs = vec![attempt.start_state.world_state_ref.clone()];
        refs.extend(attempt.evidence_refs.clone());
        refs.extend(
            attempt
                .route
                .iter()
                .filter_map(|node| node.evidence_ref.clone()),
        );
        refs.sort();
        refs.dedup();
        for reference in &refs {
            fs::create_dir_all(
                artifacts
                    .run_dir
                    .join(Path::new(reference).parent().expect("reference has parent")),
            )
            .expect("reference parent exists");
            let state_id = if reference == &attempt.start_state.world_state_ref {
                Some(attempt.start_state.state_id.as_str())
            } else {
                None
            };
            let mut value = json!({
                "runId": attempt.run_id,
                "scenarioId": attempt.scenario_id,
                "objectiveId": attempt.objective_id,
                "artifact": "route_attempt_link_fixture"
            });
            if let Some(state_id) = state_id {
                value["stateId"] = json!(state_id);
            }
            write_json(&artifacts.run_dir.join(reference), &value).expect("route reference writes");
            add_evidence_artifact(
                &artifacts.run_dir,
                &format!("route-link-{}", reference.replace('/', "-")),
                "application/json",
                reference,
                json!({ "artifact": "route_attempt_link_fixture" }),
            )
            .expect("route reference indexed");
        }

        validate_route_attempt_evidence_refs(&artifacts.run_dir, &attempt)
            .expect("fresh indexed refs validate");

        write_json(
            &artifacts.run_dir.join(&attempt.start_state.world_state_ref),
            &json!({
                "runId": attempt.run_id,
                "scenarioId": attempt.scenario_id,
                "objectiveId": attempt.objective_id,
                "stateId": "stale-start",
                "artifact": "route_attempt_link_fixture"
            }),
        )
        .expect("stale start writes");
        let stale = validate_route_attempt_evidence_refs(&artifacts.run_dir, &attempt)
            .expect_err("stale start state rejected");
        assert!(stale.to_string().contains("startState is stale"));

        attempt.objective_id = "missing-objective".to_string();
        write_json(
            &artifacts.run_dir.join(&attempt.start_state.world_state_ref),
            &json!({
                "runId": attempt.run_id,
                "scenarioId": attempt.scenario_id,
                "objectiveId": "different-objective",
                "stateId": attempt.start_state.state_id,
                "artifact": "route_attempt_link_fixture"
            }),
        )
        .expect("objective drift writes");
        let missing_objective = validate_route_attempt_evidence_refs(&artifacts.run_dir, &attempt)
            .expect_err("objective evidence is required");
        assert!(missing_objective.to_string().contains("objectiveId"));

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn route_attempt_dashboard_read_model_links_route_objective_and_world_state_evidence() {
        let (missing_root, missing_artifacts) = create_test_run("route-attempt-dashboard-missing");
        let missing = read_dashboard_run(&missing_artifacts.run_dir).expect("dashboard reads");
        assert!(!missing.route_attempts.present);
        assert_eq!(missing.route_attempts.status, "missing");
        fs::remove_dir_all(missing_root).expect("missing fixture removed");

        let (root, artifacts) = create_test_run("route-attempt-dashboard-present");
        let mut attempt = RouteAttemptEvidenceArtifact::from_json_str(include_str!(
            "../../../examples/route-attempt-evidence-v1/route-attempt-success.sample.json"
        ))
        .expect("success fixture parses");
        let run = read_json_value(artifacts.run_dir.join("run.json")).expect("run reads");
        attempt.run_id = json_string(&run, "id").expect("run id present");

        let mut refs = vec![attempt.start_state.world_state_ref.clone()];
        refs.extend(attempt.evidence_refs.clone());
        refs.extend(
            attempt
                .route
                .iter()
                .filter_map(|node| node.evidence_ref.clone()),
        );
        refs.sort();
        refs.dedup();
        for reference in &refs {
            fs::create_dir_all(
                artifacts
                    .run_dir
                    .join(Path::new(reference).parent().expect("reference has parent")),
            )
            .expect("reference parent exists");
            let mut value = json!({
                "runId": attempt.run_id,
                "scenarioId": attempt.scenario_id,
                "objectiveId": attempt.objective_id,
                "artifact": "route_attempt_link_fixture"
            });
            if reference == &attempt.start_state.world_state_ref {
                value["stateId"] = json!(attempt.start_state.state_id);
            }
            write_json(&artifacts.run_dir.join(reference), &value).expect("route reference writes");
            add_evidence_artifact(
                &artifacts.run_dir,
                &format!("route-dashboard-link-{}", reference.replace('/', "-")),
                "application/json",
                reference,
                json!({ "artifact": "route_attempt_link_fixture" }),
            )
            .expect("route reference indexed");
        }

        let route_path = "evidence/route-attempts/route-attempt.json";
        fs::create_dir_all(artifacts.run_dir.join("evidence/route-attempts"))
            .expect("route attempt evidence dir exists");
        write_json(&artifacts.run_dir.join(route_path), &json!(attempt))
            .expect("route attempt writes");
        add_evidence_artifact(
            &artifacts.run_dir,
            "route-attempt-evidence",
            "application/json",
            route_path,
            json!({ "artifact": "route_attempt_evidence" }),
        )
        .expect("route attempt indexed");

        let dashboard = read_dashboard_run(&artifacts.run_dir).expect("dashboard reads");
        assert!(dashboard.route_attempts.present);
        assert_eq!(dashboard.route_attempts.status, "passed");
        assert_eq!(dashboard.route_attempts.attempt_count, 1);
        assert_eq!(dashboard.route_attempts.passed_count, 1);
        assert!(dashboard
            .route_attempts
            .evidence_refs
            .contains(&route_path.to_string()));
        assert!(dashboard
            .route_attempts
            .evidence_refs
            .contains(&"evidence/scenarios/collect-and-exit/world-state-start.json".to_string()));
        assert!(dashboard
            .route_attempts
            .boundary
            .contains("must not run solvers"));

        write_json(
            &artifacts.run_dir.join(route_path),
            &json!({ "schemaVersion": "bad" }),
        )
        .expect("malformed route attempt writes");
        let malformed = read_dashboard_run(&artifacts.run_dir).expect("malformed dashboard reads");
        assert!(malformed.route_attempts.present);
        assert_eq!(malformed.route_attempts.status, "malformed");
        assert_eq!(malformed.route_attempts.malformed_count, 1);

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn visual_comparison_evidence_accepts_unchanged_and_changed_fixtures() {
        let unchanged = VisualComparisonEvidenceArtifact::from_json_str(include_str!(
            "../../../examples/visual-comparison-evidence-v1/visual-comparison-unchanged.sample.json"
        ))
        .expect("unchanged visual comparison fixture parses");
        assert_eq!(
            unchanged.schema_version,
            VISUAL_COMPARISON_EVIDENCE_SCHEMA_VERSION
        );
        assert_eq!(unchanged.outcome, VisualComparisonOutcome::Unchanged);
        assert_eq!(unchanged.pixel_diff_summary.unwrap().changed_pixels, 0);
        assert!(unchanged
            .guardrails
            .iter()
            .any(|guardrail| guardrail.contains("No aesthetic")));

        let changed = VisualComparisonEvidenceArtifact::from_json_str(include_str!(
            "../../../examples/visual-comparison-evidence-v1/visual-comparison-changed.sample.json"
        ))
        .expect("changed visual comparison fixture parses");
        assert_eq!(changed.outcome, VisualComparisonOutcome::Changed);
        assert_eq!(changed.changed_regions.len(), 1);
        assert_eq!(
            changed.pixel_diff_summary.as_ref().unwrap().changed_pixels,
            64
        );
    }

    #[test]
    fn visual_comparison_evidence_rejects_missing_thresholds_and_bad_screenshot_refs() {
        let missing_thresholds = include_str!(
            "../../../examples/visual-comparison-evidence-v1/invalid/missing-thresholds.json"
        );
        let error = VisualComparisonEvidenceArtifact::from_json_str(missing_thresholds)
            .expect_err("comparable outcomes require thresholds");
        assert!(error.to_string().contains("thresholds"));

        let malformed_ref = include_str!(
            "../../../examples/visual-comparison-evidence-v1/invalid/malformed-screenshot-ref.json"
        );
        let error = VisualComparisonEvidenceArtifact::from_json_str(malformed_ref)
            .expect_err("unsafe or unsupported screenshot refs are rejected");
        assert!(
            error.to_string().contains("evidence artifact path")
                || error.to_string().contains("PNG or JPEG")
        );

        let mut missing = VisualComparisonEvidenceArtifact::from_json_str(include_str!(
            "../../../examples/visual-comparison-evidence-v1/invalid/missing-screenshot-state.json"
        ))
        .expect("explicit missing screenshot state is accepted");
        missing.after.screenshot_ref = Some("evidence/screenshots/after-goal.png".to_string());
        let error = missing
            .validate()
            .expect_err("missing screenshot state cannot also include screenshotRef");
        assert!(error.to_string().contains("missingReason"));
    }

