    #[test]
    fn evaluates_scenario_assertions_against_captured_state() {
        let scenario = Scenario {
            id: "probe-smoke".to_string(),
            description: "probe".to_string(),
            steps: Vec::new(),
            assertions: vec![
                ScenarioAssertion::WorldState {
                    world_state: json_path_equals("tick", json!(2)),
                },
                ScenarioAssertion::FrameStats {
                    frame_stats: json_path_equals("fixedDeltaMs", json!(16)),
                },
                ScenarioAssertion::WorldState {
                    world_state: json_path_equals("object.id", json!("missing")),
                },
                ScenarioAssertion::WorldState {
                    world_state: json_path_equals("collisions.0.pairId", json!("goal:player")),
                },
                ScenarioAssertion::WorldState {
                    world_state: json_path_assertion("collisions", |assertion| {
                        assertion.count_equals = Some(1);
                    }),
                },
                ScenarioAssertion::RuntimeEvents {
                    runtime_events: json_path_assertion("events", |assertion| {
                        assertion.count_greater_than = Some(0);
                    }),
                },
                ScenarioAssertion::WorldFlags {
                    world_flags: json_path_equals("coin_collected", json!(true)),
                },
                ScenarioAssertion::PhysicsEvidence {
                    physics_evidence: json_path_equals("grounded.player", json!(true)),
                },
                ScenarioAssertion::ConsoleErrors {
                    console_errors: json_path_assertion("logs", |assertion| {
                        assertion.count_equals = Some(0);
                    }),
                },
                ScenarioAssertion::PerformanceMetrics {
                    performance_metrics: json_path_assertion("ScriptDuration", |assertion| {
                        assertion.less_than = Some(json!(10));
                    }),
                },
                ScenarioAssertion::CollisionEvidence {
                    collision_evidence: json_path_equals(
                        "1.staticEntityId",
                        json!("tilemap.collision.authoring-map.terrain.2.0.wall"),
                    ),
                },
            ],
        };
        let world_state = json!({
            "tick": 2,
            "object": { "id": "probe-square" },
            "collisions": [
                { "pairId": "goal:player" },
                { "pairId": "player:tilemap.collision.authoring-map.terrain.2.0.wall", "staticEntityId": "tilemap.collision.authoring-map.terrain.2.0.wall" }
            ],
            "physics": { "grounded": { "player": true } },
            "goalFlags": { "coin_collected": true }
        });
        let frame_stats = json!({ "fixedDeltaMs": 16 });
        let runtime_events =
            json!({ "stepCount": 0, "events": [{ "type": "runtime.physics.jump" }] });
        let performance_metrics = json!({ "ScriptDuration": 2.5 });
        let console_errors = json!({ "logs": [], "count": 0 });
        let none = serde_json::Value::Null;
        let sources = assertion_sources_for_test(
            &world_state,
            &frame_stats,
            &runtime_events,
            &world_state["goalFlags"],
            &world_state["physics"],
            &performance_metrics,
            &console_errors,
            &world_state["collisions"],
            &none,
            &none,
        );

        let assertions = evaluate_scenario_assertions(&scenario, &sources);

        assert_eq!(assertions.len(), 11);
        assert_eq!(assertions[0]["passed"], true);
        assert_eq!(assertions[1]["passed"], true);
        assert_eq!(assertions[2]["passed"], false);
        assert_eq!(assertions[2]["actual"], "probe-square");
        assert_eq!(assertions[3]["passed"], true);
        assert_eq!(assertions[4]["operator"], "countEquals");
        assert_eq!(assertions[4]["evidence_ref"], "evidence/world-state.json");
        assert_eq!(assertions[5]["passed"], true);
        assert_eq!(assertions[6]["passed"], true);
        assert_eq!(assertions[6]["target"], "world_flags");
        assert_eq!(assertions[7]["passed"], true);
        assert_eq!(assertions[7]["target"], "physics_evidence");
        assert_eq!(assertions[8]["passed"], true);
        assert_eq!(assertions[9]["passed"], true);
        assert_eq!(assertions[10]["passed"], true);
        assert_eq!(assertions[10]["target"], "collision_evidence");
    }

    #[test]
    fn scenario_steps_call_runtime_probe_api() {
        let mut client = CdpClient::new(RecordingRuntimeTransport { calls: Vec::new() });

        execute_scenario_step(
            &mut client,
            &ScenarioStep::Wait {
                wait: WaitStep { frames: 3 },
            },
        )
        .expect("wait executes");
        execute_scenario_step(
            &mut client,
            &ScenarioStep::Input {
                input: InputStep {
                    right: Some(true),
                    ..InputStep::default()
                },
            },
        )
        .expect("input executes");
        execute_scenario_step(
            &mut client,
            &ScenarioStep::Transition {
                transition: TransitionStep {
                    id: "to_level_2".to_string(),
                },
            },
        )
        .expect("transition executes");
        execute_scenario_step(
            &mut client,
            &ScenarioStep::Replay {
                replay: InputReplay {
                    schema_version: "1".to_string(),
                    id: "move-right".to_string(),
                    events: vec![
                        InputReplayEvent {
                            frame: 0,
                            key: ReplayKey::Right,
                            pressed: true,
                        },
                        InputReplayEvent {
                            frame: 4,
                            key: ReplayKey::Right,
                            pressed: false,
                        },
                    ],
                },
            },
        )
        .expect("replay executes");

        let transport = client.into_transport();
        let readiness = "Boolean(window.__OUROFORGE__ && typeof window.__OUROFORGE__.step === 'function' && typeof window.__OUROFORGE__.setInput === 'function')";
        assert_eq!(transport.calls[0], readiness);
        assert_eq!(transport.calls[1], "window.__OUROFORGE__.step(3)");
        assert_eq!(transport.calls[2], readiness);
        assert_eq!(
            transport.calls[3],
            "window.__OUROFORGE__.setInput({\"right\":true})"
        );
        let transition_readiness =
            "Boolean(window.__OUROFORGE__ && typeof window.__OUROFORGE__.transition === 'function')";
        assert_eq!(transport.calls[4], transition_readiness);
        assert_eq!(
            transport.calls[5],
            "window.__OUROFORGE__.transition(\"to_level_2\")"
        );
        assert_eq!(transport.calls[6], readiness);
        assert_eq!(
            transport.calls[7],
            "window.__OUROFORGE__.setInput({\"right\":true})"
        );
        assert_eq!(transport.calls[8], readiness);
        assert_eq!(transport.calls[9], "window.__OUROFORGE__.step(4)");
        assert_eq!(transport.calls[10], readiness);
        assert_eq!(
            transport.calls[11],
            "window.__OUROFORGE__.setInput({\"right\":false})"
        );
    }

    #[test]
    fn browser_smoke_records_worker_run_failure_evidence() {
        let (root, artifacts) = create_test_run("ouroforge-browser-worker-run-failure-test");
        let mut config = BrowserSmokeConfig::new(&artifacts.run_dir, "http://127.0.0.1:8765")
            .expect("config builds");
        config.debugging_http_url = "http://127.0.0.1:9".to_string();

        let error = run_browser_smoke(&config).expect_err("worker run fails without chrome");
        assert!(!error.to_string().is_empty());

        let index = read_evidence_index(&artifacts.run_dir).expect("evidence index reads");
        let failure = index
            .artifacts
            .iter()
            .find(|artifact| {
                artifact
                    .metadata
                    .get("artifact")
                    .and_then(|value| value.as_str())
                    == Some("browser_worker_failure")
            })
            .expect("failure artifact indexed");
        assert_eq!(failure.metadata["phase"], "worker_run");
        assert_eq!(failure.metadata["worker_id"], "worker-1");
        assert!(artifacts.run_dir.join(&failure.path).is_file());
        let failure_value =
            read_json_value(artifacts.run_dir.join(&failure.path)).expect("failure artifact reads");
        assert_eq!(failure_value["artifact"], "browser_worker_failure");
        assert_eq!(failure_value["phase"], "worker_run");
        assert_eq!(failure_value["execution_boundary"], "openchrome_cdp");

        let events = read_ledger_events(&artifacts.run_dir).expect("ledger reads");
        assert!(events.iter().any(|event| {
            event["event"] == "browser.worker.failed"
                && event["payload"]["worker_id"] == "worker-1"
                && event["payload"]["phase"] == "worker_run"
                && event["payload"]["failure_path"] == failure.path
        }));
        fs::remove_dir_all(root).ok();
    }

