    #[test]
    fn scene_tilemap_v1_accepts_bounded_grid_and_deterministic_layer_order() {
        let scene: SceneDocument = serde_json::from_value(json!({
            "schemaVersion": "1",
            "id": "tilemap-v1-scene",
            "bounds": { "width": 320, "height": 180 },
            "tilemaps": [
                {
                    "id": "level",
                    "tileSize": { "width": 16, "height": 16 },
                    "grid": { "width": 3, "height": 2 },
                    "tiles": [
                        { "id": "empty", "color": "#172532" },
                        { "id": "solid", "color": "#334155", "asset": "assets/tiles/solid.svg", "solid": true },
                        { "id": "hazard", "color": "#ef4444" }
                    ],
                    "layers": [
                        {
                            "id": "foreground",
                            "order": 10,
                            "data": [null, null, "hazard", null, "solid", null],
                            "collisionLayer": "collision"
                        },
                        {
                            "id": "collision",
                            "order": 0,
                            "visible": false,
                            "data": [null, null, null, null, "solid", null]
                        },
                        {
                            "id": "background",
                            "order": -10,
                            "data": ["empty", "empty", "empty", "empty", "empty", "empty"],
                            "metadata": { "role": "backdrop" }
                        }
                    ],
                    "metadata": { "purpose": "tilemap fixture" }
                }
            ],
            "entities": [
                {
                    "id": "player",
                    "sprite": { "color": "#5eead4" },
                    "components": {
                        "transform": { "x": 32, "y": 72 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": true
                    }
                }
            ]
        }))
        .expect("tilemap scene parses");

        validate_scene(&scene).expect("tilemap v1 validates");
        assert_eq!(scene.tilemaps[0].tile_size.width, 16);
        assert_eq!(scene.tilemaps[0].grid.width, 3);
        assert!(scene.tilemaps[0].tiles.iter().any(|tile| tile.solid));
        assert_eq!(
            scene_tilemap_layer_order(&scene)
                .iter()
                .map(|entry| entry.layer_id.as_str())
                .collect::<Vec<_>>(),
            vec!["background", "foreground"]
        );
        assert_eq!(
            serde_json::to_string(&scene_tilemap_layer_order(&scene))
                .expect("tilemap layer order serializes"),
            r#"[{"tilemapId":"level","layerId":"background","order":-10},{"tilemapId":"level","layerId":"foreground","order":10}]"#
        );
    }

    #[test]
    fn scene_tilemap_tile_accepts_trigger_goal_and_hazard_fields() {
        // The browser runtime normalizes tile-level `trigger`, `goal`, and
        // `hazard` fields (examples/game-runtime/tilemap.js). SceneTileDefinition
        // is `deny_unknown_fields`, so a scene using them must still parse and
        // validate or it cannot be used as a validated scenario/seed.
        let scene: SceneDocument = serde_json::from_value(json!({
            "schemaVersion": "1",
            "id": "tilemap-tile-flags-scene",
            "bounds": { "width": 320, "height": 180 },
            "tilemaps": [
                {
                    "id": "level",
                    "tileSize": { "width": 16, "height": 16 },
                    "grid": { "width": 2, "height": 1 },
                    "tiles": [
                        { "id": "spikes", "color": "#ef4444", "hazard": true },
                        { "id": "exit", "color": "#facc15", "goal": true, "trigger": "exit_reached" }
                    ],
                    "layers": [
                        { "id": "main", "order": 0, "data": ["spikes", "exit"] }
                    ]
                }
            ],
            "entities": [
                {
                    "id": "player",
                    "sprite": { "color": "#5eead4" },
                    "components": {
                        "transform": { "x": 16, "y": 16 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": true
                    }
                }
            ]
        }))
        .expect("tile flag scene parses");

        validate_scene(&scene).expect("tile flag scene validates");
        let tiles = &scene.tilemaps[0].tiles;
        assert!(tiles.iter().any(|tile| tile.id == "spikes" && tile.hazard));
        let exit = tiles
            .iter()
            .find(|tile| tile.id == "exit")
            .expect("exit tile present");
        assert!(exit.goal);
        assert_eq!(exit.trigger.as_deref(), Some("exit_reached"));
    }

    #[test]
