    #[test]
    fn scene_physics_v2_accepts_kinematic_triggers_and_collision_masks() {
        let scene: SceneDocument = serde_json::from_value(json!({
            "schemaVersion": "1",
            "id": "physics-v2-scene",
            "bounds": { "width": 320, "height": 180 },
            "collisionRules": {
                "version": "2",
                "defaultLayer": "world",
                "layers": [
                    { "id": "world", "solid": true, "collidesWith": ["actors"] },
                    { "id": "actors", "solid": true, "collidesWith": ["world", "triggers"] },
                    { "id": "triggers", "solid": false, "triggerOnly": true, "collidesWith": ["actors"] }
                ]
            },
            "entities": [
                {
                    "id": "player",
                    "sprite": { "color": "#5eead4" },
                    "components": {
                        "transform": { "x": 0, "y": 0 },
                        "velocity": { "x": 1, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": true,
                        "collider": {
                            "shape": "aabb",
                            "body": "kinematic",
                            "offset": { "x": 0, "y": 0 },
                            "size": { "width": 16, "height": 16 },
                            "trigger": true,
                            "collisionGroup": "actors",
                            "collisionMask": ["world", "triggers"]
                        }
                    }
                },
                {
                    "id": "goal",
                    "sprite": { "color": "#facc15" },
                    "components": {
                        "transform": { "x": 32, "y": 0 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": false,
                        "collider": {
                            "shape": "aabb",
                            "body": "static",
                            "size": { "width": 16, "height": 16 },
                            "sensor": true,
                            "collisionGroup": "triggers"
                        }
                    }
                }
            ]
        }))
        .expect("physics scene parses");
        validate_scene(&scene).expect("physics v2 collider schema validates");
        let rules = scene.collision_rules.as_ref().expect("collision rules");
        assert_eq!(rules.version, "2");
        assert_eq!(rules.default_layer, "world");
        assert!(rules
            .layers
            .iter()
            .any(|layer| layer.id == "triggers" && layer.trigger_only && !layer.solid));
        let collider = scene.entities[0]
            .components
            .collider
            .as_ref()
            .expect("collider present");
        assert_eq!(collider.body, "kinematic");
        assert!(collider.trigger);
        assert_eq!(collider.collision_group.as_deref(), Some("actors"));
        assert_eq!(
            collider.collision_mask,
            vec!["world".to_string(), "triggers".to_string()]
        );

        let mut invalid_body = scene.clone();
        invalid_body.entities[0]
            .components
            .collider
            .as_mut()
            .expect("collider")
            .body = "rigid".to_string();
        let rejected = validate_scene(&invalid_body).expect_err("invalid body rejected");
        assert!(rejected.to_string().contains(
            "collider body must be static, dynamic, trigger, sensor, or legacy kinematic"
        ));

        let mut duplicate_mask = scene.clone();
        duplicate_mask.entities[0]
            .components
            .collider
            .as_mut()
            .expect("collider")
            .collision_mask = vec!["world".to_string(), "world".to_string()];
        let rejected = validate_scene(&duplicate_mask).expect_err("duplicate mask rejected");
        assert!(rejected
            .to_string()
            .contains("duplicate scene entity player collider collisionMask"));

        let mut unsafe_group = scene.clone();
        unsafe_group.entities[0]
            .components
            .collider
            .as_mut()
            .expect("collider")
            .collision_group = Some("../world".to_string());
        let rejected = validate_scene(&unsafe_group).expect_err("unsafe group rejected");
        assert!(rejected.to_string().contains("may only contain ASCII"));

        let mut unknown_group = scene.clone();
        unknown_group.entities[0]
            .components
            .collider
            .as_mut()
            .expect("collider")
            .collision_group = Some("ghosts".to_string());
        let rejected = validate_scene(&unknown_group).expect_err("unknown group rejected");
        assert!(rejected
            .to_string()
            .contains("collisionGroup references unknown collisionRules layer"));

        let mut unknown_mask = scene.clone();
        unknown_mask.entities[0]
            .components
            .collider
            .as_mut()
            .expect("collider")
            .collision_mask = vec!["world".to_string(), "ghosts".to_string()];
        let rejected = validate_scene(&unknown_mask).expect_err("unknown mask rejected");
        assert!(rejected
            .to_string()
            .contains("collisionMask references unknown collisionRules layer"));

        let mut duplicate_layer = scene.clone();
        duplicate_layer
            .collision_rules
            .as_mut()
            .expect("rules")
            .layers
            .push(SceneCollisionLayer {
                id: "world".to_string(),
                solid: true,
                trigger_only: false,
                collides_with: vec![],
            });
        let rejected = validate_scene(&duplicate_layer).expect_err("duplicate layer rejected");
        assert!(rejected
            .to_string()
            .contains("duplicate scene collisionRules layer id"));

        let mut legacy_without_rules = scene.clone();
        legacy_without_rules.collision_rules = None;
        legacy_without_rules.entities[0]
            .components
            .collider
            .as_mut()
            .expect("collider")
            .collision_group = Some("legacy-freeform".to_string());
        validate_scene(&legacy_without_rules).expect("legacy freeform collision group accepted");
    }

    #[test]
